function vendorProfileValue(profile: Record<string, unknown>, section: string, field: string) {
  const sectionValue = objectRecord(profile[section]);
  return sectionValue[field];
}

function vendorProfileHasValue(profile: Record<string, unknown>, section: string, field: string) {
  const value = vendorProfileValue(profile, section, field);
  if (Array.isArray(value)) return value.map((item) => cleanText(item)).filter(Boolean).length > 0;
  return Boolean(cleanText(value));
}

function vendorProfileCsvValue(profile: Record<string, unknown>, section: string, field: string) {
  const value = vendorProfileValue(profile, section, field);
  if (Array.isArray(value)) return value.map((item) => cleanText(item)).filter(Boolean).join("; ");
  return cleanText(value) || "";
}

function vendorOnboardingGapReport(row: Record<string, unknown>) {
  const profile = normalizeVendorProfileData(row.profile_data);
  const gaps: string[] = [];
  const vendorName = cleanText(row.vendor_name);
  const primaryEmail = cleanText(row.primary_email);
  const whatsapp = cleanText(row.whatsapp_phone);
  const legalName = cleanText(row.legal_name);
  if (!vendorName) gaps.push("Vendor name");
  if (!cleanText(row.domain)) gaps.push("Domain");
  if (!primaryEmail && !whatsapp && !cleanText(vendorProfileValue(profile, "general", "mobile_number"))) gaps.push("Contact channel");
  if (!vendorProfileHasValue(profile, "general", "operating_country")) gaps.push("Operating country");
  const hasLegalIdentity = Boolean(
    legalName
    || vendorProfileHasValue(profile, "mexico", "legal_name")
    || vendorProfileHasValue(profile, "mexico", "rfc")
    || vendorProfileHasValue(profile, "international", "legal_name")
    || vendorProfileHasValue(profile, "international", "usdot_number")
    || vendorProfileHasValue(profile, "international", "mc_number")
  );
  if (!hasLegalIdentity) gaps.push("Legal identity");
  if (!vendorProfileHasValue(profile, "carrier_profile", "geographic_scope")) gaps.push("Geographic scope");
  if (!vendorProfileHasValue(profile, "carrier_profile", "service_scope")) gaps.push("Service scope");
  if (!vendorProfileHasValue(profile, "carrier_profile", "regional_coverage")) gaps.push("Regional coverage");
  if (!vendorProfileHasValue(profile, "insurance_infrastructure", "equipment_types")) gaps.push("Equipment");
  if (!vendorProfileHasValue(profile, "insurance_infrastructure", "coverage_amounts")) gaps.push("Insurance coverage");

  const readinessScore = Math.max(0, Math.round(((10 - gaps.length) / 10) * 100));
  const currentStage = normalizeVendorFunnelStage(row.funnel_stage) || "targeted";
  const suggestedAction = !primaryEmail && !whatsapp
    ? "Add contact before invite"
    : gaps.length
      ? "Complete onboarding profile"
      : row.base_stage !== "procurement"
        ? "Move to Procurement Base"
        : currentStage === "targeted" || currentStage === "nested"
          ? "Draft onboarding"
          : currentStage === "drafted"
            ? "Send onboarding invite"
            : "Continue onboarding";

  return {
    vendor_id: row.id,
    vendor_name: vendorName,
    domain: cleanText(row.domain),
    primary_email: primaryEmail,
    whatsapp_phone: whatsapp,
    base_stage: cleanText(row.base_stage) || "sourcing",
    funnel_stage: currentStage,
    readiness_score: readinessScore,
    missing_count: gaps.length,
    missing_required_fields: gaps.join("; "),
    suggested_action: suggestedAction,
    operating_country: vendorProfileCsvValue(profile, "general", "operating_country"),
    legal_name: legalName || vendorProfileCsvValue(profile, "mexico", "legal_name") || vendorProfileCsvValue(profile, "international", "legal_name"),
    rfc: vendorProfileCsvValue(profile, "mexico", "rfc"),
    usdot_number: vendorProfileCsvValue(profile, "international", "usdot_number"),
    mc_number: vendorProfileCsvValue(profile, "international", "mc_number"),
    geographic_scope: vendorProfileCsvValue(profile, "carrier_profile", "geographic_scope"),
    service_scope: vendorProfileCsvValue(profile, "carrier_profile", "service_scope"),
    regional_coverage: vendorProfileCsvValue(profile, "carrier_profile", "regional_coverage"),
    equipment_types: vendorProfileCsvValue(profile, "insurance_infrastructure", "equipment_types"),
    certifications: vendorProfileCsvValue(profile, "carrier_profile", "certifications"),
    coverage_amounts: vendorProfileCsvValue(profile, "insurance_infrastructure", "coverage_amounts"),
    general_manager: vendorProfileCsvValue(profile, "key_contacts", "general_manager"),
    operations_manager: vendorProfileCsvValue(profile, "key_contacts", "operations_manager"),
    commercial_manager: vendorProfileCsvValue(profile, "key_contacts", "commercial_manager")
  };
}

async function buildVendorOnboardingGaps(supabase: ReturnType<typeof createClient>, user: { owner_email: string | null }) {
  const pageSize = 1000;
  const maxRows = 10000;
  const vendors: Record<string, unknown>[] = [];
  let offset = 0;
  let total = 0;

  while (offset < maxRows) {
    const result = await supabase
      .from("vendors")
      .select("*", { count: "exact" })
      .eq("owner_email", user.owner_email)
      .neq("base_stage", "archived")
      .order("vendor_name", { ascending: true })
      .range(offset, offset + pageSize - 1);
    if (result.error) throw result.error;
    if (offset === 0) total = result.count || 0;
    const rows = (result.data || []) as Record<string, unknown>[];
    vendors.push(...rows);
    if (rows.length < pageSize) break;
    offset += pageSize;
  }

  const reports = vendors.map(vendorOnboardingGapReport);
  const gaps = reports.filter((row) => Number(row.missing_count || 0) > 0);
  return {
    rows: gaps,
    summary: {
      total_vendors: total || vendors.length,
      scanned_vendors: vendors.length,
      vendors_with_gaps: gaps.length,
      complete_vendors: reports.length - gaps.length,
      truncated: vendors.length >= maxRows && (total || 0) > vendors.length
    }
  };
}

function hasCorrectionValue(value: unknown): boolean {
  if (Array.isArray(value)) return value.some(hasCorrectionValue);
  if (typeof value === "object" && value !== null) return Object.values(value).some(hasCorrectionValue);
  return Boolean(cleanText(value));
}

function compactVendorProfileData(profile: Record<string, unknown>) {
  const compact: Record<string, Record<string, unknown>> = {};
  for (const [sectionKey, sectionValue] of Object.entries(profile)) {
    const section = objectRecord(sectionValue);
    for (const [fieldKey, value] of Object.entries(section)) {
      if (!hasCorrectionValue(value)) continue;
      compact[sectionKey] ||= {};
      compact[sectionKey][fieldKey] = Array.isArray(value)
        ? value.map((item) => cleanText(item)).filter(Boolean)
        : value;
    }
  }
  return compact;
}

function mergeVendorProfileData(current: Record<string, unknown>, correction: Record<string, unknown>) {
  const merged: Record<string, Record<string, unknown>> = {};
  for (const [sectionKey, sectionValue] of Object.entries(current)) {
    const section = objectRecord(sectionValue);
    if (Object.keys(section).length) merged[sectionKey] = { ...section };
  }
  for (const [sectionKey, sectionValue] of Object.entries(compactVendorProfileData(correction))) {
    merged[sectionKey] = {
      ...(merged[sectionKey] || {}),
      ...objectRecord(sectionValue)
    };
  }
  return merged;
}

function compactVendorCorrectionInput(input: Record<string, unknown>, current: Record<string, unknown>) {
  const patch: Record<string, unknown> = {};
  const cleanFields = [
    "vendor_name",
    "legal_name",
    "domain",
    "contact_name",
    "primary_email",
    "whatsapp_phone",
    "preferred_channel",
    "logo_url",
    "coverage_notes",
    "notes",
    "base_stage",
    "funnel_stage",
    "status"
  ];

  for (const field of cleanFields) {
    if (hasCorrectionValue(input[field])) patch[field] = input[field];
  }

  const tags = normalizeTags(input.tags);
  if (tags.length) patch.tags = tags;

  const correctionProfile = compactVendorProfileData(normalizeVendorProfileData(input.profile_data));
  if (Object.keys(correctionProfile).length) {
    patch.profile_data = mergeVendorProfileData(normalizeVendorProfileData(current.profile_data), correctionProfile);
  }

  return patch;
}

async function uniqueVendorMatch(
  supabase: ReturnType<typeof createClient>,
  user: { owner_email: string | null },
  column: string,
  value: string,
  matchBy: string
) {
  const result = await supabase
    .from("vendors")
    .select("*")
    .eq("owner_email", user.owner_email)
    .eq(column, value)
    .limit(2);
  if (result.error) throw result.error;
  const rows = (result.data || []) as Record<string, unknown>[];
  if (rows.length === 1) return { vendor: rows[0], matchBy };
  if (rows.length > 1) return { error: `Ambiguous ${matchBy}: ${value}` };
  return null;
}

async function findVendorForOnboardingCorrection(
  supabase: ReturnType<typeof createClient>,
  user: { owner_email: string | null },
  input: Record<string, unknown>
) {
  const vendorId = cleanText(input.vendor_id || input.id);
  if (vendorId) {
    const match = await uniqueVendorMatch(supabase, user, "id", vendorId, "vendor_id");
    if (match) return match;
  }

  const domain = normalizeDomain(input.domain || input.vendor_domain || input.primary_email);
  if (domain) {
    const match = await uniqueVendorMatch(supabase, user, "domain", domain, "domain");
    if (match) return match;
  }

  const email = normalizeEmail(input.primary_email || input.email);
  if (email) {
    const match = await uniqueVendorMatch(supabase, user, "primary_email", email, "primary_email");
    if (match) return match;
  }

  const vendorName = cleanText(input.vendor_name || input.vendor || input.carrier || input.name);
  if (vendorName) {
    const match = await uniqueVendorMatch(supabase, user, "vendor_name", vendorName, "vendor_name");
    if (match) return match;
  }

  return { error: "Missing vendor_id, domain, email, or vendor_name" };
}

async function importVendorOnboardingCorrections(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  vendors: unknown[]
) {
  const inputs = vendors.map(objectRecord).filter((row) => hasCorrectionValue(row)).slice(0, 5000);
  let updated = 0;
  let skipped = 0;
  const rows: Record<string, unknown>[] = [];
  const errors: Record<string, unknown>[] = [];

  async function processCorrection(input: Record<string, unknown>) {
    const match = await findVendorForOnboardingCorrection(supabase, user, input);
    if (!match || !("vendor" in match) || !match.vendor) {
      skipped += 1;
      errors.push({
        vendor_id: cleanText(input.vendor_id || input.id),
        vendor_name: cleanText(input.vendor_name),
        domain: normalizeDomain(input.domain),
        error_reason: match && "error" in match ? match.error : "No matching vendor found"
      });
      return;
    }

    const patchInput = compactVendorCorrectionInput(input, match.vendor);
    if (!Object.keys(patchInput).length) {
      skipped += 1;
      errors.push({
        vendor_id: cleanText(match.vendor.id),
        vendor_name: cleanText(match.vendor.vendor_name),
        domain: normalizeDomain(match.vendor.domain),
        error_reason: "No correction values found"
      });
      return;
    }

    const patch = normalizeVendorPatch(patchInput, match.vendor);
    if (patch.vendor_name === null) {
      skipped += 1;
      errors.push({
        vendor_id: cleanText(match.vendor.id),
        vendor_name: cleanText(match.vendor.vendor_name),
        domain: normalizeDomain(match.vendor.domain),
        error_reason: "Vendor name cannot be blank"
      });
      return;
    }

    const result = await supabase
      .from("vendors")
      .update(patch)
      .eq("owner_email", user.owner_email)
      .eq("id", match.vendor.id)
      .select()
      .single();
    if (result.error) throw result.error;
    updated += 1;
    rows.push(result.data);
  }

  for (const batch of chunkValues(inputs, 20)) {
    await Promise.all(batch.map(processCorrection));
  }

  if (updated) {
    await writeAuditLog(
      supabase,
      user,
      "vendor.onboarding_gaps.import",
      "vendors",
      null,
      `Applied ${updated} vendor onboarding correction(s)`,
      { updated, skipped, error_count: errors.length }
    );
  }

  return { updated, skipped, rows, errors: errors.slice(0, 200), total_rows: inputs.length };
}

function normalizeImportedVendor(row: Record<string, unknown>, source = "google_sheet") {
  const profileData = readImportedVendorProfileData(row);
  return {
    vendor_name: firstValue(row, ["vendor_name", "vendor", "carrier", "carrier name", "company", "company name", "nombre", "transportista", "proveedor", "name"]),
    legal_name: firstValue(row, ["legal_name", "legal name", "razon social", "legal entity"]),
    domain: firstValue(row, ["domain", "website", "web", "site", "vendor_domain"]),
    contact_name: firstValue(row, ["contact_name", "contact", "contacto", "pricing contact", "sales rep", "representative"]),
    primary_email: firstValue(row, ["primary_email", "email", "mail", "correo", "e-mail", "pricing email"]),
    whatsapp_phone: firstValue(row, ["whatsapp_phone", "whatsapp", "phone", "telefono", "mobile", "cell"]),
    preferred_channel: firstValue(row, ["preferred_channel", "channel", "canal"]) || "email",
    logo_url: firstValue(row, ["logo_url", "logo", "logo link", "logo url", "image", "image_url", "brand logo"]),
    tags: Array.from(new Set([...normalizeTags(firstValue(row, ["tags", "tag", "services", "service", "equipment", "equipos", "coverage type", "tipo"])), ...vendorProfileDerivedTags(profileData)])),
    coverage_notes: firstValue(row, ["coverage_notes", "coverage", "lanes", "rutas", "regions", "region", "markets", "mercados", "notes coverage"]),
    notes: firstValue(row, ["notes", "notas", "comments", "comentarios", "observations", "observaciones"]),
    base_stage: firstValue(row, ["base_stage", "base", "stage"]) || "sourcing",
    profile_data: profileData,
    source
  };
}

const VENDOR_FUNNEL_STAGES = ["targeted", "nested", "drafted", "invited", "onboarded", "trained", "activated", "completed"];
const VENDOR_FUNNEL_STAGE_LABELS: Record<string, string> = {
  targeted: "Targeted",
  nested: "Nested",
  drafted: "Drafted",
  invited: "Invited",
  onboarded: "Onboarded",
  trained: "Trained",
  activated: "Activated",
  completed: "Completed"
};
const VENDOR_FUNNEL_STAGE_DESCRIPTIONS: Record<string, string> = {
  targeted: "Moved from Sourcing Base into Procurement Base.",
  nested: "Has linked carrier quotes in staging or Rateware.",
  drafted: "Selected for onboarding preparation.",
  invited: "Onboarding invitation has been sent.",
  onboarded: "Supplier registration is complete.",
  trained: "TMS training or setup is complete.",
  activated: "Ready for immediate procurement use.",
  completed: "Legal document package is fully signed."
};
const VENDOR_FUNNEL_STAGE_TIMESTAMPS: Record<string, string> = {
  targeted: "targeted_at",
  nested: "nested_at",
  drafted: "drafted_at",
  invited: "invited_at",
  onboarded: "onboarded_at",
  trained: "trained_at",
  activated: "activated_at",
  completed: "completed_at"
};

function normalizeVendorFunnelStage(value: unknown) {
  const stage = cleanText(value)?.toLowerCase();
  return stage && VENDOR_FUNNEL_STAGES.includes(stage) ? stage : null;
}

function vendorFunnelPatch(stage: string | null, now = new Date().toISOString()) {
  if (!stage) return {};
  const timestampField = VENDOR_FUNNEL_STAGE_TIMESTAMPS[stage];
  return {
    funnel_stage: stage,
    funnel_stage_updated_at: now,
    ...(timestampField ? { [timestampField]: now } : {})
  };
}

function vendorFunnelUpdatePatch(stage: string | null, current: Record<string, unknown> = {}, now = new Date().toISOString()) {
  if (!stage) return {};
  const currentStage = normalizeVendorFunnelStage(current.funnel_stage);
  const timestampField = VENDOR_FUNNEL_STAGE_TIMESTAMPS[stage];
  const patch: Record<string, unknown> = { funnel_stage: stage };
  if (stage !== currentStage || !current.funnel_stage_updated_at) {
    patch.funnel_stage_updated_at = now;
  }
  if (timestampField && !current[timestampField]) {
    patch[timestampField] = now;
  }
  return patch;
}

function normalizeVendorProfileData(value: unknown) {
  return objectRecord(value);
}

function normalizeVendor(input: Record<string, unknown>, source = "manual") {
  const vendorName = cleanText(input.vendor_name || input.name || input.carrier || input.vendor);
  if (!vendorName) throw new Error("Vendor name is required.");

  const preferred = cleanText(input.preferred_channel)?.toLowerCase() || "email";
  const whatsappPermissionBasis = cleanText(input.whatsapp_permission_basis)?.toLowerCase() || "contractual";
  const whatsappOptInStatus = cleanText(input.whatsapp_opt_in_status)?.toLowerCase() || "contractual";
  const whatsappGroupStatus = cleanText(input.whatsapp_group_status)?.toLowerCase() || "manual_only";
  const status = cleanText(input.status)?.toLowerCase() || "active";
  const baseStage = cleanText(input.base_stage)?.toLowerCase() || "sourcing";
  const now = new Date().toISOString();
  const funnelStage = normalizeVendorFunnelStage(input.funnel_stage) || (baseStage === "procurement" ? "targeted" : null);
  const profileData = normalizeVendorProfileData(input.profile_data);
  const emailList = normalizeEmailList(input.primary_email || input.email);
  const secondaryEmails = Array.from(new Set([...emailList.slice(1), ...normalizeEmailList(input.secondary_emails)]));

  return {
    vendor_name: vendorName,
    legal_name: cleanText(input.legal_name),
    domain: normalizeDomain(input.domain || input.vendor_domain),
    contact_name: cleanText(input.contact_name || input.contact),
    primary_email: emailList[0] || "",
    secondary_emails: secondaryEmails,
    whatsapp_phone: cleanText(input.whatsapp_phone || input.phone || input.whatsapp),
    preferred_channel: ["email", "whatsapp", "whatsapp_group", "multi", "portal"].includes(preferred) ? preferred : "email",
    whatsapp_permission_basis: ["contractual", "consent", "manual", "unknown"].includes(whatsappPermissionBasis) ? whatsappPermissionBasis : "contractual",
    whatsapp_do_not_contact: cleanBoolean(input.whatsapp_do_not_contact || input.do_not_contact_whatsapp),
    whatsapp_opt_in_status: ["contractual", "opted_in", "manual", "unknown", "opted_out"].includes(whatsappOptInStatus) ? whatsappOptInStatus : "contractual",
    whatsapp_group_url: cleanText(input.whatsapp_group_url || input.group_url),
    whatsapp_group_name: cleanText(input.whatsapp_group_name || input.group_name),
    whatsapp_meta_group_id: cleanText(input.whatsapp_meta_group_id || input.meta_group_id),
    whatsapp_group_status: ["pending", "manual_only", "api_ready", "verified", "blocked", "error"].includes(whatsappGroupStatus) ? whatsappGroupStatus : "manual_only",
    whatsapp_notes: cleanText(input.whatsapp_notes),
    status: ["active", "invited", "blocked", "inactive"].includes(status) ? status : "active",
    logo_url: cleanUrl(input.logo_url || input.logo),
    logo_source: cleanUrl(input.logo_url || input.logo) ? "url" : null,
    tags: Array.from(new Set([...normalizeTags(input.tags || input.tag || input.services || input.equipment || input.coverage), ...vendorProfileDerivedTags(profileData)])),
    coverage_notes: cleanText(input.coverage_notes || input.coverage || input.lanes),
    notes: cleanText(input.notes),
    profile_data: profileData,
    base_stage: ["sourcing", "procurement", "archived"].includes(baseStage) ? baseStage : "sourcing",
    ...vendorFunnelPatch(funnelStage, now),
    source_spreadsheet_url: cleanText(input.source_spreadsheet_url),
    source_spreadsheet_id: cleanText(input.source_spreadsheet_id),
    source_sheet_gid: cleanText(input.source_sheet_gid),
    source_sheet_name: cleanText(input.source_sheet_name),
    source_row_number: input.source_row_number ? Number(input.source_row_number) : null,
    source_row_hash: cleanText(input.source_row_hash),
    last_synced_at: input.last_synced_at || null,
    sync_notes: cleanText(input.sync_notes),
    source
  };
}

function normalizeVendorPatch(input: Record<string, unknown>, current: Record<string, unknown> = {}) {
  const patch: Record<string, unknown> = {};
  const now = new Date().toISOString();
  if (input.vendor_name !== undefined) patch.vendor_name = cleanText(input.vendor_name);
  if (input.legal_name !== undefined) patch.legal_name = cleanText(input.legal_name);
  if (input.domain !== undefined) patch.domain = normalizeDomain(input.domain);
  if (input.contact_name !== undefined) patch.contact_name = cleanText(input.contact_name);
  if (input.primary_email !== undefined || input.email !== undefined) {
    const emailList = normalizeEmailList(input.primary_email ?? input.email);
    patch.primary_email = emailList[0] || "";
    patch.secondary_emails = Array.from(new Set([...emailList.slice(1), ...normalizeEmailList(input.secondary_emails)]));
  } else if (input.secondary_emails !== undefined) {
    patch.secondary_emails = normalizeEmailList(input.secondary_emails);
  }
  if (input.whatsapp_phone !== undefined) patch.whatsapp_phone = cleanText(input.whatsapp_phone);
  if (input.whatsapp_permission_basis !== undefined) {
    const basis = cleanText(input.whatsapp_permission_basis)?.toLowerCase();
    if (basis && ["contractual", "consent", "manual", "unknown"].includes(basis)) patch.whatsapp_permission_basis = basis;
  }
  if (input.whatsapp_do_not_contact !== undefined || input.do_not_contact_whatsapp !== undefined) {
    patch.whatsapp_do_not_contact = cleanBoolean(input.whatsapp_do_not_contact ?? input.do_not_contact_whatsapp);
  }
  if (input.whatsapp_opt_in_status !== undefined) {
    const optIn = cleanText(input.whatsapp_opt_in_status)?.toLowerCase();
    if (optIn && ["contractual", "opted_in", "manual", "unknown", "opted_out"].includes(optIn)) patch.whatsapp_opt_in_status = optIn;
  }
  if (input.whatsapp_group_url !== undefined || input.group_url !== undefined) patch.whatsapp_group_url = cleanText(input.whatsapp_group_url ?? input.group_url);
  if (input.whatsapp_group_name !== undefined || input.group_name !== undefined) patch.whatsapp_group_name = cleanText(input.whatsapp_group_name ?? input.group_name);
  if (input.whatsapp_meta_group_id !== undefined || input.meta_group_id !== undefined) patch.whatsapp_meta_group_id = cleanText(input.whatsapp_meta_group_id ?? input.meta_group_id);
  if (input.whatsapp_group_status !== undefined) {
    const groupStatus = cleanText(input.whatsapp_group_status)?.toLowerCase();
    if (groupStatus && ["pending", "manual_only", "api_ready", "verified", "blocked", "error"].includes(groupStatus)) patch.whatsapp_group_status = groupStatus;
  }
  if (input.whatsapp_notes !== undefined) patch.whatsapp_notes = cleanText(input.whatsapp_notes);
  if (input.logo_url !== undefined || input.logo !== undefined) {
    const nextLogoUrl = cleanUrl(input.logo_url ?? input.logo);
    patch.logo_url = nextLogoUrl;
    patch.logo_source = nextLogoUrl && nextLogoUrl === current.logo_url && current.logo_source ? current.logo_source : nextLogoUrl ? "url" : null;
  }
  if (input.coverage_notes !== undefined) patch.coverage_notes = cleanText(input.coverage_notes);
  if (input.notes !== undefined) patch.notes = cleanText(input.notes);
  if (input.profile_data !== undefined) {
    const profileData = normalizeVendorProfileData(input.profile_data);
    patch.profile_data = profileData;
    if (input.tags === undefined) {
      patch.tags = Array.from(new Set([...normalizeTags(current.tags), ...vendorProfileDerivedTags(profileData)]));
    }
  }
  const status = cleanText(input.status)?.toLowerCase();
  if (status && ["active", "invited", "blocked", "inactive"].includes(status)) patch.status = status;
  const baseStage = cleanText(input.base_stage)?.toLowerCase();
  if (baseStage && ["sourcing", "procurement", "archived"].includes(baseStage)) {
    patch.base_stage = baseStage;
    patch.archived_at = baseStage === "archived" ? new Date().toISOString() : null;
    if (baseStage === "procurement" && input.funnel_stage === undefined) {
      Object.assign(patch, vendorFunnelUpdatePatch(normalizeVendorFunnelStage(current.funnel_stage) || "targeted", current, now));
    }
    if ((baseStage === "sourcing" || baseStage === "archived") && input.funnel_stage === undefined) {
      patch.funnel_stage = null;
      patch.funnel_stage_updated_at = null;
    }
  }
  if (input.funnel_stage !== undefined) {
    Object.assign(patch, vendorFunnelUpdatePatch(normalizeVendorFunnelStage(input.funnel_stage), current, now));
  }
  if (input.tags !== undefined) {
    const profileData = input.profile_data !== undefined ? normalizeVendorProfileData(input.profile_data) : normalizeVendorProfileData(current.profile_data);
    patch.tags = Array.from(new Set([...normalizeTags(input.tags), ...vendorProfileDerivedTags(profileData)]));
  }
  if (input.preferred_channel !== undefined) {
    const preferred = cleanText(input.preferred_channel)?.toLowerCase();
    if (preferred && ["email", "whatsapp", "whatsapp_group", "multi", "portal"].includes(preferred)) patch.preferred_channel = preferred;
  }
  patch.updated_at = now;
  return patch;
}

function normalizeUuidList(value: unknown) {
  const rawValues = Array.isArray(value)
    ? value
    : String(value || "").split(/[,\s;|]+/);
  return Array.from(new Set(rawValues
    .map((item) => cleanText(item))
    .filter((item) => /^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i.test(item))));
}

function normalizeSegment(input: Record<string, unknown>, user?: { owner_user_id: string | null; owner_email: string | null }) {
  const segmentName = cleanText(input.segment_name || input.name);
  if (!segmentName) throw new Error("Segment name is required.");

  const status = cleanText(input.status)?.toLowerCase() || null;
  const preferredChannel = cleanText(input.preferred_channel)?.toLowerCase() || null;
  const coverageFilter = cleanText(input.coverage_filter || input.coverage);
  const vendorIds = normalizeUuidList(input.vendor_ids);
  const segmentType = cleanText(input.segment_type || input.type)?.toLowerCase();
  const normalizedType = vendorIds.length
    ? "participant_template"
    : ["dynamic", "participant_template"].includes(segmentType || "")
      ? segmentType || "dynamic"
      : "dynamic";

  return {
    segment_name: segmentName,
    description: cleanText(input.description),
    tags: normalizeTags(input.tags),
    status: status && ["active", "invited", "blocked", "inactive"].includes(status) ? status : null,
    preferred_channel: preferredChannel && ["email", "whatsapp", "whatsapp_group", "multi", "portal"].includes(preferredChannel) ? preferredChannel : null,
    coverage_filter: coverageFilter,
    segment_type: normalizedType,
    vendor_ids: vendorIds,
    notes: cleanText(input.notes),
    owner_user_id: user?.owner_user_id || null,
    owner_email: user?.owner_email || null,
    updated_at: new Date().toISOString()
  };
}

function cleanBoolean(value: unknown) {
  if (typeof value === "boolean") return value;
  const text = String(value ?? "").trim().toLowerCase();
  return ["true", "1", "yes", "y", "on", "checked"].includes(text);
}

function cleanOptionalBoolean(value: unknown) {
  if (value === null || value === undefined || value === "") return null;
  if (typeof value === "boolean") return value;
  const text = String(value ?? "").trim().toLowerCase();
  if (["true", "1", "yes", "y", "on", "checked"].includes(text)) return true;
  if (["false", "0", "no", "n", "off", "unchecked"].includes(text)) return false;
  return null;
}

function cleanTimestamp(value: unknown) {
  const text = cleanText(value);
  if (!text) return null;
  const date = new Date(text);
  return Number.isNaN(date.getTime()) ? null : date.toISOString();
}

function cleanPercent(value: unknown) {
  const numberValue = cleanNumber(value);
  if (numberValue === null) return null;
  return Math.min(100, Math.max(0, numberValue));
}

function strictBidNumber(value: unknown, label: string, options: { required?: boolean; positive?: boolean } = {}) {
  const text = cleanText(value);
  if (!text) {
    if (options.required) throw new Error(`${label} is required.`);
    return null;
  }
  const normalized = text.replace(/[$,]/g, "").trim();
  if (!/^-?\d+(?:\.\d+)?$/.test(normalized)) {
    throw new Error(`${label} must be numeric.`);
  }
  const numberValue = Number(normalized);
  if (!Number.isFinite(numberValue)) throw new Error(`${label} must be numeric.`);
  if (options.positive !== false && numberValue <= 0) throw new Error(`${label} must be greater than zero.`);
  return numberValue;
}

function strictPercentNumber(value: unknown, label: string) {
  const numberValue = strictBidNumber(value, label, { positive: false });
  if (numberValue === null) return null;
  if (numberValue < 0 || numberValue > 100) throw new Error(`${label} must be between 0 and 100.`);
  return numberValue;
}

function strictCurrencyCode(value: unknown, fallback = "USD") {
  const currency = (cleanText(value) || fallback || "USD").toUpperCase();
  if (!/^[A-Z]{3}$/.test(currency)) throw new Error("Currency must be a 3-letter code like USD, MXN, or CAD.");
  return currency;
}

function normalizeCommercialModel(value: unknown) {
  const text = cleanText(value)?.toLowerCase().replace(/[\s-]+/g, "_");
  if (!text) return null;
  const aliases: Record<string, string> = {
    direct: "direct_cost_plus",
    direct_carrier: "direct_cost_plus",
    cost_plus: "direct_cost_plus",
    direct_cost_plus: "direct_cost_plus",
    carrier_share: "carrier_share",
    shared_margin: "carrier_share",
    share: "carrier_share",
    xbf: "xbf_buy_sell",
    buy_sell: "xbf_buy_sell",
    xbf_buy_sell: "xbf_buy_sell"
  };
  const normalized = aliases[text] || text;
  return ["direct_cost_plus", "carrier_share", "xbf_buy_sell"].includes(normalized) ? normalized : null;
}

function availabilityValidationStatus(value: unknown, mirrorEnabled: boolean) {
  const text = cleanText(value)?.toLowerCase();
  if (text && ["not_requested", "mirror_requested", "mirror_enabled", "validated", "rejected"].includes(text)) return text;
  return mirrorEnabled ? "mirror_requested" : "not_requested";
}

function baseTrailerName(value: unknown) {
  const text = cleanText(value) || "Dry Van";
  const cleaned = text
    .replace(/\s*-\s*hazmat\s*reefer\s*$/i, "")
    .replace(/\s*-\s*hazmat\s*$/i, "")
    .replace(/\s*-\s*reefer\s*$/i, "")
    .replace(/\s+hazmat\s+reefer\s*$/i, "")
    .replace(/\s+hazmat\s*$/i, "")
    .replace(/\s+reefer\s*$/i, "")
    .trim();
  return cleaned || "Dry Van";
}

function trailerWithFlags(trailer: unknown, hazmat: unknown, temperatureControlled: unknown) {
  const suffix = [
    cleanBoolean(hazmat) ? "Hazmat" : null,
    cleanBoolean(temperatureControlled) ? "Reefer" : null
  ].filter(Boolean).join(" ");
  const base = baseTrailerName(trailer);
  return suffix ? `${base} - ${suffix}` : base;
}

function normalizeStagingPatch(input: Record<string, unknown>, current: Record<string, unknown> = {}) {
  const patch: Record<string, unknown> = {};
  const textFields = [
    "vendor_domain",
    "vendor_reference",
    "rfx_id",
    "row_id",
    "origin",
    "destination",
    "equipment",
    "trailer",
    "config",
    "operation",
    "service",
    "driver",
    "mx_border_crossing_point",
    "us_border_crossing_point",
    "mx_linehaul",
    "us_linehaul",
    "us_miles",
    "fsc",
    "fuel",
    "border_crossing_fee",
    "flat_rate",
    "all_in_rate",
    "currency",
    "weekly_capacity",
    "notes",
    "accessorials",
    "normalized_origin",
    "normalized_destination",
    "origin_market",
    "origin_country",
    "origin_zip_prefix",
    "origin_city",
    "origin_state",
    "origin_region",
    "origin_match_reason",
    "origin_match_source",
    "destination_market",
    "destination_country",
    "destination_zip_prefix",
    "destination_city",
    "destination_state",
    "destination_region",
    "destination_match_reason",
    "destination_match_source",
    "normalized_equipment",
    "normalized_trailer",
    "normalized_config",
    "normalized_operation",
    "normalized_service",
    "normalized_driver",
    "catalog_match_status",
    "location_match_status",
    "mileage_source",
    "lane_type",
    "leg_status",
    "leg_summary",
    "fuel_region",
    "fuel_source",
    "mx_fuel_source",
    "fx_source"
  ];

  for (const field of textFields) {
    if (input[field] !== undefined) patch[field] = cleanText(input[field]);
  }

  for (const field of ["mx_linehaul", "us_linehaul", "us_miles", "fsc", "fuel", "border_crossing_fee", "flat_rate", "all_in_rate"]) {
    if (input[field] !== undefined) patch[field] = cleanRateText(input[field]);
  }

  if (input.quote_date !== undefined) patch.quote_date = cleanDate(input.quote_date);
  if (input.hazmat !== undefined) patch.hazmat = cleanBoolean(input.hazmat);
  if (input.temperature_controlled !== undefined) patch.temperature_controlled = cleanBoolean(input.temperature_controlled);
  if (input.origin_match_manual !== undefined) patch.origin_match_manual = cleanBoolean(input.origin_match_manual);
  if (input.destination_match_manual !== undefined) patch.destination_match_manual = cleanBoolean(input.destination_match_manual);

  if (input.trailer !== undefined || input.hazmat !== undefined || input.temperature_controlled !== undefined) {
    const nextHazmat = input.hazmat !== undefined ? input.hazmat : current.hazmat;
    const nextTemperatureControlled = input.temperature_controlled !== undefined ? input.temperature_controlled : current.temperature_controlled;
    patch.trailer = trailerWithFlags(
      input.trailer !== undefined ? input.trailer : current.trailer,
      nextHazmat,
      nextTemperatureControlled
    );
    patch.normalized_trailer = patch.trailer;
    patch.hazmat = cleanBoolean(nextHazmat);
    patch.temperature_controlled = cleanBoolean(nextTemperatureControlled);
  }

  const status = cleanText(input.status)?.toLowerCase();
  if (status && ["pending_review", "approved", "rejected", "archived"].includes(status)) patch.status = status;

  if (input.confidence !== undefined) {
    patch.confidence = Math.max(0, Math.min(1, Number(input.confidence) || 0));
  }

  if (input.calculated_miles !== undefined) patch.calculated_miles = Number(input.calculated_miles) || null;
  if (input.calculated_km !== undefined) patch.calculated_km = Number(input.calculated_km) || null;
  if (input.carrier_fsc_per_mile !== undefined) patch.carrier_fsc_per_mile = Number(input.carrier_fsc_per_mile) || null;
  if (input.normalized_fsc_per_mile !== undefined) patch.normalized_fsc_per_mile = Number(input.normalized_fsc_per_mile) || null;
  if (input.normalized_fsc_total !== undefined) patch.normalized_fsc_total = Number(input.normalized_fsc_total) || null;
  if (input.fuel_diesel_per_gallon !== undefined) patch.fuel_diesel_per_gallon = Number(input.fuel_diesel_per_gallon) || null;
  if (input.fuel_delta !== undefined) patch.fuel_delta = Number(input.fuel_delta) || null;
  if (input.normalized_all_in_rate !== undefined) patch.normalized_all_in_rate = Number(input.normalized_all_in_rate) || null;
  if (input.mx_diesel_mxn_per_liter !== undefined) patch.mx_diesel_mxn_per_liter = Number(input.mx_diesel_mxn_per_liter) || null;
  if (input.mx_diesel_usd_per_liter !== undefined) patch.mx_diesel_usd_per_liter = Number(input.mx_diesel_usd_per_liter) || null;
  if (input.fx_rate_mxn_usd !== undefined) patch.fx_rate_mxn_usd = Number(input.fx_rate_mxn_usd) || null;
  if (input.mx_fuel_efficiency_km_per_liter !== undefined) patch.mx_fuel_efficiency_km_per_liter = Number(input.mx_fuel_efficiency_km_per_liter) || null;
  if (input.mx_fuel_factor !== undefined) patch.mx_fuel_factor = Number(input.mx_fuel_factor) || null;
  if (input.mx_fuel_cost_usd !== undefined) patch.mx_fuel_cost_usd = Number(input.mx_fuel_cost_usd) || null;
  if (input.origin_match_confidence !== undefined) patch.origin_match_confidence = Number(input.origin_match_confidence) || null;
  if (input.destination_match_confidence !== undefined) patch.destination_match_confidence = Number(input.destination_match_confidence) || null;
  if (input.fuel_index_date !== undefined) patch.fuel_index_date = cleanDate(input.fuel_index_date);
  if (input.origin_location_candidates !== undefined) patch.origin_location_candidates = Array.isArray(input.origin_location_candidates) ? input.origin_location_candidates : [];
  if (input.destination_location_candidates !== undefined) patch.destination_location_candidates = Array.isArray(input.destination_location_candidates) ? input.destination_location_candidates : [];

  const routeParts = [
    patch.origin,
    patch.destination,
    patch.equipment,
    patch.trailer,
    patch.config,
    patch.operation,
    patch.service,
    patch.driver,
    patch.mx_border_crossing_point && patch.us_border_crossing_point
      ? `${patch.mx_border_crossing_point}/${patch.us_border_crossing_point}`
      : patch.mx_border_crossing_point || patch.us_border_crossing_point
  ].filter(Boolean);
  const rfxKey = [patch.rfx_id, patch.row_id].filter(Boolean).join("-");

  if (routeParts.length) patch.route_key = routeParts.join(" ");
  if (rfxKey) patch.rfx_key = rfxKey;
  if (routeParts.length || rfxKey) patch.business_key = [rfxKey, routeParts.join(" ")].filter(Boolean).join(" ");

  return patch;
}

function cleanDate(value: unknown) {
  const text = cleanText(value);
  if (!text) return null;

  const isoMatch = text.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (isoMatch) return `${isoMatch[1]}-${isoMatch[2]}-${isoMatch[3]}`;

  const slashMatch = text.match(/^(\d{1,2})[/-](\d{1,2})[/-](\d{2,4})$/);
  if (slashMatch) {
    const first = Number(slashMatch[1]);
    const second = Number(slashMatch[2]);
    const year = Number(slashMatch[3].length === 2 ? `20${slashMatch[3]}` : slashMatch[3]);
    const month = first > 12 ? second : first;
    const day = first > 12 ? first : second;
    if (month >= 1 && month <= 12 && day >= 1 && day <= 31) {
      return `${year}-${String(month).padStart(2, "0")}-${String(day).padStart(2, "0")}`;
    }
  }

  const parsed = new Date(text);
  return Number.isNaN(parsed.getTime()) ? null : parsed.toISOString().slice(0, 10);
}

function shipperActionDueDate(daysFromNow: number) {
  const date = new Date();
  date.setUTCHours(0, 0, 0, 0);
  date.setUTCDate(date.getUTCDate() + Math.max(0, Math.round(daysFromNow)));
  return date.toISOString().slice(0, 10);
}

function cleanNumber(value: unknown) {
  if (value === null || value === undefined || value === "") return null;
  const rateText = cleanRateText(value);
  if (rateText) return Number(rateText);
  const numberValue = Number(value);
  return Number.isFinite(numberValue) ? numberValue : null;
}

function normalizeHeaderKey(value: unknown) {
  return String(value ?? "")
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .toLowerCase()
    .replace(/[#%()[\]{}:;.,/\\|_+-]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function resolveVendorReferenceFromRows(vendors: Record<string, unknown>[], reference: unknown) {
  const ranked = vendors
    .map((vendor) => ({ vendor, ...scoreVendorReference(vendor, reference) }))
    .filter((match) => match.score >= 75)
    .sort((a, b) => b.score - a.score);
  return ranked[0] || null;
}

function vendorById(vendors: Record<string, unknown>[]) {
  return new Map(vendors.map((vendor) => [cleanText(vendor.id), vendor]).filter(([id]) => Boolean(id)) as [string, Record<string, unknown>][]);
}

function vendorLinkPatchFromRows(vendors: Record<string, unknown>[], reference: unknown) {
  if (!cleanText(reference)) return {};
  const match = resolveVendorReferenceFromRows(vendors, reference);
  const fallbackDomain = domainFromVendorReference(reference);
  if (!match) return { vendor_id: null, vendor_domain: fallbackDomain || cleanText(reference) };
  return {
    vendor_id: match.vendor.id,
    vendor_domain: normalizeDomain(match.vendor.domain) || match.domain || fallbackDomain || cleanText(reference)
  };
}

function uploadVendorRecord(upload: Record<string, unknown>) {
  return typeof upload.vendors === "object" && upload.vendors ? upload.vendors as Record<string, unknown> : {};
}

function uploadVendorDomain(upload: Record<string, unknown>) {
  const vendor = uploadVendorRecord(upload);
  return domainFromVendorReference(vendor.domain)
    || domainFromVendorReference(vendor.primary_email)
    || domainFromVendorReference(upload.vendor_hint);
}

function templateRowInput(mapped: Record<string, unknown>, upload: Record<string, unknown>) {
  const inheritedVendorDomain = uploadVendorDomain(upload);
  const hasOriginLocationMetadata = [
    mapped.origin_zip_prefix,
    mapped.origin_state,
    mapped.origin_country,
    mapped.origin_market,
    mapped.origin_region
  ].some(cleanText);
  const hasDestinationLocationMetadata = [
    mapped.destination_zip_prefix,
    mapped.destination_state,
    mapped.destination_country,
    mapped.destination_market,
    mapped.destination_region
  ].some(cleanText);
  // vendor_domain holds only a real carrier domain; a bare name or personal
  // email from the template is kept as vendor_reference (the template's
  // "Vendor Name" column is the intended home for those).
  const templateVendorDomain = carrierDomain(mapped.vendor_domain) || carrierDomain(inheritedVendorDomain);
  const templateVendorReference = cleanText(mapped.vendor_name)
    || (carrierDomain(mapped.vendor_domain) ? null : cleanText(mapped.vendor_domain))
    || null;
  const input: Record<string, unknown> = {
    vendor_domain: templateVendorDomain,
    vendor_reference: templateVendorReference,
    rfx_id: mapped.rfx_id || upload.rfx_hint,
    row_id: mapped.row_id,
    quote_date: mapped.quote_date,
    origin: mapped.origin,
    origin_zip_prefix: mapped.origin_zip_prefix,
    origin_state: mapped.origin_state,
    origin_country: mapped.origin_country,
    origin_market: mapped.origin_market,
    origin_region: mapped.origin_region,
    origin_match_manual: hasOriginLocationMetadata ? true : mapped.origin_match_manual,
    origin_match_source: hasOriginLocationMetadata ? "template" : mapped.origin_match_source,
    origin_match_reason: hasOriginLocationMetadata ? "template supplied location metadata" : mapped.origin_match_reason,
    destination: mapped.destination,
    destination_zip_prefix: mapped.destination_zip_prefix,
    destination_state: mapped.destination_state,
    destination_country: mapped.destination_country,
    destination_market: mapped.destination_market,
    destination_region: mapped.destination_region,
    destination_match_manual: hasDestinationLocationMetadata ? true : mapped.destination_match_manual,
    destination_match_source: hasDestinationLocationMetadata ? "template" : mapped.destination_match_source,
    destination_match_reason: hasDestinationLocationMetadata ? "template supplied location metadata" : mapped.destination_match_reason,
    equipment: mapped.equipment,
    trailer: mapped.trailer,
    config: mapped.config,
    operation: mapped.operation,
    service: mapped.service,
    driver: mapped.driver,
    mx_border_crossing_point: mapped.mx_border_crossing_point,
    us_border_crossing_point: mapped.us_border_crossing_point,
    mx_linehaul: mapped.mx_linehaul,
    us_linehaul: mapped.us_linehaul,
    us_miles: mapped.us_miles,
    fsc: mapped.fsc,
    fuel: mapped.fuel,
    border_crossing_fee: mapped.border_crossing_fee,
    all_in_rate: mapped.all_in_rate,
    currency: mapped.currency || "USD",
    weekly_capacity: mapped.weekly_capacity,
    notes: mapped.notes,
    hazmat: mapped.hazmat,
    temperature_controlled: mapped.temperature_controlled
  };

  const distance = cleanNumber(mapped.distance);
  const distanceType = normalizeHeaderKey(mapped.distance_type);
  if (distance !== null) {
    if (distanceType.includes("km") || distanceType.includes("kilomet")) input.calculated_km = distance;
    else input.calculated_miles = distance;
  }

  return input;
}

function templateMappedRows(templateRows: Record<string, unknown>[]) {
  return templateRows
    .map((row) => (row.mapped && typeof row.mapped === "object" ? row.mapped as Record<string, unknown> : {}))
    .filter((mapped) => Object.keys(mapped).length);
}

function templateLocationScope(templateRows: Record<string, unknown>[]) {
  const references = new Set<string>();
  const stateCodes = new Set<string>();
  const zipPrefixes = new Set<string>();
  const locationKeys = new Set<string>();

  for (const mapped of templateMappedRows(templateRows)) {
    for (const field of ["origin_zip_prefix", "destination_zip_prefix"]) {
      const value = cleanText(mapped[field]);
      if (!value) continue;
      const numericPostal = value.match(/\b\d{3,5}\b/)?.[0] || "";
      if (numericPostal) {
        zipPrefixes.add(numericPostal);
        if (numericPostal.length > 3) zipPrefixes.add(numericPostal.slice(0, 3));
      }
      const caPostal = catalogKey(value).match(/\b[A-Z]\d[A-Z]\b/)?.[0] || "";
      if (caPostal) zipPrefixes.add(caPostal);
    }
    for (const field of ["origin_state", "destination_state"]) {
      const value = cleanText(mapped[field]);
      if (!value) continue;
      stateCodes.add(value.toUpperCase());
      stateCodes.add(normalizedLocationStateCode(value).toUpperCase());
    }
    for (const field of ["origin", "destination", "mx_border_crossing_point", "us_border_crossing_point"]) {
      const value = cleanText(mapped[field]);
      if (!value) continue;
      references.add(value);
      const profile = locationTextProfile(value);
      if (profile.lookup) locationKeys.add(profile.lookup);

      for (const token of profile.tokens) {
        const normalizedState = normalizedLocationStateCode(token).toUpperCase();
        if (LOCATION_MX_STATES.has(token) || LOCATION_US_STATES.has(token) || LOCATION_CA_PROVINCES.has(token)) {
          stateCodes.add(token.toUpperCase());
          stateCodes.add(normalizedState);
        }
      }

      const numericPostal = profile.lookup.match(/\b\d{3,5}\b/)?.[0] || "";
      if (numericPostal) {
        if (profile.explicitMx) zipPrefixes.add(numericPostal);
        else zipPrefixes.add(numericPostal.slice(0, 3));
        if (numericPostal.length > 3 && !profile.explicitMx) zipPrefixes.add(numericPostal);
      }
      const caPostal = profile.lookup.match(/\b[A-Z]\d[A-Z]\b/)?.[0] || "";
      if (caPostal && !profile.explicitMx) zipPrefixes.add(caPostal);
    }
  }

  return {
    references: [...references].slice(0, 500),
    stateCodes: [...stateCodes].filter(Boolean).slice(0, 100),
    zipPrefixes: [...zipPrefixes].filter(Boolean).slice(0, 500),
    locationKeys: [...locationKeys].filter(Boolean).slice(0, 500)
  };
}

async function fetchScopedTemplateLocations(
  supabase: ReturnType<typeof createClient>,
  templateRows: Record<string, unknown>[]
) {
  const selectColumns = "source,location_key,raw_value,zip_prefix,metro_city,city,state_code,state_name,country,market,region";
  const scope = templateLocationScope(templateRows);
  const byKey = new Map<string, Record<string, unknown>>();
  const addRows = (rows: Record<string, unknown>[] | null | undefined) => {
    for (const row of rows || []) {
      const key = cleanText(row.location_key) || cleanText(row.raw_value) || cleanText(row.id);
      if (!key) continue;
      byKey.set(key, row);
    }
  };

  for (const chunk of chunkValues(scope.zipPrefixes, 100)) {
    const result = await supabase
      .from("rateware_locations")
      .select(selectColumns)
      .eq("active", true)
      .in("zip_prefix", chunk)
      .limit(5000);
    if (result.error) throw result.error;
    addRows(result.data || []);
  }

  for (const chunk of chunkValues(scope.stateCodes, 50)) {
    const result = await supabase
      .from("rateware_locations")
      .select(selectColumns)
      .eq("active", true)
      .in("state_code", chunk)
      .limit(8000);
    if (result.error) throw result.error;
    addRows(result.data || []);
  }

  for (const chunk of chunkValues(scope.locationKeys, 100)) {
    const result = await supabase
      .from("rateware_locations")
      .select(selectColumns)
      .eq("active", true)
      .in("location_key", chunk)
      .limit(2000);
    if (result.error) throw result.error;
    addRows(result.data || []);
  }

  if (!byKey.size) {
    const result = await supabase
      .from("rateware_locations")
      .select(selectColumns)
      .eq("active", true)
      .limit(3000);
    if (result.error) throw result.error;
    addRows(result.data || []);
  }

  return [...byKey.values()];
}

function templateMileageKeys(templateRows: Record<string, unknown>[]) {
  const keys = new Set<string>();
  for (const mapped of templateMappedRows(templateRows)) {
    const origin = mapped.origin;
    const destination = mapped.destination;
    if (!cleanText(origin) || !cleanText(destination)) continue;
    [
      [origin, destination, mapped.equipment, mapped.trailer, mapped.config, mapped.operation, mapped.service, mapped.driver],
      [origin, destination, mapped.equipment],
      [origin, destination]
    ].forEach((parts) => {
      const key = catalogKey(parts.filter(Boolean).join(" "));
      if (key) keys.add(key);
    });
  }
  return [...keys].slice(0, 1000);
}

async function fetchScopedTemplateMileage(
  supabase: ReturnType<typeof createClient>,
  templateRows: Record<string, unknown>[]
) {
  const keys = templateMileageKeys(templateRows);
  if (!keys.length) return [];
  const rows: Record<string, unknown>[] = [];
  for (const chunk of chunkValues(keys, 100)) {
    const result = await supabase
      .from("rateware_lane_mileage")
      .select("source,route_key,miles,km")
      .eq("active", true)
      .in("route_key", chunk)
      .limit(1000);
    if (result.error) throw result.error;
    rows.push(...(result.data || []));
  }
  return rows;
}

function rowHasRateSignal(row: Record<string, unknown>) {
  return Boolean(
    cleanRateText(row.all_in_rate) ||
      cleanRateText(row.mx_linehaul) ||
      cleanRateText(row.us_linehaul) ||
      cleanRateText(row.fsc) ||
      cleanRateText(row.border_crossing_fee)
  );
}

async function bulkImportStructuredUpload(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  rawUploadId: string,
  templateRows: unknown[] = [],
  templateWarnings: unknown[] = [],
  options: Record<string, unknown> = {}
) {
  if (!rawUploadId) throw new Error("raw_upload_id is required.");
  const replaceExisting = options.replace_existing === undefined ? true : cleanBoolean(options.replace_existing);
  const expectedRateRows = Math.max(0, Number(options.expected_rate_rows || templateRows.length) || templateRows.length);
  const batchIndex = Math.max(0, Number(options.batch_index || 0) || 0);
  const batchCount = Math.max(1, Number(options.batch_count || 1) || 1);
  const importedBefore = Math.max(0, Number(options.imported_before || 0) || 0);
  const skippedBefore = Math.max(0, Number(options.skipped_before || 0) || 0);

  const uploadResult = await supabase
    .from("raw_uploads")
    .select("*, vendors(vendor_name,domain,primary_email)")
    .eq("id", rawUploadId)
    .single();
  if (uploadResult.error) throw uploadResult.error;
  const upload = uploadResult.data || {};
  if (cleanText(upload.document_type) !== "xlsx") {
    throw new Error("Bulk template import is only available for XLSX uploads.");
  }
  const inheritedVendorId = cleanText(upload.vendor_id);
  const inheritedVendorDomain = uploadVendorDomain(upload);

  const parsed = {
    rows: Array.isArray(templateRows)
      ? templateRows
          .map((row) => (row && typeof row === "object" ? row as Record<string, unknown> : null))
          .filter(Boolean) as Record<string, unknown>[]
      : [],
    warnings: Array.isArray(templateWarnings) ? templateWarnings.map(cleanText).filter(Boolean) as string[] : []
  };
  if (!parsed.rows.length) {
    throw new Error(parsed.warnings[0] || "No structured template rows were found in this workbook.");
  }

  const vendorsPromise = inheritedVendorId
    ? Promise.resolve({ data: [], error: null })
    : supabase
        .from("vendors")
        .select("id,vendor_name,legal_name,domain,primary_email,secondary_emails,status,base_stage")
        .eq("owner_email", user.owner_email)
        .limit(5000);

  const [catalogResult, scopedLocations, scopedMileage, vendorsResult] = await Promise.all([
    supabase
      .from("rateware_catalog_items")
      .select("source,category,raw_value,normalized_value,code")
      .eq("active", true)
      .limit(10000),
    fetchScopedTemplateLocations(supabase, parsed.rows),
    fetchScopedTemplateMileage(supabase, parsed.rows),
    vendorsPromise
  ]);
  for (const result of [catalogResult, vendorsResult]) {
    if (result.error) throw result.error;
  }

  const jobResult = await supabase
    .from("interpretation_jobs")
    .insert({
      raw_upload_id: rawUploadId,
      status: "running",
      model: `structured-template-import ${batchIndex + 1}/${batchCount}`
    })
    .select("id")
    .single();
  if (jobResult.error) throw jobResult.error;

  const catalog = buildCatalogIndex(catalogResult.data || []);
  const locationIndex = buildLocationIndex(scopedLocations || []);
  const mileage = new Map((scopedMileage || []).map((lane) => [catalogKey(lane.route_key), lane]));
  const vendors = vendorsResult.data || [];
  const rowsToInsert: Record<string, unknown>[] = [];
  const warnings = [...parsed.warnings];
  let skipped = 0;

  for (const [index, parsedRow] of parsed.rows.entries()) {
    const mapped = parsedRow.mapped && typeof parsedRow.mapped === "object" ? parsedRow.mapped as Record<string, unknown> : {};
    const raw = parsedRow.raw && typeof parsedRow.raw === "object" ? parsedRow.raw as Record<string, unknown> : {};
    const sheetName = cleanText(parsedRow.sheet_name) || "Sheet";
    const sourceRowNumber = Number(parsedRow.source_row_number || index + 1) || index + 1;
    const input = templateRowInput(mapped, upload);
    const patch = normalizeStagingPatch(input, {});
    const rowWarnings: string[] = [];
    if (!patch.origin || !patch.destination) rowWarnings.push("missing origin or destination");
    if (!rowHasRateSignal(patch)) rowWarnings.push("missing usable rate");
    if (rowWarnings.length) {
      skipped += 1;
      if (warnings.length < 20) warnings.push(`${sheetName} row ${sourceRowNumber}: ${rowWarnings.join(", ")}.`);
      continue;
    }

    const vendorReference = patch.vendor_domain || mapped.vendor_domain || mapped.vendor_name || upload.vendor_hint;
    if (inheritedVendorId) {
      Object.assign(patch, {
        vendor_id: inheritedVendorId,
        vendor_domain: inheritedVendorDomain || domainFromVendorReference(vendorReference) || patch.vendor_domain || null
      });
    } else {
      Object.assign(patch, vendorLinkPatchFromRows(vendors, vendorReference));
    }
    Object.assign(patch, normalizeRowWithCurrentCatalog(patch, catalog, locationIndex, mileage));

    rowsToInsert.push({
      ...patch,
      raw_upload_id: rawUploadId,
      interpretation_job_id: jobResult.data.id,
      status: "pending_review",
      confidence: 1,
      row_id: patch.row_id || String(index + 1),
      extraction_warnings: [],
      audit_flags: [],
      field_confidence: {
        import_method: "structured_template",
        all_fields: 1
      },
      source_evidence: {
        import_method: "structured_template",
        sheet_name: sheetName,
        source_row_number: sourceRowNumber,
        mapped_fields: Object.keys(mapped)
      },
      extracted_payload: {
        import_method: "structured_template",
        sheet_name: sheetName,
        source_row_number: sourceRowNumber,
        raw_values: raw
      }
    });
  }

  if (!rowsToInsert.length) {
    await supabase
      .from("interpretation_jobs")
      .update({ status: "failed", completed_at: new Date().toISOString(), extracted_rows: 0, error_message: "No usable template rows found." })
      .eq("id", jobResult.data.id);
    throw new Error(warnings[0] || "No usable template rows found.");
  }

  let existingRowsResult: { data: Array<{ id: string }> | null; error: unknown } = { data: [], error: null };
  if (replaceExisting) {
    existingRowsResult = await supabase
      .from("rate_staging")
      .select("id")
      .eq("raw_upload_id", rawUploadId)
      .in("status", ["pending_review", "rejected"]);
    if (existingRowsResult.error) throw existingRowsResult.error;
  }

  const insertedRows: Record<string, unknown>[] = [];
  for (let index = 0; index < rowsToInsert.length; index += 500) {
    const result = await supabase
      .from("rate_staging")
      .insert(rowsToInsert.slice(index, index + 500))
      .select("id");
    if (result.error) throw result.error;
    insertedRows.push(...(result.data || []));
  }

  const existingIds = (existingRowsResult.data || []).map((row) => row.id).filter(Boolean);
  if (existingIds.length) {
    const archiveResult = await supabase
      .from("rate_staging")
      .update({ status: "archived" })
      .in("id", existingIds);
    if (archiveResult.error) throw archiveResult.error;
  }

  const totalImportedRows = importedBefore + insertedRows.length;
  const totalSkippedRows = skippedBefore + skipped;
  const auditStatus = warnings.length || totalSkippedRows ? "needs_review" : "ok";
  const auditWarnings = warnings.slice(0, 25);
  const now = new Date().toISOString();
  const [jobUpdate, uploadUpdate] = await Promise.all([
    supabase
      .from("interpretation_jobs")
      .update({
        status: "completed",
        completed_at: now,
        extracted_rows: insertedRows.length,
        error_message: null
      })
      .eq("id", jobResult.data.id),
    supabase
      .from("raw_uploads")
      .update({
        status: "staged",
        vendor_hint: upload.vendor_hint || inheritedVendorDomain || null,
        interpreted_at: now,
        error_message: null,
        interpreted_rate_rows: totalImportedRows,
        expected_rate_rows: expectedRateRows,
        audit_status: auditStatus,
        audit_warnings: auditWarnings,
        interpretation_audit: {
          status: auditStatus,
          import_method: "structured_template",
          batch_index: batchIndex,
          batch_count: batchCount,
          expected_rate_rows: expectedRateRows,
          interpreted_rate_rows: totalImportedRows,
          skipped_rows: totalSkippedRows,
          warning_count: warnings.length,
          warnings: auditWarnings
        }
      })
      .eq("id", rawUploadId)
  ]);
  if (jobUpdate.error) throw jobUpdate.error;
  if (uploadUpdate.error) throw uploadUpdate.error;

  await writeAuditLog(supabase, user, "upload.bulk_template_import", "raw_uploads", rawUploadId, `Bulk imported ${insertedRows.length} structured rate row(s)`, {
    filename: upload.original_filename,
    batch_index: batchIndex,
    batch_count: batchCount,
    expected_rows: expectedRateRows,
    imported_rows: insertedRows.length,
    total_imported_rows: totalImportedRows,
    skipped_rows: skipped,
    total_skipped_rows: totalSkippedRows,
    warning_count: warnings.length
  });

  return {
    imported_rows: insertedRows.length,
    expected_rows: expectedRateRows,
    skipped_rows: skipped,
    total_imported_rows: totalImportedRows,
    total_skipped_rows: totalSkippedRows,
    batch_index: batchIndex,
    batch_count: batchCount,
    warnings: auditWarnings
  };
}

function randomToken() {
  const bytes = new Uint8Array(18);
  crypto.getRandomValues(bytes);
  return Array.from(bytes).map((byte) => byte.toString(16).padStart(2, "0")).join("");
}

function normalizeRfxEvent(input: Record<string, unknown>) {
  const rfxId = cleanText(input.rfx_id || input.rfx || input.event_id) || `RFx-${new Date().toISOString().slice(0, 10)}`;
  const eventType = cleanText(input.event_type || input.type)?.toLowerCase() || "spot";
  const status = cleanText(input.status)?.toLowerCase() || "draft";
  const bidVisibilityMode = cleanText(input.bid_visibility_mode || input.visibility_mode)?.toLowerCase() || "anonymous_rank";
  return {
    rfx_id: rfxId,
    name: cleanText(input.name || input.event_name || input.title) || rfxId,
    customer: cleanText(input.customer || input.shipper || input.account),
    event_type: ["spot", "rfx", "bid"].includes(eventType) ? eventType : "spot",
    status: ["draft", "open", "closed", "awarded", "archived"].includes(status) ? status : "draft",
    bid_visibility_mode: ["private", "anonymous_rank", "open_leaderboard"].includes(bidVisibilityMode) ? bidVisibilityMode : "anonymous_rank",
    due_date: cleanDate(input.due_date || input.deadline),
    notes: cleanText(input.notes || input.description),
    updated_at: new Date().toISOString()
  };
}

function normalizeRfxEventPatch(input: Record<string, unknown>) {
  const patch: Record<string, unknown> = {};
  if (input.rfx_id !== undefined || input.rfx !== undefined) patch.rfx_id = cleanText(input.rfx_id || input.rfx);
  if (input.name !== undefined || input.event_name !== undefined || input.title !== undefined) patch.name = cleanText(input.name || input.event_name || input.title);
  if (input.customer !== undefined || input.shipper !== undefined || input.account !== undefined) patch.customer = cleanText(input.customer || input.shipper || input.account);
  if (input.event_type !== undefined || input.type !== undefined) {
    const eventType = cleanText(input.event_type || input.type)?.toLowerCase();
    if (eventType && ["spot", "rfx", "bid"].includes(eventType)) patch.event_type = eventType;
  }
  if (input.status !== undefined) {
    const status = cleanText(input.status)?.toLowerCase();
    if (status && ["draft", "open", "closed", "awarded", "archived"].includes(status)) patch.status = status;
  }
  if (input.bid_visibility_mode !== undefined || input.visibility_mode !== undefined) {
    const bidVisibilityMode = cleanText(input.bid_visibility_mode || input.visibility_mode)?.toLowerCase();
    if (bidVisibilityMode && ["private", "anonymous_rank", "open_leaderboard"].includes(bidVisibilityMode)) {
      patch.bid_visibility_mode = bidVisibilityMode;
    }
  }
  if (input.due_date !== undefined || input.deadline !== undefined) patch.due_date = cleanDate(input.due_date || input.deadline);
  if (input.notes !== undefined || input.description !== undefined) patch.notes = cleanText(input.notes || input.description);
  patch.updated_at = new Date().toISOString();
  return patch;
}

function normalizeRfxLane(input: Record<string, unknown>, index = 0) {
  const origin = cleanText(input.origin || input.orig || input.origin_city || input.from);
  const destination = cleanText(input.destination || input.dest || input.destination_city || input.to);
  return {
    lane_number: Number(input.lane_number || input.lane || input.seq || index + 1) || index + 1,
    origin,
    origin_city: cleanText(input.origin_city || input.o_city),
    origin_state: cleanText(input.origin_state || input.o_state || input.origin_st || input.o_st),
    origin_country: cleanText(input.origin_country || input.o_country),
    origin_market: cleanText(input.origin_market || input.o_market),
    origin_region: cleanText(input.origin_region || input.o_region),
    destination,
    destination_city: cleanText(input.destination_city || input.d_city),
    destination_state: cleanText(input.destination_state || input.d_state || input.destination_st || input.d_st),
    destination_country: cleanText(input.destination_country || input.d_country),
    destination_market: cleanText(input.destination_market || input.d_market),
    destination_region: cleanText(input.destination_region || input.d_region),
    equipment: cleanText(input.equipment || input.equip),
    trailer: cleanText(input.trailer || input.trailer_type),
    config: cleanText(input.config || input.configuration),
    operation: cleanText(input.operation),
    service: cleanText(input.service),
    rfx_segment_key: cleanText(input.rfx_segment_key || input.segment_key),
    rfx_segment_name: cleanText(input.rfx_segment_name || input.segment_name || input.operating_segment),
    weekly_volume: cleanNumber(input.weekly_volume || input.weekly_loads || input.loads_per_week || input.volume),
    annual_volume: cleanNumber(input.annual_volume || input.annual_loads),
    target_rate: cleanNumber(input.target_rate || input.target || input.budget),
    currency: cleanText(input.currency)?.toUpperCase() || "USD",
    incumbent_vendor: cleanText(input.incumbent_vendor || input.incumbent),
    logistics_model: cleanText(input.logistics_model || input.logistic_model || input.modelo_logistico || input.shipment_model),
    operation_criteria: cleanText(input.operation_criteria || input.operational_criteria || input.criterios_de_operacion),
    business_rules: cleanText(input.business_rules || input.reglas_de_negocio),
    service_specifications: cleanText(input.service_specifications || input.service_specs || input.especificaciones_de_servicio),
    carrier_requirements: cleanText(input.carrier_requirements || input.required_carrier_profile || input.perfil_requerido || input.carrier_profile),
    other_notes: cleanText(input.other_notes || input.otras_notas || input.notas_adicionales || input.additional_notes),
    notes: cleanText(input.notes || input.lane_notes),
    updated_at: new Date().toISOString()
  };
}

function normalizeRfxLanePatch(input: Record<string, unknown>) {
  const patch: Record<string, unknown> = {};
  const textFields = [
    "origin",
    "origin_city",
    "origin_state",
    "origin_country",
    "origin_market",
    "origin_region",
    "destination",
    "destination_city",
    "destination_state",
    "destination_country",
    "destination_market",
    "destination_region",
    "equipment",
    "trailer",
    "config",
    "operation",
    "service",
    "rfx_segment_key",
    "rfx_segment_name",
    "incumbent_vendor",
    "logistics_model",
    "operation_criteria",
    "business_rules",
    "service_specifications",
    "carrier_requirements",
    "other_notes",
    "notes"
  ];
  const numericFields = ["lane_number", "weekly_volume", "annual_volume", "target_rate"];
  for (const field of textFields) {
    if (Object.prototype.hasOwnProperty.call(input, field)) patch[field] = cleanText(input[field]);
  }
  for (const field of numericFields) {
    if (Object.prototype.hasOwnProperty.call(input, field)) patch[field] = cleanNumber(input[field]);
  }
  if (Object.prototype.hasOwnProperty.call(input, "currency")) {
    patch.currency = cleanText(input.currency)?.toUpperCase() || null;
  }
  if (Object.keys(patch).length) patch.updated_at = new Date().toISOString();
  return patch;
}

function laneText(row: Record<string, unknown>) {
  return [
    row.origin,
    row.origin_city,
    row.origin_state,
    row.origin_country,
    row.origin_market,
    row.origin_region,
    row.destination,
    row.destination_city,
    row.destination_state,
    row.destination_country,
    row.destination_market,
    row.destination_region,
    row.equipment,
    row.trailer,
    row.config,
    row.operation,
    row.service
  ].filter(Boolean).join(" ");
}

function stringMatchScore(left: unknown, right: unknown, weight: number) {
  const a = catalogKey(left);
  const b = catalogKey(right);
  if (!a || !b) return 0;
  if (a === b) return weight;
  if (a.includes(b) || b.includes(a)) return Math.round(weight * 0.65);
  return 0;
}

function sideMatchScore(lane: Record<string, unknown>, rate: Record<string, unknown>, prefix: "origin" | "destination") {
  const normalizedField = prefix === "origin" ? "normalized_origin" : "normalized_destination";
  let score = 0;
  score += stringMatchScore(lane[`${prefix}_market`], rate[`${prefix}_market`], 30);
  score += stringMatchScore(lane[`${prefix}_region`], rate[`${prefix}_region`], 14);
  score += stringMatchScore(lane[`${prefix}_state`], rate[`${prefix}_state`], 14);
  score += stringMatchScore(lane[`${prefix}_country`], rate[`${prefix}_country`], 10);
  score += stringMatchScore(lane[prefix], rate[normalizedField] || rate[prefix], 22);
  score += stringMatchScore(lane[`${prefix}_city`], rate[`${prefix}_city`] || rate[normalizedField] || rate[prefix], 18);
  return Math.min(50, score);
}

function rateFitForLane(lane: Record<string, unknown>, rate: Record<string, unknown>) {
  const score =
    sideMatchScore(lane, rate, "origin") +
    sideMatchScore(lane, rate, "destination") +
    stringMatchScore(lane.equipment, rate.equipment || rate.normalized_equipment, 12) +
    stringMatchScore(lane.trailer, rate.trailer || rate.normalized_trailer, 10) +
    stringMatchScore(lane.config, rate.config || rate.normalized_config, 8) +
    stringMatchScore(lane.operation, rate.operation || rate.normalized_operation, 12) +
    stringMatchScore(lane.service, rate.service || rate.normalized_service, 10);
  return Math.min(100, score);
}

function bestRatewareBenchmark(lane: Record<string, unknown>, rates: Record<string, unknown>[]) {
  const matches = rates
    .map((rate) => ({
      rate,
      score: rateFitForLane(lane, rate),
      amount: numericAmount(rate.all_in_rate)
    }))
    .filter((item) => item.score >= 40 && item.amount !== null)
    .sort((a, b) => b.score - a.score || Number(a.amount) - Number(b.amount));
  const best = matches[0];
  if (!best) return null;
  return {
    rate_id: best.rate.id,
    score: best.score,
    vendor: (best.rate.vendors as Record<string, unknown> | undefined)?.vendor_name || best.rate.vendor_domain || null,
    vendor_domain: best.rate.vendor_domain || null,
    all_in_rate: best.amount,
    currency: best.rate.currency || "USD",
    quote_date: best.rate.quote_date || null,
    origin: best.rate.normalized_origin || best.rate.origin || null,
    destination: best.rate.normalized_destination || best.rate.destination || null
  };
}

function percentileValue(values: number[], percentile: number) {
  const sorted = values.filter((value) => Number.isFinite(value)).sort((a, b) => a - b);
  if (!sorted.length) return null;
  const position = (sorted.length - 1) * percentile;
  const lower = Math.floor(position);
  const upper = Math.ceil(position);
  if (lower === upper) return sorted[lower];
  const weight = position - lower;
  return sorted[lower] + (sorted[upper] - sorted[lower]) * weight;
}

function rateCarrierKey(rate: Record<string, unknown>) {
  return cleanText(rate.vendor_id)
    || normalizeDomain(rate.vendor_domain)
    || normalizeDomain((rate.vendors as Record<string, unknown> | undefined)?.domain)
    || cleanText((rate.vendors as Record<string, unknown> | undefined)?.vendor_name)
    || cleanText(rate.vendor)
    || cleanText(rate.id)
    || "";
}

function supplyDepthForLane(lane: Record<string, unknown>, rates: Record<string, unknown>[]) {
  const matches = rates
    .map((rate) => ({
      rate,
      score: rateFitForLane(lane, rate),
      amount: numericAmount(rate.all_in_rate),
      currency: cleanText(rate.currency || lane.currency || "USD")?.toUpperCase() || "USD"
    }))
    .filter((item) => item.score >= 40 && item.amount !== null)
    .sort((a, b) => Number(a.amount) - Number(b.amount));
  const carrierKeys = new Set(matches.map((item) => rateCarrierKey(item.rate)).filter(Boolean));
  const targetRate = cleanNumber(lane.target_rate);
  const targetCurrency = cleanText(lane.currency)?.toUpperCase() || cleanText(matches[0]?.currency)?.toUpperCase() || "USD";
  const comparableMatches = matches.filter((item) => item.currency === targetCurrency);
  const priceMatches = comparableMatches.length ? comparableMatches : [];
  const amounts = priceMatches.map((item) => Number(item.amount)).filter(Number.isFinite);
  const atOrBelowTarget = targetRate !== null && priceMatches.length
    ? priceMatches.filter((item) => Number(item.amount) <= targetRate).length
    : 0;
  const target_probability = targetRate !== null && priceMatches.length
    ? Math.round((atOrBelowTarget / priceMatches.length) * 100)
    : null;
  const carrierCount = carrierKeys.size;
  const depthScore = Math.min(100, Math.round((carrierCount / 12) * 100));
  const matchScore = matches.length
    ? Math.round(matches.reduce((sum, item) => sum + item.score, 0) / matches.length)
    : 0;
  const likelihood_score = target_probability !== null
    ? Math.round((target_probability * 0.72) + (depthScore * 0.18) + (matchScore * 0.10))
    : Math.round((depthScore * 0.65) + (matchScore * 0.35));
  return {
    carrier_count: carrierCount,
    quote_count: matches.length,
    p25_rate: percentileValue(amounts, 0.25),
    p50_rate: percentileValue(amounts, 0.50),
    p75_rate: percentileValue(amounts, 0.75),
    p90_rate: percentileValue(amounts, 0.90),
    best_rate: amounts[0] ?? null,
    currency: targetCurrency,
    historical_currencies: Array.from(new Set(matches.map((item) => item.currency).filter(Boolean))).sort(),
    comparable_quote_count: priceMatches.length,
    target_currency: targetCurrency,
    target_rate: targetRate,
    target_probability,
    target_probability_reason: targetRate === null ? "target_not_set" : priceMatches.length ? "comparable" : "currency_mismatch",
    likelihood_score,
    match_score: matchScore,
    depth_score: depthScore
  };
}

function invitationWithComparison(invitation: Record<string, unknown>, benchmark: Record<string, unknown> | null) {
  const bidRate = cleanNumber(invitation.bid_rate);
  const benchmarkRate = cleanNumber(benchmark?.all_in_rate);
  return {
    ...invitation,
    bid_delta: bidRate !== null && benchmarkRate !== null ? bidRate - benchmarkRate : null,
    bid_delta_pct: bidRate !== null && benchmarkRate ? ((bidRate - benchmarkRate) / benchmarkRate) * 100 : null,
    benchmark
  };
}

function isQuotedInvitation(invitation: Record<string, unknown>) {
  const status = cleanText(invitation.invitation_status)?.toLowerCase();
  return Boolean(cleanNumber(invitation.bid_rate) !== null || status === "quoted" || status === "bid_submitted");
}

function vendorOwnsRate(vendor: Record<string, unknown>, rate: Record<string, unknown>) {
  if (vendor.id && rate.vendor_id && vendor.id === rate.vendor_id) return true;
  const vendorDomain = normalizeDomain(vendor.domain);
  const rateDomain = normalizeDomain(rate.vendor_domain);
  if (vendorDomain && rateDomain && vendorDomain === rateDomain) return true;
  const emails = vendorEmails(vendor);
  return Boolean(rateDomain && emails.some((email) => email.endsWith(`@${rateDomain}`)));
}

function scoreVendorForLane(vendor: Record<string, unknown>, lane: Record<string, unknown>, rates: Record<string, unknown>[]) {
  let score = 28;
  const evidence: string[] = [];
  const gaps: string[] = [];
  const status = cleanText(vendor.status)?.toLowerCase();
  const baseStage = cleanText(vendor.base_stage)?.toLowerCase();
  if (status === "active") score += 12;
  if (status === "blocked") {
    score -= 80;
    gaps.push("Blocked vendor");
  }
  if (status === "inactive") {
    score -= 20;
    gaps.push("Inactive vendor");
  }
  if (baseStage === "procurement") {
    score += 18;
    evidence.push("Procurement Base carrier");
  } else if (baseStage === "sourcing") {
    score += 8;
    evidence.push("Available in Sourcing Base");
  }
  if (vendor.primary_email) score += 8;
  else gaps.push("Missing email");
  if (vendor.whatsapp_phone) score += 4;
  const vendorText = catalogKey(vendorSearchText(vendor));
  const laneTerms = [
    lane.origin_market,
    lane.destination_market,
    lane.origin_region,
    lane.destination_region,
    lane.origin_state,
    lane.destination_state,
    lane.equipment,
    lane.trailer,
    lane.operation,
    lane.service
  ].map(catalogKey).filter(Boolean);
  const textHits = laneTerms.filter((term) => vendorText.includes(term));
  if (textHits.length) {
    score += Math.min(18, textHits.length * 5);
    evidence.push(`Vendor profile matches ${textHits.slice(0, 3).join(", ")}`);
  }
  const vendorRates = rates.filter((rate) => vendorOwnsRate(vendor, rate));
  const bestRateScore = vendorRates.reduce((best, rate) => Math.max(best, rateFitForLane(lane, rate)), 0);
  if (bestRateScore >= 40) {
    score += Math.min(30, Math.round(bestRateScore / 3));
    evidence.push(`Historical Rateware fit ${bestRateScore}/100`);
  } else {
    gaps.push("No strong historical Rateware lane match");
  }
  return {
    vendor_id: vendor.id,
    vendor_name: vendor.vendor_name,
    domain: vendor.domain,
    primary_email: vendor.primary_email,
    base_stage: vendor.base_stage,
    status: vendor.status,
    fit_score: Math.max(0, Math.min(100, Math.round(score))),
    evidence,
    gaps
  };
}

async function fetchApprovedRateRows(supabase: ReturnType<typeof createClient>) {
  const result = await supabase
    .from("rate_staging")
    .select("*, vendors(vendor_name,domain,primary_email,base_stage,status)")
    .eq("status", "approved")
    .limit(2000);
  if (result.error) throw result.error;
  return result.data || [];
}

async function requireOwnedRfxEvent(supabase: ReturnType<typeof createClient>, user: { owner_email: string | null }, eventId: unknown) {
  const id = cleanText(eventId);
  if (!id) throw new Error("RFx event id is required.");
  const result = await supabase
    .from("rfx_events")
    .select("*")
    .eq("id", id)
    .eq("owner_email", user.owner_email)
    .single();
  if (result.error) throw result.error;
  return result.data;
}

async function requireOwnedRfxLane(supabase: ReturnType<typeof createClient>, user: { owner_email: string | null }, laneId: unknown) {
  const id = cleanText(laneId);
  if (!id) throw new Error("RFx lane id is required.");
  const laneResult = await supabase
    .from("rfx_lanes")
    .select("*, rfx_events!inner(id,owner_email)")
    .eq("id", id)
    .eq("rfx_events.owner_email", user.owner_email)
    .single();
  if (laneResult.error) throw laneResult.error;
  return laneResult.data;
}

async function requireOwnedRfxLaneVendor(supabase: ReturnType<typeof createClient>, user: { owner_email: string | null }, invitationId: unknown) {
  const id = cleanText(invitationId);
  if (!id) throw new Error("RFx invitation id is required.");
  const result = await supabase
    .from("rfx_lane_vendors")
    .select("*, rfx_events!inner(id,rfx_id,name,customer,status,owner_email), rfx_lanes(*), vendors(id,vendor_name,legal_name,domain,primary_email,base_stage,status)")
    .eq("id", id)
    .eq("rfx_events.owner_email", user.owner_email)
    .single();
  if (result.error) throw result.error;
  return result.data || {};
}

function normalizeAwardRole(value: unknown) {
  const role = cleanText(value)?.toLowerCase();
  return role === "backup" ? "backup" : "primary";
}

async function awardRfxLaneVendor(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  input: Record<string, unknown>
) {
  const invitation = await requireOwnedRfxLaneVendor(supabase, user, input.id || input.rfx_lane_vendor_id || input.invitation_id);
  if (cleanNumber(invitation.bid_rate) === null) throw new Error("A carrier bid rate is required before awarding.");
  const role = normalizeAwardRole(input.award_role || input.role);
  const now = new Date().toISOString();

  if (role === "primary") {
    const clearResult = await supabase
      .from("rfx_lane_vendors")
      .update({
        award_role: null,
        award_reason: null,
        award_notes: null,
        awarded_at: null,
        awarded_by: null,
        updated_at: now
      })
      .eq("rfx_lane_id", invitation.rfx_lane_id)
      .eq("award_role", "primary")
      .neq("id", invitation.id);
    if (clearResult.error) throw clearResult.error;
  }

  const result = await supabase
    .from("rfx_lane_vendors")
    .update({
      award_role: role,
      award_reason: cleanText(input.award_reason || input.reason) || (role === "primary" ? "Primary procurement award" : "Backup carrier"),
      award_notes: cleanText(input.award_notes || input.notes),
      awarded_at: now,
      awarded_by: user.owner_email,
      invitation_status: role === "primary" ? "awarded" : "quoted",
      updated_at: now
    })
    .eq("id", invitation.id)
    .select("*, vendors(id,vendor_name,domain,primary_email,base_stage,status)")
    .single();
  if (result.error) throw result.error;

  if (role === "primary") {
    const eventId = cleanText(invitation.rfx_event_id);
    if (eventId) {
      const eventUpdate = await supabase
        .from("rfx_events")
        .update({ status: "awarded", updated_at: now })
        .eq("id", eventId)
        .eq("owner_email", user.owner_email);
      if (eventUpdate.error) throw eventUpdate.error;
    }
  }

  return { row: result.data, before: invitation, award_role: role };
}

async function clearRfxAward(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  input: Record<string, unknown>
) {
  const invitation = await requireOwnedRfxLaneVendor(supabase, user, input.id || input.rfx_lane_vendor_id || input.invitation_id);
  const wasPrimary = cleanText(invitation.award_role) === "primary";
  const nextStatus = cleanText(invitation.invitation_status) === "awarded" ? "quoted" : cleanText(invitation.invitation_status) || "quoted";
  const now = new Date().toISOString();
  const result = await supabase
    .from("rfx_lane_vendors")
    .update({
      award_role: null,
      award_reason: null,
      award_notes: null,
      awarded_at: null,
      awarded_by: null,
      invitation_status: nextStatus,
      updated_at: now
    })
    .eq("id", invitation.id)
    .select("*, vendors(id,vendor_name,domain,primary_email,base_stage,status)")
    .single();
  if (result.error) throw result.error;

  if (wasPrimary && cleanText(invitation.rfx_event_id)) {
    const remaining = await supabase
      .from("rfx_lane_vendors")
      .select("id", { count: "exact", head: true })
      .eq("rfx_event_id", invitation.rfx_event_id)
      .eq("award_role", "primary");
    if (remaining.error) throw remaining.error;
    if (!remaining.count) {
      const eventUpdate = await supabase
        .from("rfx_events")
        .update({ status: "open", updated_at: now })
        .eq("id", invitation.rfx_event_id)
        .eq("owner_email", user.owner_email);
      if (eventUpdate.error) throw eventUpdate.error;
    }
  }

  return { row: result.data, before: invitation };
}

function rfxAwardRateInput(invitation: Record<string, unknown>, event: Record<string, unknown>, index: number, targetStatus: string) {
  const lane = objectRecord(invitation.rfx_lanes);
  const vendor = objectRecord(invitation.vendors);
  const vendorDomain = carrierDomain(vendor.domain) || carrierDomain(vendor.primary_email) || domainFromVendorReference(invitation.vendor_domain);
  const vendorReference = cleanText(vendor.vendor_name || vendor.legal_name || vendorDomain);
  const hasOriginLocationMetadata = [lane.origin_state, lane.origin_country, lane.origin_market, lane.origin_region].some(cleanText);
  const hasDestinationLocationMetadata = [lane.destination_state, lane.destination_country, lane.destination_market, lane.destination_region].some(cleanText);
  const rowLabel = [
    cleanText(event.rfx_id) || "RFx",
    cleanText(lane.lane_number) || String(index + 1),
    vendorDomain || vendorReference || cleanText(invitation.vendor_id) || "carrier"
  ].filter(Boolean).join("-");

  return {
    vendor_domain: vendorDomain,
    vendor_reference: vendorReference,
    rfx_id: event.rfx_id,
    row_id: rowLabel,
    quote_date: cleanDate(invitation.responded_at || invitation.awarded_at || new Date().toISOString()),
    origin: lane.origin,
    origin_state: lane.origin_state,
    origin_country: lane.origin_country,
    origin_market: lane.origin_market,
    origin_region: lane.origin_region,
    origin_match_manual: hasOriginLocationMetadata,
    origin_match_source: hasOriginLocationMetadata ? "rfx_lane" : null,
    origin_match_reason: hasOriginLocationMetadata ? "RFx lane supplied location metadata" : null,
    destination: lane.destination,
    destination_state: lane.destination_state,
    destination_country: lane.destination_country,
    destination_market: lane.destination_market,
    destination_region: lane.destination_region,
    destination_match_manual: hasDestinationLocationMetadata,
    destination_match_source: hasDestinationLocationMetadata ? "rfx_lane" : null,
    destination_match_reason: hasDestinationLocationMetadata ? "RFx lane supplied location metadata" : null,
    equipment: lane.equipment,
    trailer: lane.trailer,
    config: lane.config,
    operation: lane.operation,
    service: lane.service,
    all_in_rate: invitation.bid_rate,
    currency: invitation.currency || lane.currency || "USD",
    weekly_capacity: invitation.weekly_capacity,
    notes: [
      cleanText(invitation.notes),
      normalizeCommercialModel(invitation.commercial_model) ? `Commercial model: ${normalizeCommercialModel(invitation.commercial_model)}` : null,
      cleanNumber(invitation.marksman_margin_pct) !== null ? `MARKSMAN margin: ${cleanNumber(invitation.marksman_margin_pct)}%` : null,
      cleanNumber(invitation.carrier_share_pct) !== null ? `Carrier share: ${cleanNumber(invitation.carrier_share_pct)}%` : null,
      cleanOptionalBoolean(invitation.best_alternative_offered) ? `Best alternative: ${[cleanText(invitation.alternative_equipment), cleanNumber(invitation.alternative_units) !== null ? `${cleanNumber(invitation.alternative_units)} unit(s)` : null, cleanText(invitation.alternative_notes)].filter(Boolean).join(" / ")}` : null,
      cleanOptionalBoolean(invitation.equipment_available) !== null ? `Equipment available: ${cleanOptionalBoolean(invitation.equipment_available) ? "yes" : "no"}` : null,
      cleanText(invitation.unit_details) ? `Unit details: ${cleanText(invitation.unit_details)}` : null,
      cleanText(invitation.eta_pickup) ? `ETA pickup: ${cleanText(invitation.eta_pickup)}` : null,
      cleanText(invitation.eta_delivery) ? `ETA delivery: ${cleanText(invitation.eta_delivery)}` : null,
      cleanText(invitation.award_reason),
      cleanText(invitation.award_notes),
      "Source: RFx award closeout"
    ].filter(Boolean).join(" | "),
    status: targetStatus,
    confidence: 1
  };
}

async function closeoutAwardedRfxToRateware(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  input: Record<string, unknown>
) {
  const event = await requireOwnedRfxEvent(supabase, user, input.event_id || input.rfx_event_id || input.id);
  const targetStatus = cleanText(input.target_status) === "pending_review" ? "pending_review" : "approved";
  const now = new Date().toISOString();
  const awardsResult = await supabase
    .from("rfx_lane_vendors")
    .select("*, rfx_lanes(*), vendors(id,vendor_name,legal_name,domain,primary_email,base_stage,status)")
    .eq("rfx_event_id", event.id)
    .eq("award_role", "primary")
    .neq("invitation_status", "archived")
    .order("awarded_at", { ascending: true });
  if (awardsResult.error) throw awardsResult.error;

  const awards = awardsResult.data || [];
  const pendingAwards = awards.filter((row) => cleanNumber(row.bid_rate) !== null && !row.rate_staging_id);
  const skipped = awards.length - pendingAwards.length;
  if (!pendingAwards.length) {
    return { inserted: 0, skipped, rows: [], raw_upload_id: null, job_id: null };
  }

  const storageStamp = now.replace(/[^0-9T]/g, "").slice(0, 15);
  const rawUpload = await supabase
    .from("raw_uploads")
    .insert({
      original_filename: `${cleanText(event.rfx_id) || "rfx"}-award-closeout.json`,
      storage_bucket: "rfx-awards",
      storage_path: `rfx-awards/${event.id}/${storageStamp}-${safeStorageSegment(event.rfx_id || event.id)}.json`,
      mime_type: "application/json",
      file_size_bytes: 0,
      document_type: "xlsx",
      vendor_hint: null,
      rfx_hint: event.rfx_id,
      status: "staged",
      staging_target: "rate_staging",
      interpreted_at: now,
      interpreted_rate_rows: pendingAwards.length,
      expected_rate_rows: pendingAwards.length,
      audit_status: "ok",
      audit_warnings: [],
      interpretation_audit: {
        status: "ok",
        import_method: "rfx_award_closeout",
        rfx_event_id: event.id,
        rfx_id: event.rfx_id,
        target_status: targetStatus,
        awarded_rows: pendingAwards.length,
        skipped_rows: skipped
      }
    })
    .select("id")
    .single();
  if (rawUpload.error) throw rawUpload.error;

  const job = await supabase
    .from("interpretation_jobs")
    .insert({
      raw_upload_id: rawUpload.data.id,
      status: "completed",
      completed_at: now,
      model: "rfx-award-closeout",
      extracted_rows: pendingAwards.length,
      error_message: null
    })
    .select("id")
    .single();
  if (job.error) throw job.error;

  const mappedRows = pendingAwards.map((award, index) => ({ mapped: rfxAwardRateInput(award, event, index, targetStatus) }));
  const [catalogResult, scopedLocations, scopedMileage] = await Promise.all([
    supabase
      .from("rateware_catalog_items")
      .select("source,category,raw_value,normalized_value,code")
      .eq("active", true)
      .limit(10000),
    fetchScopedTemplateLocations(supabase, mappedRows),
    fetchScopedTemplateMileage(supabase, mappedRows)
  ]);
  if (catalogResult.error) throw catalogResult.error;

  const catalog = buildCatalogIndex(catalogResult.data || []);
  const locationIndex = buildLocationIndex(scopedLocations || []);
  const mileage = new Map((scopedMileage || []).map((lane) => [catalogKey(lane.route_key), lane]));
  const insertedRows: Record<string, unknown>[] = [];

  for (const [index, award] of pendingAwards.entries()) {
    const mapped = mappedRows[index].mapped as Record<string, unknown>;
    const patch = normalizeStagingPatch(mapped, {});
    patch.vendor_id = award.vendor_id;
    Object.assign(patch, normalizeRowWithCurrentCatalog(patch, catalog, locationIndex, mileage));
    const insert = await supabase
      .from("rate_staging")
      .insert({
        ...patch,
        raw_upload_id: rawUpload.data.id,
        interpretation_job_id: job.data.id,
        status: targetStatus,
        confidence: 1,
        extraction_warnings: [],
        audit_flags: [],
        field_confidence: {
          import_method: "rfx_award_closeout",
          all_fields: 1,
          award_decision: 1
        },
        source_evidence: {
          import_method: "rfx_award_closeout",
          rfx_event_id: event.id,
          rfx_lane_id: award.rfx_lane_id,
          rfx_lane_vendor_id: award.id,
          award_role: award.award_role,
          award_reason: award.award_reason,
          awarded_at: award.awarded_at
        },
        extracted_payload: {
          import_method: "rfx_award_closeout",
          rfx_event: { id: event.id, rfx_id: event.rfx_id, name: event.name },
          lane: award.rfx_lanes,
          bid: {
            id: award.id,
            vendor_id: award.vendor_id,
            bid_rate: award.bid_rate,
            currency: award.currency,
            weekly_capacity: award.weekly_capacity,
            transit_days: award.transit_days,
            notes: award.notes,
            award_reason: award.award_reason,
            award_notes: award.award_notes
          }
        }
      })
      .select("id,row_id,status")
      .single();
    if (insert.error) throw insert.error;
    insertedRows.push(insert.data);

    const link = await supabase
      .from("rfx_lane_vendors")
      .update({ rate_staging_id: insert.data.id, rateware_closeout_at: now, updated_at: now })
      .eq("id", award.id);
    if (link.error) throw link.error;
  }

  const eventUpdate = await supabase
    .from("rfx_events")
    .update({ status: "awarded", updated_at: now })
    .eq("id", event.id)
    .eq("owner_email", user.owner_email);
  if (eventUpdate.error) throw eventUpdate.error;

  const uploadUpdate = await supabase
    .from("raw_uploads")
    .update({ interpreted_rate_rows: insertedRows.length })
    .eq("id", rawUpload.data.id);
  if (uploadUpdate.error) throw uploadUpdate.error;

  return {
    inserted: insertedRows.length,
    skipped,
    rows: insertedRows,
    raw_upload_id: rawUpload.data.id,
    job_id: job.data.id,
    target_status: targetStatus
  };
}

function awardNoticeOutcome(invitation: Record<string, unknown>) {
  const role = cleanText(invitation.award_role)?.toLowerCase();
  if (role === "primary") return { key: "awarded", label: "Awarded" };
  if (role === "backup") return { key: "backup", label: "Backup" };
  return { key: "not_awarded", label: "Not awarded" };
}

function awardNoticeLaneSummary(invitation: Record<string, unknown>) {
  const lane = objectRecord(invitation.rfx_lanes);
  const outcome = awardNoticeOutcome(invitation);
  return {
    outcome,
    lane_number: cleanText(lane.lane_number),
    origin: cleanText(lane.origin || lane.origin_city),
    destination: cleanText(lane.destination || lane.destination_city),
    equipment: [lane.equipment, lane.trailer, lane.config].map(cleanText).filter(Boolean).join(" / "),
    service: [lane.operation, lane.service].map(cleanText).filter(Boolean).join(" / "),
    bid_rate: cleanNumber(invitation.bid_rate),
    currency: cleanText(invitation.currency || lane.currency) || "USD",
    capacity: cleanNumber(invitation.weekly_capacity),
    transit_days: cleanNumber(invitation.transit_days),
    reason: cleanText(invitation.award_reason || invitation.award_notes)
  };
}

function awardNoticeTableHtml(rows: Record<string, unknown>[]) {
  if (!rows.length) return "";
  return `
    <table style="border-collapse:collapse;width:100%;font-family:Arial,sans-serif;font-size:13px">
      <thead>
        <tr>
          <th style="border:1px solid #cbd7df;padding:7px;text-align:left;background:#f1f5f8">Result</th>
          <th style="border:1px solid #cbd7df;padding:7px;text-align:left;background:#f1f5f8">Lane</th>
          <th style="border:1px solid #cbd7df;padding:7px;text-align:left;background:#f1f5f8">Equipment</th>
          <th style="border:1px solid #cbd7df;padding:7px;text-align:left;background:#f1f5f8">Service</th>
          <th style="border:1px solid #cbd7df;padding:7px;text-align:right;background:#f1f5f8">Your bid</th>
          <th style="border:1px solid #cbd7df;padding:7px;text-align:left;background:#f1f5f8">Notes</th>
        </tr>
      </thead>
      <tbody>
        ${rows.map((row) => {
          const outcome = objectRecord(row.outcome);
          const rate = cleanNumber(row.bid_rate);
          const amount = rate === null ? "-" : `${rate.toLocaleString("en-US", { maximumFractionDigits: 2 })} ${cleanText(row.currency) || "USD"}`;
          return `
            <tr>
              <td style="border:1px solid #d9e2e8;padding:7px">${escapeHtmlText(outcome.label)}</td>
              <td style="border:1px solid #d9e2e8;padding:7px">${escapeHtmlText([row.lane_number ? `#${row.lane_number}` : null, `${row.origin || "-"} -> ${row.destination || "-"}`].filter(Boolean).join(" "))}</td>
              <td style="border:1px solid #d9e2e8;padding:7px">${escapeHtmlText(row.equipment || "-")}</td>
              <td style="border:1px solid #d9e2e8;padding:7px">${escapeHtmlText(row.service || "-")}</td>
              <td style="border:1px solid #d9e2e8;padding:7px;text-align:right">${escapeHtmlText(amount)}</td>
              <td style="border:1px solid #d9e2e8;padding:7px">${escapeHtmlText(row.reason || "")}</td>
            </tr>
          `;
        }).join("")}
      </tbody>
    </table>
  `;
}

function awardNoticeRowsText(rows: Record<string, unknown>[]) {
  return rows.map((row) => {
    const outcome = objectRecord(row.outcome);
    const rate = cleanNumber(row.bid_rate);
    const amount = rate === null ? "-" : `${rate.toLocaleString("en-US", { maximumFractionDigits: 2 })} ${cleanText(row.currency) || "USD"}`;
    return [
      cleanText(outcome.label),
      [row.lane_number ? `#${row.lane_number}` : null, `${row.origin || "-"} -> ${row.destination || "-"}`].filter(Boolean).join(" "),
      cleanText(row.equipment),
      cleanText(row.service),
      amount,
      cleanText(row.reason)
    ].filter(Boolean).join(" | ");
  }).join("\n");
}

function awardNoticeHtml(event: Record<string, unknown>, vendor: Record<string, unknown>, rows: Record<string, unknown>[], portalLink: string | null) {
  const counts = rows.reduce((acc, row) => {
    const key = cleanText(objectRecord(row.outcome).key) || "not_awarded";
    acc[key] = (acc[key] || 0) + 1;
    return acc;
  }, {} as Record<string, number>);
  const headline = counts.awarded
    ? "Your award decision is ready."
    : counts.backup
      ? "You have been selected as backup capacity."
      : "This RFx has been awarded to another carrier.";
  return `
    <div style="font-family:Arial,sans-serif;color:#1f2d36;line-height:1.45">
      <p>Estimados ${escapeHtmlText(vendor.vendor_name || vendor.domain || "team")},</p>
      <p>${escapeHtmlText(headline)}</p>
      <p>RFx: <strong>${escapeHtmlText(event.rfx_id || event.name || "RFx")}</strong>${event.name ? ` | ${escapeHtmlText(event.name)}` : ""}</p>
      ${awardNoticeTableHtml(rows)}
      ${portalLink ? `<p>Bid Room: <a href="${escapeHtmlText(portalLink)}">${escapeHtmlText(portalLink)}</a></p>` : ""}
      <p>Gracias por participar. Mantendremos su capacidad y comentarios visibles para siguientes asignaciones.</p>
      <p>MARKSMAN Procurement</p>
    </div>
  `;
}

async function ensureAwardNoticeCampaign(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  event: Record<string, unknown>,
  senderEmail: string,
  senderLabel: string
) {
  const name = `${cleanText(event.rfx_id || event.name) || "RFx"} award closeout`;
  const existing = await supabase
    .from("outreach_campaigns")
    .select("*")
    .eq("owner_email", user.owner_email)
    .eq("rfx_event_id", event.id)
    .eq("name", name)
    .neq("status", "archived")
    .order("created_at", { ascending: false })
    .limit(1);
  if (existing.error) throw existing.error;
  if (existing.data?.[0]) return existing.data[0];

  const result = await supabase
    .from("outreach_campaigns")
    .insert(withOwner({
      rfx_event_id: event.id,
      name,
      channel: "email",
      status: "draft",
      sender_email: senderEmail,
      sender_label: senderLabel,
      sender_connection_status: "draft_only",
      notes: "rfx_award_notice"
    }, user))
    .select()
    .single();
  if (result.error) throw result.error;
  return result.data;
}

async function generateRfxAwardNotices(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  input: Record<string, unknown>
) {
  const event = await requireOwnedRfxEvent(supabase, user, input.event_id || input.rfx_event_id || input.id);
  const appOrigin = cleanText(input.app_origin) || Deno.env.get("RATEWARE_APP_URL") || "https://rateware.vercel.app";
  const senderEmail = (cleanText(input.sender_email) || GMAIL_ALLOWED_SENDER).toLowerCase();
  const senderLabel = cleanText(input.sender_label) || senderEmail;
  const campaign = await ensureAwardNoticeCampaign(supabase, user, event, senderEmail, senderLabel);
  const invitationsResult = await supabase
    .from("rfx_lane_vendors")
    .select("*, vendors(id,vendor_name,domain,primary_email,whatsapp_phone,preferred_channel,contact_name), rfx_lanes(*)")
    .eq("rfx_event_id", event.id)
    .neq("invitation_status", "archived")
    .order("updated_at", { ascending: false });
  if (invitationsResult.error) throw invitationsResult.error;

  const rows = new Map<string, Record<string, unknown>[]>();
  const skipped: Record<string, unknown>[] = [];
  for (const invitation of invitationsResult.data || []) {
    const status = cleanText(invitation.invitation_status)?.toLowerCase() || "";
    const hasDecision = Boolean(cleanText(invitation.award_role));
    const hasParticipation = cleanNumber(invitation.bid_rate) !== null || ["invited", "viewed", "responded", "quoted", "bid_submitted", "awarded"].includes(status);
    if (!hasDecision && !hasParticipation) continue;
    const vendor = objectRecord(invitation.vendors);
    const recipient = cleanText(vendor.primary_email);
    if (!recipient) {
      skipped.push({ invitation_id: invitation.id, vendor_id: invitation.vendor_id, reason: "Missing vendor email" });
      continue;
    }
    const key = cleanText(invitation.vendor_id) || recipient || cleanText(invitation.id) || crypto.randomUUID();
    const bucket = rows.get(key) || [];
    bucket.push(invitation);
    rows.set(key, bucket);
  }

  const messageRows: Record<string, unknown>[] = [];
  const now = new Date().toISOString();
  for (const invitationGroup of rows.values()) {
    const sortedGroup = [...invitationGroup].sort((a, b) => {
      const aLane = objectRecord(a.rfx_lanes);
      const bLane = objectRecord(b.rfx_lanes);
      return String(aLane.lane_number || a.rfx_lane_id || a.id || "").localeCompare(String(bLane.lane_number || b.rfx_lane_id || b.id || ""));
    });
    const first = sortedGroup[0];
    const vendor = objectRecord(first.vendors);
    const recipientEmail = cleanText(vendor.primary_email);
    const laneSummaries = sortedGroup.map(awardNoticeLaneSummary);
    const counts = laneSummaries.reduce((acc, row) => {
      const key = cleanText(objectRecord(row.outcome).key) || "not_awarded";
      acc[key] = (acc[key] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);
    const subjectPrefix = counts.awarded ? "Award" : counts.backup ? "Backup status" : "RFx closeout";
    const subject = `${subjectPrefix}: ${cleanText(event.rfx_id || event.name) || "Bid Room"}`;
    const token = cleanText(first.invitation_token);
    const portalLink = token ? `${appOrigin.replace(/\/$/, "")}/rfx-bid.html?token=${encodeURIComponent(token)}` : null;
    const htmlBody = awardNoticeHtml(event, vendor, laneSummaries, portalLink);
    const textBody = [
      `Estimados ${cleanText(vendor.vendor_name || vendor.domain || "team")},`,
      `RFx: ${cleanText(event.rfx_id || event.name) || "RFx"}`,
      "",
      awardNoticeRowsText(laneSummaries),
      "",
      portalLink ? `Bid Room: ${portalLink}` : null,
      "Gracias por participar.",
      "MARKSMAN Procurement"
    ].filter(Boolean).join("\n");
    const invitationIds = sortedGroup.map((item) => item.id).filter(Boolean);
    const laneIds = sortedGroup.map((item) => item.rfx_lane_id).filter(Boolean);
    messageRows.push(withOwner({
      campaign_id: campaign.id,
      template_id: null,
      rfx_event_id: event.id,
      rfx_lane_id: first.rfx_lane_id,
      rfx_lane_vendor_id: first.id,
      vendor_id: first.vendor_id,
      channel: "email",
      recipient_email: recipientEmail,
      subject,
      html_body: htmlBody,
      text_body: textBody,
      gmail_compose_url: gmailComposeUrl(recipientEmail, subject, textBody),
      sender_email: senderEmail,
      sender_label: senderLabel,
      sender_connection_status: "draft_only",
      status: "drafted",
      metadata: {
        notice_type: "rfx_award_closeout",
        generated_at: now,
        award_summary: counts,
        rfx_lane_vendor_ids: invitationIds,
        rfx_lane_ids: laneIds,
        bid_link: portalLink,
        sender_email: senderEmail,
        sender_label: senderLabel
      }
    }, user));
  }

  if (!messageRows.length) return { generated: 0, rows: [], skipped, campaign_id: campaign.id };

  const result = await supabase
    .from("outreach_messages")
    .upsert(messageRows, { onConflict: "campaign_id,rfx_lane_vendor_id,channel" })
    .select("*, vendors(vendor_name,domain,primary_email,whatsapp_phone), outreach_campaigns(name), rfx_events(rfx_id,name), rfx_lanes(origin,destination,equipment,trailer,operation,service), rfx_lane_vendors(id,invitation_status,award_role,bid_rate,currency,responded_at)");
  if (result.error) throw result.error;

  const historyRows = (result.data || []).map((message) => withOwner({
    outreach_message_id: message.id,
    campaign_id: campaign.id,
    vendor_id: message.vendor_id,
    rfx_event_id: message.rfx_event_id,
    channel: "email",
    direction: "outbound",
    status: "drafted",
    subject: message.subject,
    body_preview: contactPreview(message.text_body || message.html_body),
    metadata: {
      generated_from: "rfx_award_closeout",
      notice_type: "rfx_award_closeout",
      award_summary: objectRecord(message.metadata).award_summary || null
    }
  }, user));
  if (historyRows.length) {
    const history = await supabase.from("contact_history").insert(historyRows);
    if (history.error) throw history.error;
  }

  const campaignUpdate = await supabase
    .from("outreach_campaigns")
    .update({
      status: "generated",
      sender_email: senderEmail,
      sender_label: senderLabel,
      sender_connection_status: "draft_only",
      updated_at: now
    })
    .eq("id", campaign.id)
    .eq("owner_email", user.owner_email);
  if (campaignUpdate.error) throw campaignUpdate.error;

  return { generated: result.data?.length || 0, rows: result.data || [], skipped, campaign_id: campaign.id };
}

const BID_ROOM_CHAT_THREAD_TYPES = new Set(["event_group", "lane_group", "carrier_private"]);

function normalizeBidRoomThreadType(value: unknown) {
  const threadType = cleanText(value)?.toLowerCase() || "event_group";
  return BID_ROOM_CHAT_THREAD_TYPES.has(threadType) ? threadType : "event_group";
}

function bidRoomGoogleThreadKey(eventId: unknown, threadType: string, laneId: unknown, vendorId: unknown) {
  return [
    "rateware",
    "bid-room",
    cleanText(eventId) || "event",
    threadType,
    cleanText(laneId) || "event",
    cleanText(vendorId) || "group"
  ].join("-").replace(/[^a-zA-Z0-9_-]+/g, "-").slice(0, 190);
}

function bidRoomThreadTitle(threadType: string, event: Record<string, unknown>, lane?: Record<string, unknown> | null, vendor?: Record<string, unknown> | null) {
  const eventRef = [cleanText(event.rfx_id), cleanText(event.name)].filter(Boolean).join(" | ") || "Bid Room";
  if (threadType === "carrier_private") return `${eventRef} | Private: ${cleanText(vendor?.vendor_name || vendor?.domain) || "Carrier"}`;
  if (threadType === "lane_group") return `${eventRef} | Lane: ${[lane?.origin, lane?.destination].filter(Boolean).join(" -> ") || lane?.lane_number || "Selected lane"}`;
  return `${eventRef} | Event group`;
}

function googleChatThreadTarget(thread: Record<string, unknown>, threadKey: string) {
  const threadName = cleanText(thread.google_chat_thread_name);
  return {
    replyOption: threadName ? "REPLY_MESSAGE_OR_FAIL" : "REPLY_MESSAGE_FALLBACK_TO_NEW_THREAD",
    thread: threadName ? { name: threadName } : { threadKey }
  };
}

async function syncBidRoomMessageToGoogleChatApi(
  supabase: ReturnType<typeof createClient>,
  thread: Record<string, unknown>,
  message: Record<string, unknown>,
  event: Record<string, unknown>
) {
  const ownerEmail = cleanText(message.owner_email || thread.owner_email || event.owner_email);
  if (!ownerEmail) return { status: "not_configured", name: null };
  const connectionResult = await supabase
    .from("google_chat_connections")
    .select("default_space_name,default_space_display_name,status")
    .eq("owner_email", ownerEmail)
    .eq("account_email", GOOGLE_CHAT_ALLOWED_ACCOUNT)
    .eq("status", "connected")
    .maybeSingle();
  if (connectionResult.error) throw connectionResult.error;
  const connection = connectionResult.data;
  const spaceName = cleanText(connection?.default_space_name);
  if (!connection || !spaceName) return { status: "not_configured", name: null };

  const threadKey = cleanText(thread.google_chat_thread_key) || bidRoomGoogleThreadKey(thread.rfx_event_id, String(thread.thread_type || "event_group"), thread.rfx_lane_id, thread.vendor_id);
  const sender = cleanText(message.sender_name || message.sender_email) || "Rateware";
  const title = cleanText(thread.title) || cleanText(event.rfx_id || event.name) || "Bid Room";
  const text = `*${title}*\n${sender}: ${cleanText(message.body) || ""}`;
  try {
    const accessToken = await googleChatAccessToken(supabase, { owner_email: ownerEmail });
    const target = googleChatThreadTarget(thread, threadKey);
    const params = new URLSearchParams({ messageReplyOption: target.replyOption });
    const response = await fetch(`https://chat.googleapis.com/v1/${spaceName}/messages?${params.toString()}`, {
      method: "POST",
      headers: {
        Authorization: `Bearer ${accessToken}`,
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        text,
        thread: target.thread
      })
    });
    const payload = await response.json().catch(() => ({}));
    const status = response.ok ? "synced" : "error";
    await supabase.from("bid_room_chat_messages").update({
      google_chat_message_name: cleanText(payload.name),
      google_chat_sync_status: status
    }).eq("id", message.id);
    await supabase.from("bid_room_chat_threads").update({
      google_chat_space: spaceName,
      google_chat_thread_key: threadKey,
      google_chat_thread_name: cleanText(payload?.thread?.name) || cleanText(thread.google_chat_thread_name),
      google_chat_sync_status: status,
      updated_at: new Date().toISOString()
    }).eq("id", thread.id);
    if (!response.ok) {
      await supabase.from("google_chat_connections").update({
        last_error: cleanText(payload?.error?.message) || `Google Chat send failed (${response.status}).`,
        updated_at: new Date().toISOString()
      }).eq("owner_email", ownerEmail).eq("account_email", GOOGLE_CHAT_ALLOWED_ACCOUNT);
    }
    return { status, name: cleanText(payload.name), space_name: spaceName };
  } catch (error) {
    await supabase.from("bid_room_chat_messages").update({ google_chat_sync_status: "error" }).eq("id", message.id);
    await supabase.from("bid_room_chat_threads").update({ google_chat_sync_status: "error" }).eq("id", thread.id);
    return { status: "error", name: null, error: String(error?.message || error) };
  }
}

async function syncBidRoomMessageToGoogleChat(
  supabase: ReturnType<typeof createClient>,
  thread: Record<string, unknown>,
  message: Record<string, unknown>,
  event: Record<string, unknown>
) {
  const apiSync = await syncBidRoomMessageToGoogleChatApi(supabase, thread, message, event);
  if (apiSync.status !== "not_configured") return apiSync;
  if (!GOOGLE_CHAT_WEBHOOK_URL) return { status: "not_configured", name: null };
  const threadKey = cleanText(thread.google_chat_thread_key) || bidRoomGoogleThreadKey(thread.rfx_event_id, String(thread.thread_type || "event_group"), thread.rfx_lane_id, thread.vendor_id);
  const url = new URL(GOOGLE_CHAT_WEBHOOK_URL);
  url.searchParams.set("threadKey", threadKey);
  url.searchParams.set("messageReplyOption", "REPLY_MESSAGE_FALLBACK_TO_NEW_THREAD");
  const sender = cleanText(message.sender_name || message.sender_email) || "Rateware";
  const title = cleanText(thread.title) || cleanText(event.rfx_id || event.name) || "Bid Room";
  const text = `*${title}*\n${sender}: ${cleanText(message.body) || ""}`;
  try {
    const response = await fetch(url.toString(), {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ text })
    });
    const payload = await response.json().catch(() => ({}));
    const status = response.ok ? "synced" : "error";
    await supabase.from("bid_room_chat_messages").update({
      google_chat_message_name: cleanText(payload.name),
      google_chat_sync_status: status
    }).eq("id", message.id);
    await supabase.from("bid_room_chat_threads").update({
      google_chat_thread_key: threadKey,
      google_chat_thread_name: cleanText(payload?.thread?.name),
      google_chat_sync_status: status,
      updated_at: new Date().toISOString()
    }).eq("id", thread.id);
    return { status, name: cleanText(payload.name) };
  } catch (error) {
    await supabase.from("bid_room_chat_messages").update({ google_chat_sync_status: "error" }).eq("id", message.id);
    await supabase.from("bid_room_chat_threads").update({ google_chat_sync_status: "error" }).eq("id", thread.id);
    return { status: "error", name: null, error: String(error?.message || error) };
  }
}

function googleChatConnectionCanReadMessages(connection: Record<string, unknown> | null | undefined) {
  const scopes = Array.isArray(connection?.scopes) ? connection?.scopes.map(String) : [];
  return scopes.includes("https://www.googleapis.com/auth/chat.messages.readonly")
    || scopes.includes("https://www.googleapis.com/auth/chat.messages");
}

function googleChatMessageThreadName(message: Record<string, unknown>) {
  return cleanText(objectRecord(message.thread).name);
}

function googleChatMessageBody(message: Record<string, unknown>) {
  return cleanText(message.text || message.argumentText || message.formattedText);
}

async function syncGoogleChatInboundMessagesForThreads(
  supabase: ReturnType<typeof createClient>,
  ownerEmail: string | null,
  threads: Record<string, unknown>[],
  input: Record<string, unknown> = {}
) {
  const owner = cleanText(ownerEmail);
  const candidateThreads = (threads || []).filter((thread) => cleanText(thread.id) && cleanText(thread.rfx_event_id));
  if (!owner || !candidateThreads.length) return { status: "skipped", imported: 0, skipped: 0, reason: "No Bid Room threads to sync." };

  const connectionResult = await supabase
    .from("google_chat_connections")
    .select("*")
    .eq("owner_email", owner)
    .eq("account_email", GOOGLE_CHAT_ALLOWED_ACCOUNT)
    .eq("status", "connected")
    .maybeSingle();
  if (connectionResult.error) throw connectionResult.error;
  const connection = connectionResult.data;
  const spaceName = cleanText(connection?.default_space_name);
  if (!connection || !spaceName) return { status: "not_configured", imported: 0, skipped: 0 };
  if (!googleChatConnectionCanReadMessages(connection)) {
    return {
      status: "needs_reconnect",
      imported: 0,
      skipped: 0,
      reason: `Reconnect Google Chat in Settings to allow Rateware to read messages from ${spaceName}.`
    };
  }

  const accessToken = await googleChatAccessToken(supabase, { owner_email: owner });
  const url = new URL(`https://chat.googleapis.com/v1/${spaceName}/messages`);
  url.searchParams.set("pageSize", String(Math.min(Math.max(Number(input.limit) || 100, 10), 100)));
  const response = await fetch(url.toString(), {
    headers: { Authorization: `Bearer ${accessToken}` }
  });
  const payload = await response.json().catch(() => ({}));
  if (!response.ok) {
    const message = cleanText(payload?.error?.message) || `Google Chat message sync failed (${response.status}).`;
    await supabase.from("google_chat_connections").update({
      last_error: message,
      updated_at: new Date().toISOString()
    }).eq("owner_email", owner).eq("account_email", GOOGLE_CHAT_ALLOWED_ACCOUNT);
    return { status: "error", imported: 0, skipped: 0, error: message };
  }

  const googleMessages = Array.isArray(payload.messages)
    ? payload.messages
        .filter((message: Record<string, unknown>) => cleanText(message.name))
        .sort((a: Record<string, unknown>, b: Record<string, unknown>) => {
          const aTime = new Date(String(a.createTime || 0)).getTime();
          const bTime = new Date(String(b.createTime || 0)).getTime();
          return aTime - bTime;
        })
    : [];
  if (!googleMessages.length) return { status: "synced", imported: 0, skipped: 0 };

  const googleNames = googleMessages.map((message: Record<string, unknown>) => cleanText(message.name)).filter(Boolean) as string[];
  const existingResult = googleNames.length
    ? await supabase
        .from("bid_room_chat_messages")
        .select("id,thread_id,google_chat_message_name")
        .eq("owner_email", owner)
        .in("google_chat_message_name", googleNames)
    : { data: [], error: null };
  if (existingResult.error) throw existingResult.error;

  const existingByGoogleName = new Map((existingResult.data || []).map((message) => [String(message.google_chat_message_name), message]));
  const threadsById = new Map(candidateThreads.map((thread) => [String(thread.id), thread]));
  const threadsByGoogleThreadName = new Map(
    candidateThreads
      .map((thread) => [cleanText(thread.google_chat_thread_name), thread] as [string | null, Record<string, unknown>])
      .filter(([name]) => Boolean(name)) as [string, Record<string, unknown>][]
  );
  const eventGroupThread = candidateThreads.find((thread) => cleanText(thread.thread_type) === "event_group") || candidateThreads[0];

  let imported = 0;
  let skipped = 0;
  let updatedThreads = 0;

  for (const googleMessage of googleMessages) {
    const googleMessageName = cleanText(googleMessage.name);
    const googleThreadName = googleChatMessageThreadName(googleMessage);
    const existingMessage = googleMessageName ? existingByGoogleName.get(googleMessageName) : null;
    if (existingMessage) {
      const existingThread = threadsById.get(String(existingMessage.thread_id));
      if (existingThread && googleThreadName && cleanText(existingThread.google_chat_thread_name) !== googleThreadName) {
        await supabase.from("bid_room_chat_threads").update({
          google_chat_space: spaceName,
          google_chat_thread_name: googleThreadName,
          google_chat_sync_status: "synced",
          updated_at: new Date().toISOString()
        }).eq("id", existingThread.id);
        existingThread.google_chat_thread_name = googleThreadName;
        threadsByGoogleThreadName.set(googleThreadName, existingThread);
        updatedThreads += 1;
      }
      skipped += 1;
      continue;
    }

    const body = googleChatMessageBody(googleMessage);
    if (!body) {
      skipped += 1;
      continue;
    }
    const targetThread = (googleThreadName && threadsByGoogleThreadName.get(googleThreadName)) || eventGroupThread;
    if (!targetThread) {
      skipped += 1;
      continue;
    }
    if (googleThreadName && cleanText(targetThread.google_chat_thread_name) !== googleThreadName) {
      await supabase.from("bid_room_chat_threads").update({
        google_chat_space: spaceName,
        google_chat_thread_name: googleThreadName,
        google_chat_sync_status: "synced",
        updated_at: new Date().toISOString()
      }).eq("id", targetThread.id);
      targetThread.google_chat_thread_name = googleThreadName;
      threadsByGoogleThreadName.set(googleThreadName, targetThread);
      updatedThreads += 1;
    }

    const sender = objectRecord(googleMessage.sender);
    const senderType = cleanText(sender.type)?.toUpperCase();
    const createdAt = new Date(String(googleMessage.createTime || ""));
    const insertResult = await supabase.from("bid_room_chat_messages").insert({
      owner_user_id: cleanText(targetThread.owner_user_id),
      owner_email: owner,
      thread_id: targetThread.id,
      rfx_event_id: targetThread.rfx_event_id,
      rfx_lane_id: targetThread.rfx_lane_id || null,
      vendor_id: targetThread.vendor_id || null,
      sender_role: senderType === "BOT" ? "system" : "procurement",
      sender_name: cleanText(sender.displayName || sender.name) || "Google Chat",
      sender_email: null,
      body,
      google_chat_message_name: googleMessageName,
      google_chat_sender_name: cleanText(sender.name),
      google_chat_sync_status: "synced",
      created_at: Number.isNaN(createdAt.getTime()) ? new Date().toISOString() : createdAt.toISOString(),
      metadata: {
        source: "google_chat_inbound",
        google_chat_space: spaceName,
        google_chat_thread_name: googleThreadName,
        sender
      }
    });
    if (insertResult.error) {
      if (String(insertResult.error.code || "") === "23505") skipped += 1;
      else throw insertResult.error;
    } else {
      await supabase.from("bid_room_chat_threads").update({
        updated_at: Number.isNaN(createdAt.getTime()) ? new Date().toISOString() : createdAt.toISOString(),
        read_status: "unread",
        last_action_at: new Date().toISOString()
      }).eq("id", targetThread.id);
      imported += 1;
    }
  }

  return { status: "synced", imported, skipped, updated_threads: updatedThreads };
}

async function retryGoogleChatSync(
  supabase: ReturnType<typeof createClient>,
  user: { owner_email: string | null },
  input: Record<string, unknown> = {}
) {
  const limit = Math.min(Math.max(Number(input.limit) || 50, 1), 100);
  const messagesResult = await supabase
    .from("bid_room_chat_messages")
    .select("*")
    .eq("owner_email", user.owner_email)
    .in("google_chat_sync_status", ["error", "pending", "not_configured"])
    .order("created_at", { ascending: false })
    .limit(limit);
  if (messagesResult.error) throw messagesResult.error;

  const messages = messagesResult.data || [];
  const threadIds = [...new Set(messages.map((message) => cleanText(message.thread_id)).filter(Boolean))];
  const eventIds = [...new Set(messages.map((message) => cleanText(message.rfx_event_id)).filter(Boolean))];

  const threadsResult = threadIds.length
    ? await supabase.from("bid_room_chat_threads").select("*").in("id", threadIds)
    : { data: [], error: null };
  if (threadsResult.error) throw threadsResult.error;
  const eventsResult = eventIds.length
    ? await supabase.from("rfx_events").select("*").in("id", eventIds)
    : { data: [], error: null };
  if (eventsResult.error) throw eventsResult.error;

  const threadsById = new Map((threadsResult.data || []).map((thread) => [String(thread.id), thread]));
  const eventsById = new Map((eventsResult.data || []).map((event) => [String(event.id), event]));
  let synced = 0;
  let failed = 0;
  let skipped = 0;
  const rows: Record<string, unknown>[] = [];

  for (const message of messages) {
    const thread = threadsById.get(String(message.thread_id));
    const event = eventsById.get(String(message.rfx_event_id));
    if (!thread || !event) {
      skipped += 1;
      rows.push({ id: message.id, status: "skipped", reason: "Missing Bid Room thread or event." });
      continue;
    }
    const result = await syncBidRoomMessageToGoogleChat(supabase, thread, message, event);
    if (result.status === "synced") synced += 1;
    else if (result.status === "not_configured") skipped += 1;
    else failed += 1;
    rows.push({ id: message.id, status: result.status, error: result.error || null });
  }

  return { attempted: messages.length, synced, failed, skipped, rows };
}

async function findOrCreateBidRoomChatThread(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  event: Record<string, unknown>,
  input: Record<string, unknown>
) {
  const threadType = normalizeBidRoomThreadType(input.thread_type || input.scope);
  let lane: Record<string, unknown> | null = null;
  let vendor: Record<string, unknown> | null = null;
  const laneId = cleanText(input.rfx_lane_id || input.lane_id);
  const vendorId = cleanText(input.vendor_id);

  if (threadType === "lane_group" || laneId) {
    const laneResult = await supabase
      .from("rfx_lanes")
      .select("id,lane_number,origin,destination,rfx_event_id")
      .eq("id", laneId)
      .eq("rfx_event_id", event.id)
      .single();
    if (laneResult.error) throw laneResult.error;
    lane = laneResult.data;
  }

  if (threadType === "carrier_private") {
    if (!vendorId) throw new Error("Private carrier chat requires a vendor.");
    const vendorResult = await supabase
      .from("vendors")
      .select("id,vendor_name,domain,primary_email")
      .eq("id", vendorId)
      .maybeSingle();
    if (vendorResult.error) throw vendorResult.error;
    if (!vendorResult.data) throw new Error("Vendor was not found.");
    vendor = vendorResult.data;
  }

  let query = supabase
    .from("bid_room_chat_threads")
    .select("*, vendors(vendor_name,domain), rfx_lanes(lane_number,origin,destination)")
    .eq("rfx_event_id", event.id)
    .eq("thread_type", threadType)
    .neq("status", "archived");
  query = lane ? query.eq("rfx_lane_id", lane.id) : query.is("rfx_lane_id", null);
  query = vendor ? query.eq("vendor_id", vendor.id) : query.is("vendor_id", null);
  const existing = await query.maybeSingle();
  if (existing.error) throw existing.error;
  if (existing.data) return existing.data;

  const row = withOwner({
    rfx_event_id: event.id,
    rfx_lane_id: lane?.id || null,
    vendor_id: vendor?.id || null,
    thread_type: threadType,
    title: cleanText(input.title) || bidRoomThreadTitle(threadType, event, lane, vendor),
    google_chat_thread_key: bidRoomGoogleThreadKey(event.id, threadType, lane?.id, vendor?.id),
    google_chat_sync_status: "ready",
    metadata: {
      source: "rateware_bid_room",
      rfx_id: event.rfx_id || null
    }
  }, user);
  const created = await supabase
    .from("bid_room_chat_threads")
    .insert(row)
    .select("*, vendors(vendor_name,domain), rfx_lanes(lane_number,origin,destination)")
    .single();
  if (created.error) throw created.error;
  return created.data;
}

async function listBidRoomChat(supabase: ReturnType<typeof createClient>, user: { owner_email: string | null }, input: Record<string, unknown>) {
  const event = await requireOwnedRfxEvent(supabase, user, input.rfx_event_id || input.event_id);
  let query = supabase
    .from("bid_room_chat_threads")
    .select("*, vendors(vendor_name,domain), rfx_lanes(lane_number,origin,destination)")
    .eq("owner_email", user.owner_email)
    .eq("rfx_event_id", event.id)
    .neq("status", "archived")
    .order("updated_at", { ascending: false });
  if (input.thread_type || input.scope) query = query.eq("thread_type", normalizeBidRoomThreadType(input.thread_type || input.scope));
  if (input.rfx_lane_id || input.lane_id) query = query.eq("rfx_lane_id", cleanText(input.rfx_lane_id || input.lane_id));
  if (input.vendor_id) query = query.eq("vendor_id", cleanText(input.vendor_id));
  const threadsResult = await query;
  if (threadsResult.error) throw threadsResult.error;
  const threads = threadsResult.data || [];
  const googleChatInbound = await syncGoogleChatInboundMessagesForThreads(supabase, user.owner_email, threads).catch((error) => ({
    status: "error",
    imported: 0,
    skipped: 0,
    error: String(error?.message || error)
  }));
  const threadIds = threads.map((thread) => thread.id).filter(Boolean);
  const messagesResult = threadIds.length
    ? await supabase
        .from("bid_room_chat_messages")
        .select("*, vendors(vendor_name,domain)")
        .in("thread_id", threadIds)
        .order("created_at", { ascending: true })
    : { data: [], error: null };
  if (messagesResult.error) throw messagesResult.error;
  const messagesByThread = new Map<string, Record<string, unknown>[]>();
  for (const message of messagesResult.data || []) {
    const list = messagesByThread.get(String(message.thread_id)) || [];
    list.push(message);
    messagesByThread.set(String(message.thread_id), list);
  }
  const chatConnection = await supabase
    .from("google_chat_connections")
    .select("default_space_name,status")
    .eq("owner_email", user.owner_email)
    .eq("account_email", GOOGLE_CHAT_ALLOWED_ACCOUNT)
    .eq("status", "connected")
    .maybeSingle();
  if (chatConnection.error) throw chatConnection.error;
  return {
    event,
    google_chat_configured: Boolean(chatConnection.data?.default_space_name || GOOGLE_CHAT_WEBHOOK_URL),
    google_chat_inbound: googleChatInbound,
    rows: threads.map((thread) => ({
      ...thread,
      messages: messagesByThread.get(String(thread.id)) || []
    }))
  };
}

async function updateBidRoomChatThreadAction(
  supabase: ReturnType<typeof createClient>,
  user: { owner_email: string | null },
  input: Record<string, unknown>
) {
  const threadId = cleanText(input.thread_id || input.id);
  if (!threadId) throw new Error("Thread id is required.");
  const action = cleanText(input.thread_action || input.action_type || input.status_action)?.toLowerCase() || "update";
  const now = new Date().toISOString();
  const patch: Record<string, unknown> = {
    last_action_at: now,
    updated_at: now
  };

  if (action === "mark_read") {
    patch.read_status = "read";
    patch.last_read_at = now;
  } else if (action === "mark_unread") {
    patch.read_status = "unread";
  } else if (action === "mark_needs_reply") {
    patch.communication_status = "needs_reply";
    patch.needs_reply = true;
    patch.read_status = "unread";
  } else if (action === "resolve") {
    patch.communication_status = "resolved";
    patch.needs_reply = false;
    patch.read_status = "read";
    patch.last_read_at = now;
    patch.resolved_at = now;
    patch.resolved_by = user.owner_email;
  } else if (action === "reopen") {
    patch.communication_status = "open";
    patch.needs_reply = false;
    patch.resolved_at = null;
    patch.resolved_by = null;
  } else if (action === "assign") {
    patch.assigned_to = cleanText(input.assigned_to) || user.owner_email || null;
  } else if (action === "note") {
    patch.internal_note = cleanText(input.internal_note || input.note) || null;
  } else if (action === "update") {
    const status = cleanText(input.communication_status)?.toLowerCase();
    const readStatus = cleanText(input.read_status)?.toLowerCase();
    if (status && ["open", "needs_reply", "resolved"].includes(status)) {
      patch.communication_status = status;
      patch.needs_reply = status === "needs_reply";
    }
    if (readStatus && ["read", "unread"].includes(readStatus)) patch.read_status = readStatus;
    if ("assigned_to" in input) patch.assigned_to = cleanText(input.assigned_to) || null;
    if ("internal_note" in input || "note" in input) patch.internal_note = cleanText(input.internal_note || input.note) || null;
  } else {
    throw new Error("Unsupported chat thread action.");
  }

  const result = await supabase
    .from("bid_room_chat_threads")
    .update(patch)
    .eq("id", threadId)
    .eq("owner_email", user.owner_email)
    .neq("status", "archived")
    .select("*, vendors(vendor_name,domain), rfx_lanes(lane_number,origin,destination)")
    .single();
  if (result.error) throw result.error;
  return { row: result.data, action };
}

async function applyBidUpdateFromChat(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  input: Record<string, unknown>
) {
  const threadId = cleanText(input.thread_id);
  if (!threadId) throw new Error("Chat thread id is required.");
  const invitationId = cleanText(input.rfx_lane_vendor_id || input.invitation_id);
  const now = new Date().toISOString();
  const threadResult = await supabase
    .from("bid_room_chat_threads")
    .select("*, vendors(vendor_name,domain), rfx_lanes(lane_number,origin,destination)")
    .eq("id", threadId)
    .eq("owner_email", user.owner_email)
    .neq("status", "archived")
    .single();
  if (threadResult.error) throw threadResult.error;
  const thread = threadResult.data;

  let sourceMessage: Record<string, unknown> | null = null;
  const messageId = cleanText(input.message_id || input.source_message_id);
  if (messageId) {
    const messageResult = await supabase
      .from("bid_room_chat_messages")
      .select("*")
      .eq("id", messageId)
      .eq("thread_id", thread.id)
      .eq("owner_email", user.owner_email)
      .maybeSingle();
    if (messageResult.error) throw messageResult.error;
    sourceMessage = messageResult.data || null;
  }
  if (!sourceMessage) {
    const latestMessageResult = await supabase
      .from("bid_room_chat_messages")
      .select("*")
      .eq("thread_id", thread.id)
      .eq("owner_email", user.owner_email)
      .order("created_at", { ascending: false })
      .limit(1)
      .maybeSingle();
    if (latestMessageResult.error) throw latestMessageResult.error;
    sourceMessage = latestMessageResult.data || null;
  }

  let invitationQuery = supabase
    .from("rfx_lane_vendors")
    .select("*, rfx_events!inner(owner_email), vendors(id,vendor_name,domain,primary_email,whatsapp_phone,preferred_channel,base_stage,status), rfx_lanes(id,lane_number,origin,destination,currency)")
    .eq("rfx_events.owner_email", user.owner_email);
  if (invitationId) {
    invitationQuery = invitationQuery.eq("id", invitationId);
  } else {
    const laneId = cleanText(input.rfx_lane_id || thread.rfx_lane_id);
    const vendorId = cleanText(input.vendor_id || thread.vendor_id);
    if (!laneId || !vendorId) {
      throw new Error("Choose a lane-carrier row before applying a chat bid update.");
    }
    invitationQuery = invitationQuery.eq("rfx_lane_id", laneId).eq("vendor_id", vendorId);
  }
  const invitationResult = await invitationQuery.single();
  if (invitationResult.error) throw invitationResult.error;
  const before = invitationResult.data;

  const bidRate = strictBidNumber(input.bid_rate, "All-in rate", { required: true });
  const sourceBody = cleanText(sourceMessage?.body);
  const sourceNote = cleanText(input.source_note) || sourceBody || "Bid update reviewed from Bid Room chat.";
  const laneCurrency = cleanText((before.rfx_lanes as Record<string, unknown> | null)?.currency);
  const patch: Record<string, unknown> = {
    bid_rate: bidRate,
    currency: strictCurrencyCode(input.currency, cleanText(before.currency) || laneCurrency || "USD"),
    weekly_capacity: strictBidNumber(input.weekly_capacity, "Weekly capacity"),
    transit_days: strictBidNumber(input.transit_days, "Transit days"),
    notes: cleanText(input.notes),
    invitation_status: "quoted",
    responded_at: now,
    response_source: "bid_room_chat",
    bid_source_thread_id: thread.id,
    bid_source_message_id: sourceMessage?.id || null,
    bid_source_note: sourceNote.slice(0, 2000),
    bid_updated_from_chat_at: now,
    updated_at: now
  };
  const mirrorEnabled = cleanOptionalBoolean(input.mirror_account_enabled);
  if (input.commercial_model !== undefined) patch.commercial_model = normalizeCommercialModel(input.commercial_model);
  if (input.marksman_margin_pct !== undefined) patch.marksman_margin_pct = strictPercentNumber(input.marksman_margin_pct, "MARKSMAN margin");
  if (input.carrier_share_pct !== undefined) patch.carrier_share_pct = strictPercentNumber(input.carrier_share_pct, "Carrier share");
  if (input.best_alternative_offered !== undefined) patch.best_alternative_offered = cleanOptionalBoolean(input.best_alternative_offered) === true;
  if (input.alternative_equipment !== undefined) patch.alternative_equipment = cleanText(input.alternative_equipment);
  if (input.alternative_units !== undefined) patch.alternative_units = strictBidNumber(input.alternative_units, "Alternative units");
  if (input.alternative_notes !== undefined) patch.alternative_notes = cleanText(input.alternative_notes);
  if (input.equipment_available !== undefined) patch.equipment_available = cleanOptionalBoolean(input.equipment_available);
  if (input.unit_details !== undefined) patch.unit_details = cleanText(input.unit_details);
  if (input.eta_pickup !== undefined) patch.eta_pickup = cleanTimestamp(input.eta_pickup);
  if (input.eta_delivery !== undefined) patch.eta_delivery = cleanTimestamp(input.eta_delivery);
  if (input.availability_validation_notes !== undefined) patch.availability_validation_notes = cleanText(input.availability_validation_notes);
  if (mirrorEnabled !== null) {
    patch.mirror_account_enabled = mirrorEnabled;
    patch.availability_validation_status = availabilityValidationStatus(input.availability_validation_status, mirrorEnabled);
  } else if (input.availability_validation_status !== undefined) {
    patch.availability_validation_status = availabilityValidationStatus(input.availability_validation_status, cleanBoolean(before.mirror_account_enabled));
  }

  const result = await supabase
    .from("rfx_lane_vendors")
    .update(patch)
    .eq("id", before.id)
    .select("*, vendors(id,vendor_name,domain,primary_email,whatsapp_phone,preferred_channel,base_stage,status), rfx_lanes(id,lane_number,origin,destination,currency)")
    .single();
  if (result.error) throw result.error;

  const resolveThread = input.resolve_thread !== false;
  await supabase.from("bid_room_chat_threads").update({
    communication_status: resolveThread ? "resolved" : "open",
    needs_reply: false,
    read_status: "read",
    last_read_at: now,
    resolved_at: resolveThread ? now : null,
    resolved_by: resolveThread ? user.owner_email : null,
    last_action_at: now,
    updated_at: now
  }).eq("id", thread.id).eq("owner_email", user.owner_email);

  return {
    row: result.data,
    thread,
    source_message: sourceMessage,
    before: {
      bid_rate: before.bid_rate,
      currency: before.currency,
      weekly_capacity: before.weekly_capacity,
      transit_days: before.transit_days,
      commercial_model: before.commercial_model,
      equipment_available: before.equipment_available,
      invitation_status: before.invitation_status,
      response_source: before.response_source
    },
    after: {
      bid_rate: result.data.bid_rate,
      currency: result.data.currency,
      weekly_capacity: result.data.weekly_capacity,
      transit_days: result.data.transit_days,
      commercial_model: result.data.commercial_model,
      equipment_available: result.data.equipment_available,
      invitation_status: result.data.invitation_status,
      response_source: result.data.response_source
    }
  };
}

async function postBidRoomChatMessage(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  input: Record<string, unknown>
) {
  const body = cleanText(input.body || input.message);
  if (!body) throw new Error("Message body is required.");
  const event = await requireOwnedRfxEvent(supabase, user, input.rfx_event_id || input.event_id);
  const thread = await findOrCreateBidRoomChatThread(supabase, user, event, input);
  const row = withOwner({
    thread_id: thread.id,
    rfx_event_id: event.id,
    rfx_lane_id: thread.rfx_lane_id || null,
    vendor_id: thread.vendor_id || null,
    sender_role: "procurement",
    sender_name: cleanText(input.sender_name) || user.owner_email || "Procurement",
    sender_email: user.owner_email,
    body,
    google_chat_sync_status: "pending",
    metadata: {
      source: "rateware_internal"
    }
  }, user);
  const messageResult = await supabase.from("bid_room_chat_messages").insert(row).select("*, vendors(vendor_name,domain)").single();
  if (messageResult.error) throw messageResult.error;
  await supabase.from("bid_room_chat_threads").update({
    updated_at: new Date().toISOString(),
    communication_status: "open",
    needs_reply: false,
    read_status: "read",
    last_read_at: new Date().toISOString(),
    resolved_at: null,
    resolved_by: null
  }).eq("id", thread.id);
  const sync = await syncBidRoomMessageToGoogleChat(supabase, thread, messageResult.data, event);
  return { thread, message: { ...messageResult.data, google_chat_sync_status: sync.status }, google_chat_configured: sync.status !== "not_configured" || Boolean(GOOGLE_CHAT_WEBHOOK_URL) };
}

async function syncBidRoomEventThread(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  input: Record<string, unknown>
) {
  const event = await requireOwnedRfxEvent(supabase, user, input.rfx_event_id || input.event_id);
  const thread = await findOrCreateBidRoomChatThread(supabase, user, event, {
    thread_type: "event_group",
    title: bidRoomThreadTitle("event_group", event)
  });
  const messagesResult = await supabase
    .from("bid_room_chat_messages")
    .select("*")
    .eq("thread_id", thread.id)
    .order("created_at", { ascending: false })
    .limit(1);
  if (messagesResult.error) throw messagesResult.error;

  let message = messagesResult.data?.[0] || null;
  const forceSync = input.force === true;
  if (
    message
    && !forceSync
    && cleanText(message.google_chat_sync_status) === "synced"
    && cleanText(thread.google_chat_space)
    && cleanText(thread.google_chat_thread_key)
  ) {
    return {
      thread: { ...thread, title: bidRoomThreadTitle("event_group", event), google_chat_sync_status: "synced" },
      message,
      google_chat_configured: true,
      already_synced: true
    };
  }

  if (!message) {
    const body = [
      `Bid Room thread started for ${event.rfx_id || event.name || "selected event"}.`,
      event.name ? `Event: ${event.name}` : null,
      event.customer ? `Customer: ${event.customer}` : null,
      event.due_date ? `Due date: ${event.due_date}` : null,
      "Messages posted from Rateware will mirror into this Google Chat thread."
    ].filter(Boolean).join("\n");
    const inserted = await supabase.from("bid_room_chat_messages").insert(withOwner({
      thread_id: thread.id,
      rfx_event_id: event.id,
      rfx_lane_id: null,
      vendor_id: null,
      sender_role: "system",
      sender_name: "Rateware",
      sender_email: user.owner_email,
      body,
      google_chat_sync_status: "pending",
      metadata: {
        source: "rateware_event_thread_seed",
        rfx_id: event.rfx_id || null
      }
    }, user)).select("*, vendors(vendor_name,domain)").single();
    if (inserted.error) throw inserted.error;
    message = inserted.data;
  }

  await supabase.from("bid_room_chat_threads").update({
    title: bidRoomThreadTitle("event_group", event),
    updated_at: new Date().toISOString()
  }).eq("id", thread.id);
  const sync = await syncBidRoomMessageToGoogleChat(supabase, thread, message, event);
  return {
    thread: { ...thread, title: bidRoomThreadTitle("event_group", event), google_chat_sync_status: sync.status },
    message: { ...message, google_chat_sync_status: sync.status },
    google_chat_configured: sync.status !== "not_configured" || Boolean(GOOGLE_CHAT_WEBHOOK_URL)
  };
}

function normalizeOutreachTemplate(input: Record<string, unknown>) {
  const channel = cleanText(input.channel)?.toLowerCase() || "email";
  const name = cleanText(input.name);
  if (!name) throw new Error("Template name is required.");
  return {
    name,
    channel: ["email", "whatsapp", "whatsapp_group", "multi", "email_whatsapp", "email_whatsapp_group", "whatsapp_direct_group"].includes(channel) ? channel : "email",
    subject: cleanText(input.subject),
    html_body: cleanText(extractHtmlFromMime(input.html_body || input.body || input.email_body)),
    whatsapp_body: cleanText(input.whatsapp_body || input.whatsapp_text),
    whatsapp_group_body: cleanText(input.whatsapp_group_body || input.group_body || input.whatsapp_body || input.whatsapp_text),
    meta_template_name: cleanText(input.meta_template_name || input.whatsapp_template_name),
    meta_template_language: cleanText(input.meta_template_language || input.whatsapp_template_language),
    meta_template_namespace: cleanText(input.meta_template_namespace),
    meta_template_status: cleanText(input.meta_template_status),
    meta_template_category: cleanText(input.meta_template_category),
    meta_template_components: Array.isArray(input.meta_template_components) ? input.meta_template_components : [],
    active: input.active === undefined ? true : cleanBoolean(input.active),
    is_default: input.is_default === undefined ? false : cleanBoolean(input.is_default),
    placeholders: Array.isArray(input.placeholders) ? input.placeholders.map(cleanText).filter(Boolean) : [],
    updated_at: new Date().toISOString()
  };
}

function decodeQuotedPrintable(value: string) {
  const normalized = value.replace(/=\r?\n/g, "");
  const bytes: number[] = [];
  for (let index = 0; index < normalized.length; index += 1) {
    const char = normalized[index];
    const hex = normalized.slice(index + 1, index + 3);
    if (char === "=" && /^[0-9a-fA-F]{2}$/.test(hex)) {
      bytes.push(parseInt(hex, 16));
      index += 2;
    } else {
      bytes.push(char.charCodeAt(0));
    }
  }
  return new TextDecoder("utf-8").decode(new Uint8Array(bytes));
}

function decodeBase64Text(value: string) {
  try {
    const binary = atob(value.replace(/\s+/g, ""));
    const bytes = new Uint8Array([...binary].map((char) => char.charCodeAt(0)));
    return new TextDecoder("utf-8").decode(bytes);
  } catch {
    return value;
  }
}

function extractHtmlFromMime(value: unknown) {
  const source = String(value || "");
  if (!/MIME-Version:/i.test(source) || !/Content-Type:\s*text\/html/i.test(source)) return source;
  const headerMatch = /Content-Type:\s*text\/html[\s\S]*?\r?\n\r?\n/i.exec(source);
  if (!headerMatch) return source;
  const htmlHeader = headerMatch[0];
  let htmlPart = source.slice(headerMatch.index + headerMatch[0].length);
  htmlPart = htmlPart.replace(/\r?\n--[^\r\n]+[\s\S]*$/m, "").trim();
  if (/Content-Transfer-Encoding:\s*quoted-printable/i.test(htmlHeader)) return decodeQuotedPrintable(htmlPart);
  if (/Content-Transfer-Encoding:\s*base64/i.test(htmlHeader)) return decodeBase64Text(htmlPart);
  return htmlPart;
}

function normalizeOutreachCampaign(input: Record<string, unknown>) {
  const channel = cleanText(input.channel)?.toLowerCase() || "email";
  const status = cleanText(input.status)?.toLowerCase() || "draft";
  const senderConnectionStatus = cleanText(input.sender_connection_status)?.toLowerCase() || "draft_only";
  const targetMode = cleanText(input.whatsapp_target_mode || input.target_mode)?.toLowerCase() || "direct_vendor";
  const groupPolicy = cleanText(input.group_delivery_policy)?.toLowerCase() || "manual_or_api";
  const name = cleanText(input.name);
  if (!name) throw new Error("Campaign name is required.");
  return {
    rfx_event_id: cleanText(input.rfx_event_id || input.event_id),
    template_id: cleanText(input.template_id),
    name,
    channel: ["email", "whatsapp", "whatsapp_group", "multi", "email_whatsapp", "email_whatsapp_group", "whatsapp_direct_group"].includes(channel) ? channel : "email",
    whatsapp_target_mode: ["direct_vendor", "vendor_group", "direct_and_group"].includes(targetMode) ? targetMode : "direct_vendor",
    group_delivery_policy: ["manual_only", "api_only", "manual_or_api"].includes(groupPolicy) ? groupPolicy : "manual_or_api",
    whatsapp_connection_id: cleanText(input.whatsapp_connection_id),
    status: ["draft", "generated", "queued", "sent", "closed", "archived"].includes(status) ? status : "draft",
    sender_email: cleanText(input.sender_email),
    sender_label: cleanText(input.sender_label),
    sender_connection_status: ["draft_only", "oauth_connected", "workspace_delegated"].includes(senderConnectionStatus) ? senderConnectionStatus : "draft_only",
    notes: cleanText(input.notes),
    updated_at: new Date().toISOString()
  };
}

function renderTemplateText(template: unknown, context: Record<string, unknown>) {
  return String(template || "").replace(/\{\{\s*([a-zA-Z0-9_]+)\s*\}\}/g, (_match, key) => {
    const value = context[key];
    return value === null || value === undefined ? "" : String(value);
  });
}

function htmlToText(html: unknown) {
  return String(html || "")
    .replace(/<\s*br\s*\/?>/gi, "\n")
    .replace(/<\/\s*p\s*>/gi, "\n\n")
    .replace(/<[^>]+>/g, "")
    .replace(/&nbsp;/g, " ")
    .replace(/&amp;/g, "&")
    .replace(/&lt;/g, "<")
    .replace(/&gt;/g, ">")
    .replace(/&quot;/g, '"')
    .replace(/\n{3,}/g, "\n\n")
    .trim();
}

function escapeHtmlText(value: unknown) {
  return String(value ?? "")
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function formatOutreachMoney(value: unknown, currency: unknown = "USD") {
  const number = cleanNumber(value);
  if (number === null) return "-";
  return `${new Intl.NumberFormat("en-US", { maximumFractionDigits: 2 }).format(number)} ${cleanText(currency) || "USD"}`;
}

function laneRecordFromInvitation(invitation: Record<string, unknown>) {
  return typeof invitation.rfx_lanes === "object" && invitation.rfx_lanes
    ? invitation.rfx_lanes as Record<string, unknown>
    : {};
}

function outreachTemplateLanguage(template: Record<string, unknown> | null | undefined) {
  const source = [
    template?.name,
    template?.subject,
    template?.html_body,
    template?.whatsapp_body
  ].map(cleanText).filter(Boolean).join(" ").toLowerCase();
  return /spanish|espanol|español|por favor|gracias|modelo logistico|modelo logístico/.test(source) ? "es" : "en";
}

function outreachLaneTableLabels(language = "en") {
  if (language === "es") {
    return {
      lane: "Ruta",
      origin: "Origen",
      destination: "Destino",
      equipment: "Equipo / Remolque / Config",
      operation: "Operacion",
      service: "Servicio",
      weeklyVolume: "Volumen<br>semanal",
      target: "Objetivo"
    };
  }
  return {
    lane: "Lane",
    origin: "Origin",
    destination: "Destination",
    equipment: "Equipment / Trailer / Config",
    operation: "Operation",
    service: "Service",
    weeklyVolume: "Weekly<br>volume",
    target: "Target"
  };
}

function outreachLaneRowsText(invitations: Record<string, unknown>[], language = "en") {
  return invitations.map((invitation, index) => {
    const lane = laneRecordFromInvitation(invitation);
    return [
      `${language === "es" ? "Ruta" : "Lane"} ${index + 1}: ${cleanText(lane.origin) || "-"} -> ${cleanText(lane.destination) || "-"}`,
      `${language === "es" ? "Equipo" : "Equipment"}: ${[lane.equipment, lane.trailer, lane.config].map(cleanText).filter(Boolean).join(" / ") || "-"}`,
      `${language === "es" ? "Operacion/Servicio" : "Operation/Service"}: ${[lane.operation, lane.service].map(cleanText).filter(Boolean).join(" / ") || "-"}`,
      `${language === "es" ? "Volumen" : "Volume"}: ${cleanText(lane.weekly_volume) || "-"} ${language === "es" ? "por semana" : "per week"}`,
      `${language === "es" ? "Objetivo" : "Target"}: ${formatOutreachMoney(lane.target_rate, lane.currency)}`
    ].join(" | ");
  }).join("\n");
}

function outreachLaneTableHtml(invitations: Record<string, unknown>[], language = "en") {
  if (!invitations.length) return "";
  const labels = outreachLaneTableLabels(language);
  const headerStyle = "background:rgb(31,78,121);color:rgb(255,255,255);border:1px solid rgb(183,201,217);padding:6px 8px;text-align:left;vertical-align:top;line-height:1.15;white-space:nowrap";
  const headerCenterStyle = `${headerStyle};text-align:center`;
  const cellStyle = "border:1px solid rgb(208,215,222);padding:6px 8px;vertical-align:top;line-height:1.22";
  const centerCellStyle = `${cellStyle};white-space:nowrap;text-align:center`;
  const targetCellStyle = `${centerCellStyle};background:rgb(234,243,248);font-weight:700`;
  const rows = invitations.map((invitation, index) => {
    const lane = laneRecordFromInvitation(invitation);
    const hazmatTemp = [
      cleanBoolean(lane.hazmat) ? "Hazmat" : null,
      cleanBoolean(lane.temperature_controlled) ? "Temp Ctrl" : null
    ].filter(Boolean).join(" / ") || "-";
    const equipment = [lane.equipment, lane.trailer, lane.config, hazmatTemp === "-" ? null : hazmatTemp].map(cleanText).filter(Boolean).join(" / ") || "-";
    return `
      <tr>
        <td style="${centerCellStyle}">${escapeHtmlText(index + 1)}</td>
        <td style="${cellStyle};white-space:nowrap">${escapeHtmlText(lane.origin || "-")}<br>${escapeHtmlText(lane.origin_notes || lane.origin_site || "")}</td>
        <td style="${cellStyle}">${escapeHtmlText(lane.destination || "-")}<br>${escapeHtmlText(lane.destination_notes || lane.destination_site || "")}</td>
        <td style="${cellStyle}">${escapeHtmlText(equipment)}</td>
        <td style="${centerCellStyle}">${escapeHtmlText(lane.operation || "-")}</td>
        <td style="${centerCellStyle}">${escapeHtmlText(lane.service || "-")}</td>
        <td style="${centerCellStyle}">${escapeHtmlText(lane.weekly_volume || "-")}</td>
        <td style="${targetCellStyle}">${escapeHtmlText(formatOutreachMoney(lane.target_rate, lane.currency))}</td>
      </tr>
    `;
  }).join("");
  return `
    <table style="color:rgb(31,41,55);font-family:-apple-system,BlinkMacSystemFont,&quot;Segoe UI&quot;,Roboto,Oxygen,Ubuntu,Cantarell,&quot;Helvetica Neue&quot;,Arial,sans-serif;border-collapse:collapse;width:auto;max-width:100%;table-layout:auto;font-size:12px;margin-bottom:14px">
      <thead>
        <tr>
          <th style="${headerCenterStyle}">${labels.lane}</th>
          <th style="${headerStyle}">${labels.origin}</th>
          <th style="${headerStyle}">${labels.destination}</th>
          <th style="${headerStyle}">${labels.equipment}</th>
          <th style="${headerCenterStyle}">${labels.operation}</th>
          <th style="${headerCenterStyle}">${labels.service}</th>
          <th style="${headerCenterStyle}">${labels.weeklyVolume}</th>
          <th style="${headerCenterStyle}">${labels.target}</th>
        </tr>
      </thead>
      <tbody>${rows}</tbody>
    </table>
  `;
}

function outreachLaneSignatureValue(value: unknown) {
  if (value === null || value === undefined) return "";
  if (typeof value === "boolean") return value ? "1" : "0";
  return String(value).trim();
}

function outreachLaneTableSignature(invitations: Record<string, unknown>[]) {
  const rows = invitations.map((invitation) => {
    const lane = laneRecordFromInvitation(invitation);
    return {
      invitation_id: outreachLaneSignatureValue(invitation.id),
      lane_id: outreachLaneSignatureValue(lane.id || invitation.rfx_lane_id),
      origin: outreachLaneSignatureValue(lane.origin || lane.origin_city),
      destination: outreachLaneSignatureValue(lane.destination || lane.destination_city),
      origin_site: outreachLaneSignatureValue(lane.origin_notes || lane.origin_site),
      destination_site: outreachLaneSignatureValue(lane.destination_notes || lane.destination_site),
      equipment: outreachLaneSignatureValue(lane.equipment),
      trailer: outreachLaneSignatureValue(lane.trailer),
      config: outreachLaneSignatureValue(lane.config),
      hazmat: outreachLaneSignatureValue(cleanBoolean(lane.hazmat)),
      temperature_controlled: outreachLaneSignatureValue(cleanBoolean(lane.temperature_controlled)),
      operation: outreachLaneSignatureValue(lane.operation),
      service: outreachLaneSignatureValue(lane.service),
      weekly_volume: outreachLaneSignatureValue(lane.weekly_volume),
      target_rate: outreachLaneSignatureValue(lane.target_rate),
      currency: outreachLaneSignatureValue(lane.currency)
    };
  }).sort((left, right) => `${left.invitation_id}:${left.lane_id}`.localeCompare(`${right.invitation_id}:${right.lane_id}`));
  return JSON.stringify(rows);
}

function rfxInvitationVendorGroupKey(invitation: Record<string, unknown>) {
  const vendor = typeof invitation.vendors === "object" && invitation.vendors ? invitation.vendors as Record<string, unknown> : {};
  const vendorKey = cleanText(invitation.vendor_id) || cleanText(vendor.id) || cleanText(vendor.primary_email) || cleanText(vendor.domain) || cleanText(invitation.id);
  const eventKey = cleanText(invitation.rfx_event_id);
  return eventKey && vendorKey ? `${eventKey}:${vendorKey}` : "";
}

function sortRfxInvitationGroup(invitations: Record<string, unknown>[]) {
  return [...invitations].sort((left, right) => {
    const leftLane = laneRecordFromInvitation(left);
    const rightLane = laneRecordFromInvitation(right);
    const leftKey = [
      cleanText(leftLane.lane_number).padStart(8, "0"),
      cleanText(leftLane.lane_id || leftLane.id || left.rfx_lane_id),
      cleanText(left.id)
    ].join(":");
    const rightKey = [
      cleanText(rightLane.lane_number).padStart(8, "0"),
      cleanText(rightLane.lane_id || rightLane.id || right.rfx_lane_id),
      cleanText(right.id)
    ].join(":");
    return leftKey.localeCompare(rightKey);
  });
}

function phoneForWhatsapp(value: unknown) {
  const digits = String(value || "").replace(/[^\d]/g, "");
  return digits.length >= 10 ? digits : null;
}

function gmailComposeUrl(to: unknown, subject: unknown, body: unknown) {
  const recipient = cleanText(to);
  if (!recipient) return null;
  const params = new URLSearchParams({
    view: "cm",
    fs: "1",
    to: recipient,
    su: cleanText(subject) || "",
    body: cleanText(body) || ""
  });
  return `https://mail.google.com/mail/?${params.toString()}`;
}

function whatsappDraftUrl(phone: unknown, text: unknown) {
  const normalized = phoneForWhatsapp(phone);
  if (!normalized) return null;
  return `https://wa.me/${normalized}?text=${encodeURIComponent(cleanText(text) || "")}`;
}

function contactPreview(value: unknown) {
  return String(value || "")
    .replace(/\s+/g, " ")
    .trim()
    .slice(0, 240);
}

const SUPPORT_TICKET_DB_STATUSES = ["support_ticket", "support_open", "support_in_progress", "support_resolved", "support_archived"];
const SUPPORT_TICKET_UI_STATUSES = new Set(["open", "in_progress", "resolved", "archived"]);
const SUPPORT_TICKET_PRIORITIES = new Set(["low", "normal", "high", "urgent"]);

function supportTicketStatus(row: Record<string, unknown>) {
  const metadata = objectRecord(row.metadata);
  const status = cleanText(metadata.support_status)?.toLowerCase() || cleanText(row.status)?.toLowerCase();
  if (status === "support_ticket" || status === "support_open") return "open";
  if (status === "support_in_progress") return "in_progress";
  if (status === "support_resolved") return "resolved";
  if (status === "support_archived") return "archived";
  return SUPPORT_TICKET_UI_STATUSES.has(status || "") ? status : "open";
}

function supportTicketPriority(row: Record<string, unknown>) {
  const metadata = objectRecord(row.metadata);
  const priority = cleanText(metadata.priority)?.toLowerCase();
  return SUPPORT_TICKET_PRIORITIES.has(priority || "") ? priority : "normal";
}

function supportTicketDbStatus(status: unknown) {
  const normalized = cleanText(status)?.toLowerCase() || "open";
  if (!SUPPORT_TICKET_UI_STATUSES.has(normalized)) throw new Error("Unsupported support ticket status.");
  return normalized === "open" ? "support_open" : `support_${normalized}`;
}

function supportTicketMatchesSearch(row: Record<string, unknown>, search: string) {
  if (!search) return true;
  const metadata = objectRecord(row.metadata);
  const vendor = relationRecord(row.vendors);
  const event = relationRecord(row.rfx_events);
  const haystack = [
    row.subject,
    row.body_preview,
    metadata.question,
    metadata.answer,
    metadata.route,
    metadata.contact_email,
    vendor.vendor_name,
    vendor.domain,
    vendor.primary_email,
    event.rfx_id,
    event.name,
    event.customer
  ].map((value) => String(value || "").toLowerCase()).join(" ");
  return haystack.includes(search.toLowerCase());
}

function serializeSupportTicket(row: Record<string, unknown>) {
  const metadata = objectRecord(row.metadata);
  const vendor = relationRecord(row.vendors);
  const event = relationRecord(row.rfx_events);
  return {
    ...row,
    support_status: supportTicketStatus(row),
    priority: supportTicketPriority(row),
    question: cleanText(metadata.question || row.body_preview),
    answer: cleanText(metadata.answer),
    route: cleanText(metadata.route),
    lane_id: cleanText(metadata.lane_id),
    contact_email: cleanText(metadata.contact_email || vendor.primary_email),
    assigned_to: cleanText(metadata.assigned_to),
    internal_note: cleanText(metadata.internal_note || metadata.last_internal_note),
    public_context: cleanBoolean(metadata.public_context),
    google_chat_sync_status: cleanText(metadata.google_chat_sync_status),
    google_chat_thread_id: cleanText(metadata.google_chat_thread_id),
    google_chat_message_id: cleanText(metadata.google_chat_message_id),
    vendor_name: cleanText(vendor.vendor_name || vendor.domain),
    vendor_domain: cleanText(vendor.domain),
    vendor_email: cleanText(vendor.primary_email),
    rfx_id: cleanText(event.rfx_id),
    rfx_name: cleanText(event.name),
    event_customer: cleanText(event.customer),
    due_date: cleanText(event.due_date)
  };
}

async function listVendorSupportTickets(
  supabase: ReturnType<typeof createClient>,
  user: { owner_email: string | null },
  input: Record<string, unknown>
) {
  const limit = Math.min(Math.max(Number(input.limit || 300) || 300, 1), 1000);
  let query = supabase
    .from("contact_history")
    .select("*, vendors(id,vendor_name,domain,primary_email,whatsapp_phone), rfx_events(id,rfx_id,name,customer,status,due_date)")
    .eq("owner_email", user.owner_email)
    .in("status", SUPPORT_TICKET_DB_STATUSES)
    .order("occurred_at", { ascending: false })
    .limit(limit);
  if (input.vendor_id) query = query.eq("vendor_id", cleanText(input.vendor_id));
  if (input.rfx_event_id || input.event_id) query = query.eq("rfx_event_id", cleanText(input.rfx_event_id || input.event_id));
  const result = await query;
  if (result.error) throw result.error;

  const statusFilter = cleanText(input.status)?.toLowerCase();
  const priorityFilter = cleanText(input.priority)?.toLowerCase();
  const search = cleanText(input.search)?.toLowerCase() || "";
  const rows = (result.data || [])
    .map(serializeSupportTicket)
    .filter((row) => !statusFilter || statusFilter === "all" || row.support_status === statusFilter)
    .filter((row) => !priorityFilter || priorityFilter === "all" || row.priority === priorityFilter)
    .filter((row) => supportTicketMatchesSearch(row, search));

  const summary = rows.reduce((acc, row) => {
    acc.total += 1;
    acc[row.support_status] = (acc[row.support_status] || 0) + 1;
    if (row.google_chat_sync_status === "synced") acc.google_chat_synced += 1;
    if (row.priority === "urgent" || row.priority === "high") acc.high_priority += 1;
    return acc;
  }, { total: 0, open: 0, in_progress: 0, resolved: 0, archived: 0, google_chat_synced: 0, high_priority: 0 } as Record<string, number>);

  return { rows, summary, limit };
}

async function updateVendorSupportTicket(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  input: Record<string, unknown>
) {
  const id = cleanText(input.id || input.ticket_id);
  if (!id) throw new Error("Support ticket id is required.");
  const existing = await supabase
    .from("contact_history")
    .select("*, vendors(id,vendor_name,domain,primary_email,whatsapp_phone), rfx_events(id,rfx_id,name,customer,status,due_date)")
    .eq("id", id)
    .eq("owner_email", user.owner_email)
    .in("status", SUPPORT_TICKET_DB_STATUSES)
    .single();
  if (existing.error) throw existing.error;

  const currentMetadata = objectRecord(existing.data.metadata);
  const patchMetadata: Record<string, unknown> = {
    ...currentMetadata,
    last_action_at: new Date().toISOString(),
    last_action_by: user.owner_email
  };
  const updatePatch: Record<string, unknown> = {};

  if ("status" in input || "support_status" in input) {
    const nextStatus = cleanText(input.status || input.support_status)?.toLowerCase() || "open";
    updatePatch.status = supportTicketDbStatus(nextStatus);
    patchMetadata.support_status = nextStatus;
    if (nextStatus === "resolved") patchMetadata.resolved_at = new Date().toISOString();
    if (nextStatus !== "resolved") patchMetadata.resolved_at = null;
  }
  if ("priority" in input) {
    const priority = cleanText(input.priority)?.toLowerCase() || "normal";
    if (!SUPPORT_TICKET_PRIORITIES.has(priority)) throw new Error("Unsupported support ticket priority.");
    patchMetadata.priority = priority;
  }
  if ("assigned_to" in input) patchMetadata.assigned_to = cleanText(input.assigned_to);
  if ("internal_note" in input || "note" in input) patchMetadata.internal_note = cleanText(input.internal_note || input.note);

  updatePatch.metadata = patchMetadata;
  const result = await supabase
    .from("contact_history")
    .update(updatePatch)
    .eq("id", id)
    .eq("owner_email", user.owner_email)
    .select("*, vendors(id,vendor_name,domain,primary_email,whatsapp_phone), rfx_events(id,rfx_id,name,customer,status,due_date)")
    .single();
  if (result.error) throw result.error;

  await writeAuditLog(
    supabase,
    user,
    "vendor_support.update",
    "contact_history",
    id,
    `Updated vendor support ticket ${id}`,
    { support_status: serializeSupportTicket(result.data).support_status, priority: serializeSupportTicket(result.data).priority }
  );
  return { row: serializeSupportTicket(result.data) };
}

const VENDOR_CI_CASE_TYPES = new Set([
  "service_quality",
  "cost_variance",
  "capacity_commitment",
  "compliance",
  "documentation",
  "technology",
  "claims",
  "billing",
  "communication",
  "strategic_growth"
]);
const VENDOR_CI_STATUSES = new Set(["open", "define", "measure", "analyze", "improve", "control", "resolved", "archived"]);
const VENDOR_CI_SEVERITIES = new Set(["low", "medium", "high", "critical"]);
const VENDOR_CI_METHODS = new Set(["dmaic", "8d", "capa", "kaizen", "a3"]);
const VENDOR_CI_TIERS = new Set(["watchlist", "tactical", "strategic", "collaborative"]);

function normalizedVendorCiCaseType(value: unknown) {
  const normalized = cleanText(value)?.toLowerCase() || "service_quality";
  return VENDOR_CI_CASE_TYPES.has(normalized) ? normalized : "service_quality";
}

function normalizedVendorCiStatus(value: unknown, fallback = "open") {
  const normalized = cleanText(value)?.toLowerCase() || fallback;
  if (!VENDOR_CI_STATUSES.has(normalized)) throw new Error("Unsupported vendor improvement status.");
  return normalized;
}

function normalizedVendorCiSeverity(value: unknown) {
  const normalized = cleanText(value)?.toLowerCase() || "medium";
  if (!VENDOR_CI_SEVERITIES.has(normalized)) throw new Error("Unsupported vendor improvement severity.");
  return normalized;
}

function normalizedVendorCiTier(value: unknown, fallback = "tactical") {
  const normalized = cleanText(value)?.toLowerCase() || fallback;
  if (!VENDOR_CI_TIERS.has(normalized)) throw new Error("Unsupported vendor value tier.");
  return normalized;
}

function normalizedVendorCiMethod(value: unknown, caseType = "service_quality") {
  const explicit = cleanText(value)?.toLowerCase();
  if (explicit && VENDOR_CI_METHODS.has(explicit)) return explicit;
  if (["compliance", "documentation", "billing"].includes(caseType)) return "capa";
  if (["claims", "service_quality", "communication"].includes(caseType)) return "8d";
  if (["strategic_growth", "technology"].includes(caseType)) return "kaizen";
  return "dmaic";
}

function numericScore(value: unknown, fallback = 0) {
  const number = Number(value);
  if (!Number.isFinite(number)) return fallback;
  return Math.max(0, Math.min(100, Math.round(number)));
}

function tierFromValueScore(score: number) {
  if (score >= 85) return "collaborative";
  if (score >= 65) return "strategic";
  if (score >= 40) return "tactical";
  return "watchlist";
}

function defaultScorecardForVendor(vendor: Record<string, unknown>) {
  const hasContact = Boolean(cleanText(vendor.primary_email) || cleanText(vendor.whatsapp_phone));
  const hasDomain = Boolean(cleanText(vendor.domain));
  const hasCoverage = Boolean(cleanText(vendor.coverage_notes) || cleanText(vendor.notes));
  const baseStage = cleanText(vendor.base_stage);
  const operational = (baseStage === "procurement" ? 35 : 20) + (hasCoverage ? 20 : 0) + (hasContact ? 15 : 0);
  const commercial = (baseStage === "procurement" ? 45 : 25) + (hasDomain ? 10 : 0);
  const compliance = cleanText(vendor.status) === "active" ? 55 : 35;
  const technology = hasDomain ? 40 : 25;
  const relationship = hasContact ? 50 : 25;
  const value = Math.round((operational + commercial + compliance + technology + relationship) / 5);
  return {
    operational_score: numericScore(operational),
    commercial_score: numericScore(commercial),
    financial_score: numericScore(commercial),
    compliance_score: numericScore(compliance),
    technology_score: numericScore(technology),
    relationship_score: numericScore(relationship),
    value_score: numericScore(value),
    tier: tierFromValueScore(value),
    attributes: {
      auto_seeded: true,
      source: "vendor_profile",
      base_stage: baseStage,
      contact_ready: hasContact,
      coverage_ready: hasCoverage
    }
  };
}

