async function requireOwnedVendorForCi(
  supabase: ReturnType<typeof createClient>,
  user: { owner_email: string | null },
  vendorId: unknown
) {
  const id = cleanText(vendorId);
  if (!id) throw new Error("Vendor is required.");
  const result = await supabase
    .from("vendors")
    .select("id,vendor_name,name,legal_name,domain,primary_email,whatsapp_phone,base_stage,status,coverage_notes,notes,tags")
    .eq("id", id)
    .eq("owner_email", user.owner_email)
    .single();
  if (result.error) throw result.error;
  return result.data as Record<string, unknown>;
}

async function ensureVendorValueScorecard(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  vendor: Record<string, unknown>
) {
  const existing = await supabase
    .from("vendor_value_scorecards")
    .select("*")
    .eq("owner_email", user.owner_email)
    .eq("vendor_id", vendor.id)
    .limit(1);
  if (existing.error) throw existing.error;
  if (existing.data?.[0]) return existing.data[0] as Record<string, unknown>;

  const defaults = defaultScorecardForVendor(vendor);
  const inserted = await supabase
    .from("vendor_value_scorecards")
    .insert(withOwner({
      vendor_id: vendor.id,
      ...defaults,
      last_scored_at: new Date().toISOString()
    }, user))
    .select("*")
    .single();
  if (inserted.error) throw inserted.error;
  return inserted.data as Record<string, unknown>;
}

function serializeVendorValueScorecard(row: Record<string, unknown>) {
  const vendor = relationRecord(row.vendors);
  return {
    ...row,
    vendor_name: cleanText(vendor.vendor_name || vendor.name || vendor.legal_name || vendor.domain),
    vendor_domain: cleanText(vendor.domain),
    vendor_email: cleanText(vendor.primary_email)
  };
}

const VENDOR_CI_VALUE_CURVE_LIMIT = 5000;

function vendorCiVendorName(vendor: Record<string, unknown>) {
  return cleanText(vendor.vendor_name || vendor.name || vendor.legal_name || vendor.domain || vendor.primary_email) || "Unknown vendor";
}

function vendorCiScoreBlend(autoScore: number, manualScore: unknown, manualWeight = 0.35) {
  if (manualScore === null || manualScore === undefined || manualScore === "") return numericScore(autoScore);
  const manual = Number(manualScore);
  if (!Number.isFinite(manual)) return numericScore(autoScore);
  return numericScore(autoScore * (1 - manualWeight) + numericScore(manual) * manualWeight);
}

function vendorCiSignalStats() {
  return {
    bid_invitations: 0,
    bid_responses: 0,
    awards: 0,
    capacity_confirmations: 0,
    outbound_contacts: 0,
    inbound_contacts: 0,
    failed_contacts: 0,
    support_open: 0,
    support_resolved: 0,
    ci_open: 0,
    ci_critical: 0,
    ci_resolved: 0,
    carrier_chat_messages: 0,
    procurement_chat_messages: 0
  };
}

function vendorCiStatsFor(map: Map<string, ReturnType<typeof vendorCiSignalStats>>, vendorId: unknown) {
  const id = cleanText(vendorId) || "";
  if (!id) return null;
  if (!map.has(id)) map.set(id, vendorCiSignalStats());
  return map.get(id) || null;
}

async function fetchVendorCiVendors(
  supabase: ReturnType<typeof createClient>,
  user: { owner_email: string | null },
  limit = VENDOR_CI_VALUE_CURVE_LIMIT
) {
  const rows: Record<string, unknown>[] = [];
  const pageSize = 1000;
  for (let offset = 0; offset < limit; offset += pageSize) {
    const result = await supabase
      .from("vendors")
      .select("id,vendor_name,name,legal_name,domain,primary_email,whatsapp_phone,preferred_channel,base_stage,status,tags,coverage_notes,notes,profile_data,created_at,updated_at")
      .eq("owner_email", user.owner_email)
      .order("vendor_name", { ascending: true, nullsFirst: false })
      .range(offset, Math.min(offset + pageSize - 1, limit - 1));
    if (result.error) throw result.error;
    rows.push(...(result.data || []));
    if ((result.data || []).length < pageSize) break;
  }
  return rows;
}

async function fetchVendorCiManualScorecards(
  supabase: ReturnType<typeof createClient>,
  user: { owner_email: string | null },
  limit = VENDOR_CI_VALUE_CURVE_LIMIT
) {
  const rows: Record<string, unknown>[] = [];
  const pageSize = 1000;
  for (let offset = 0; offset < limit; offset += pageSize) {
    const result = await supabase
      .from("vendor_value_scorecards")
      .select("*, vendors(id,vendor_name,name,legal_name,domain,primary_email,base_stage,status)")
      .eq("owner_email", user.owner_email)
      .order("value_score", { ascending: false })
      .range(offset, Math.min(offset + pageSize - 1, limit - 1));
    if (result.error) throw result.error;
    rows.push(...(result.data || []).map(serializeVendorValueScorecard));
    if ((result.data || []).length < pageSize) break;
  }
  return rows;
}

async function fetchVendorCiSignalRows(
  label: string,
  query: PromiseLike<{ data: unknown[] | null; error: unknown }>
) {
  try {
    const result = await query;
    if (result.error) throw result.error;
    return { rows: (result.data || []) as Record<string, unknown>[], warning: null as string | null };
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error || "Unknown signal error");
    console.warn(`Vendor CI ${label} signals unavailable; continuing without them.`, message);
    return {
      rows: [] as Record<string, unknown>[],
      warning: `${label} signals are temporarily unavailable.`
    };
  }
}

function vendorCiScoreFromSignals(
  vendor: Record<string, unknown>,
  metrics: Record<string, unknown>,
  signals: ReturnType<typeof vendorCiSignalStats>,
  manualScorecard?: Record<string, unknown>
) {
  const readiness = vendorReadinessScore(vendor);
  const linkedRates = Number(metrics.linked_rates || 0);
  const approvedRates = Number(metrics.approved_rates || 0);
  const pendingRates = Number(metrics.pending_rates || 0);
  const status = cleanText(vendor.status)?.toLowerCase();
  const baseStage = cleanText(vendor.base_stage)?.toLowerCase();
  const manualAttributes = objectRecord(manualScorecard?.attributes);
  const manualWeight = manualScorecard && !manualAttributes.auto_seeded ? 0.35 : 0.15;

  const operationalAuto = numericScore(
    readiness * 0.3
    + Math.min(24, linkedRates * 1.4)
    + Math.min(18, signals.bid_responses * 5)
    + Math.min(16, signals.capacity_confirmations * 8)
    + Math.min(12, signals.awards * 10)
    - Math.min(24, signals.support_open * 8 + signals.ci_critical * 10)
  );
  const commercialAuto = numericScore(
    (baseStage === "procurement" ? 30 : 18)
    + Math.min(26, approvedRates * 2.5)
    + Math.min(18, pendingRates * 1.2)
    + Math.min(20, signals.bid_responses * 5)
    + Math.min(18, signals.awards * 12)
  );
  const complianceAuto = numericScore(
    (status === "active" ? 64 : status === "blocked" ? 20 : 42)
    + Math.min(14, signals.support_resolved * 5)
    - Math.min(34, signals.support_open * 12 + signals.ci_critical * 10 + signals.failed_contacts * 3)
  );
  const technologyAuto = numericScore(
    (vendor.domain ? 30 : 12)
    + (vendor.primary_email ? 22 : 0)
    + (vendor.whatsapp_phone ? 12 : 0)
    + Math.min(18, signals.carrier_chat_messages * 3)
    + Math.min(18, signals.bid_responses * 4)
  );
  const relationshipAuto = numericScore(
    (vendor.primary_email || vendor.whatsapp_phone ? 35 : 18)
    + Math.min(24, signals.inbound_contacts * 5)
    + Math.min(24, signals.carrier_chat_messages * 4)
    + Math.min(14, signals.ci_resolved * 7)
    - Math.min(24, signals.support_open * 8 + signals.failed_contacts * 4)
  );
  const financialAuto = numericScore(
    28
    + Math.min(30, approvedRates * 3)
    + Math.min(20, signals.awards * 14)
    + Math.min(16, signals.bid_responses * 4)
    - Math.min(18, signals.ci_open * 4)
  );

  const operational = vendorCiScoreBlend(operationalAuto, manualScorecard?.operational_score, manualWeight);
  const commercial = vendorCiScoreBlend(commercialAuto, manualScorecard?.commercial_score, manualWeight);
  const compliance = vendorCiScoreBlend(complianceAuto, manualScorecard?.compliance_score, manualWeight);
  const technology = vendorCiScoreBlend(technologyAuto, manualScorecard?.technology_score, manualWeight);
  const relationship = vendorCiScoreBlend(relationshipAuto, manualScorecard?.relationship_score, manualWeight);
  const financial = vendorCiScoreBlend(financialAuto, manualScorecard?.financial_score, manualWeight);
  const autoValue = Math.round(
    operational * 0.22
    + commercial * 0.22
    + compliance * 0.16
    + technology * 0.12
    + relationship * 0.18
    + financial * 0.1
  );
  const value = vendorCiScoreBlend(autoValue, manualScorecard?.value_score, manualWeight);
  const tier = cleanText(manualScorecard?.tier) || tierFromValueScore(value);

  return {
    operational_score: operational,
    commercial_score: commercial,
    financial_score: financial,
    compliance_score: compliance,
    technology_score: technology,
    relationship_score: relationship,
    value_score: value,
    tier
  };
}

async function buildVendorValueCurve(
  supabase: ReturnType<typeof createClient>,
  user: { owner_email: string | null },
  input: Record<string, unknown> = {}
) {
  const limit = Math.min(Math.max(Number(input.value_curve_limit || VENDOR_CI_VALUE_CURVE_LIMIT) || VENDOR_CI_VALUE_CURVE_LIMIT, 1), VENDOR_CI_VALUE_CURVE_LIMIT);
  const vendors = await fetchVendorCiVendors(supabase, user, limit);
  const manualRows = await fetchVendorCiManualScorecards(supabase, user, limit);
  const manualByVendor = new Map(manualRows.map((row) => [cleanText(row.vendor_id) || "", row]));
  const warnings: string[] = [];
  const rateMetrics = await fetchVendorRateMetricsSafe(supabase, user);
  warnings.push(...rateMetrics.warnings);

  const [bidRowsResult, contactRowsResult, chatRowsResult, ciCaseRowsResult] = await Promise.all([
    fetchVendorCiSignalRows(
      "Bid Room",
      supabase
        .from("rfx_lane_vendors")
        .select("vendor_id,invitation_status,bid_rate,weekly_capacity,responded_at,award_role,awarded_at,equipment_available,commercial_model,rfx_events!inner(owner_email)")
        .eq("rfx_events.owner_email", user.owner_email)
        .not("vendor_id", "is", null)
        .limit(10000)
    ),
    fetchVendorCiSignalRows(
      "contact history",
      supabase
        .from("contact_history")
        .select("vendor_id,status,direction,channel,metadata,occurred_at")
        .eq("owner_email", user.owner_email)
        .not("vendor_id", "is", null)
        .limit(10000)
    ),
    fetchVendorCiSignalRows(
      "Bid Room chat",
      supabase
        .from("bid_room_chat_messages")
        .select("vendor_id,sender_role,created_at")
        .eq("owner_email", user.owner_email)
        .not("vendor_id", "is", null)
        .limit(10000)
    ),
    fetchVendorCiSignalRows(
      "improvement case",
      supabase
        .from("vendor_improvement_cases")
        .select("vendor_id,status,severity,case_type,updated_at")
        .eq("owner_email", user.owner_email)
        .not("vendor_id", "is", null)
        .limit(10000)
    )
  ]);
  for (const result of [bidRowsResult, contactRowsResult, chatRowsResult, ciCaseRowsResult]) {
    if (result.warning) warnings.push(result.warning);
  }

  const signalMap = new Map<string, ReturnType<typeof vendorCiSignalStats>>();
  for (const row of bidRowsResult.rows) {
    const stats = vendorCiStatsFor(signalMap, row.vendor_id);
    if (!stats) continue;
    stats.bid_invitations += 1;
    const status = cleanText(row.invitation_status)?.toLowerCase();
    if (row.responded_at || row.bid_rate !== null || status === "bid_submitted" || status === "quoted") stats.bid_responses += 1;
    if (row.award_role || row.awarded_at || status === "awarded") stats.awards += 1;
    if (cleanBoolean(row.equipment_available) || row.weekly_capacity) stats.capacity_confirmations += 1;
  }
  for (const row of contactRowsResult.rows) {
    const stats = vendorCiStatsFor(signalMap, row.vendor_id);
    if (!stats) continue;
    const direction = cleanText(row.direction)?.toLowerCase();
    const status = cleanText(row.status)?.toLowerCase();
    if (direction === "inbound") stats.inbound_contacts += 1;
    if (direction === "outbound") stats.outbound_contacts += 1;
    if (status === "failed" || status === "bounced" || status === "suppressed") stats.failed_contacts += 1;
    if (["support_ticket", "support_open", "support_in_progress"].includes(status || "")) stats.support_open += 1;
    if (status === "support_resolved") stats.support_resolved += 1;
  }
  for (const row of chatRowsResult.rows) {
    const stats = vendorCiStatsFor(signalMap, row.vendor_id);
    if (!stats) continue;
    const role = cleanText(row.sender_role)?.toLowerCase();
    if (role === "carrier") stats.carrier_chat_messages += 1;
    if (role === "procurement") stats.procurement_chat_messages += 1;
  }
  for (const row of ciCaseRowsResult.rows) {
    const stats = vendorCiStatsFor(signalMap, row.vendor_id);
    if (!stats) continue;
    const status = cleanText(row.status)?.toLowerCase();
    if (!["resolved", "archived"].includes(status || "")) stats.ci_open += 1;
    if (row.severity === "critical" && !["resolved", "archived"].includes(status || "")) stats.ci_critical += 1;
    if (status === "resolved") stats.ci_resolved += 1;
  }

  const scorecards = vendors.map((vendor) => {
    const vendorId = cleanText(vendor.id) || "";
    const manual = manualByVendor.get(vendorId);
    const metrics = normalizeVendorMetricRow(rateMetrics.metrics.get(vendorId));
    const signals = signalMap.get(vendorId) || vendorCiSignalStats();
    const score = vendorCiScoreFromSignals(vendor, metrics, signals, manual);
    const sourceSummary = [
      `${Number(metrics.linked_rates || 0)} rate(s)`,
      `${signals.bid_responses}/${signals.bid_invitations} bid response(s)`,
      `${signals.awards} award(s)`,
      `${signals.support_open} open support/CI issue(s)`,
      `${signals.carrier_chat_messages} carrier chat message(s)`
    ].join(" | ");
    return {
      ...(manual || {}),
      vendor_id: vendorId,
      id: cleanText(manual?.id) || `computed:${vendorId}`,
      vendor_name: vendorCiVendorName(vendor),
      vendor_domain: cleanText(vendor.domain),
      vendor_email: cleanText(vendor.primary_email),
      ...score,
      attributes: {
        ...objectRecord(manual?.attributes),
        computed_live_value_curve: true,
        manual_scorecard: Boolean(manual && !objectRecord(manual.attributes).auto_seeded),
        source_summary: sourceSummary,
        signal_sources: {
          crm: true,
          rateware: true,
          bid_room: true,
          vendor_support: true,
          bid_room_chat: true,
          manual_scorecard: Boolean(manual)
        },
        signals: {
          ...signals,
          linked_rates: Number(metrics.linked_rates || 0),
          approved_rates: Number(metrics.approved_rates || 0),
          pending_rates: Number(metrics.pending_rates || 0),
          crossborder_rates: Number(metrics.crossborder_rates || 0),
          d2d_import_export_rates: Number(metrics.d2d_import_export_rates || 0),
          mexico_rates: Number(metrics.mexico_rates || 0),
          last_quote_date: cleanText(metrics.last_quote_date)
        }
      },
      source_summary: sourceSummary,
      linked_rates: Number(metrics.linked_rates || 0),
      approved_rates: Number(metrics.approved_rates || 0),
      bid_invitations: signals.bid_invitations,
      bid_responses: signals.bid_responses,
      awards: signals.awards,
      support_open: signals.support_open + signals.ci_open,
      chat_messages: signals.carrier_chat_messages,
      last_scored_at: cleanText(manual?.last_scored_at) || new Date().toISOString()
    };
  });

  return {
    scorecards: scorecards.sort((left, right) => Number(right.value_score || 0) - Number(left.value_score || 0)),
    warnings,
    source_counts: {
      vendors: vendors.length,
      manual_scorecards: manualRows.length,
      bid_rows: bidRowsResult.rows.length,
      contact_rows: contactRowsResult.rows.length,
      chat_rows: chatRowsResult.rows.length,
      ci_case_rows: ciCaseRowsResult.rows.length
    }
  };
}

function vendorCiNextStep(row: Record<string, unknown>) {
  const status = cleanText(row.status) || "open";
  const method = cleanText(row.methodology)?.toUpperCase() || "DMAIC";
  const map: Record<string, string> = {
    open: `Open ${method} case and define the business requirement.`,
    define: "Confirm problem statement, scope, owner and due date.",
    measure: "Capture evidence, impact, frequency and baseline metric.",
    analyze: "Document root cause and decide if this is process, carrier, market or compliance.",
    improve: "Assign corrective action, target date and required proof.",
    control: "Validate effectiveness and decide whether the vendor tier can improve.",
    resolved: "Resolved. Keep evidence available in the vendor profile.",
    archived: "Archived."
  };
  return map[status] || map.open;
}

function serializeVendorImprovementCase(row: Record<string, unknown>, scorecardByVendor = new Map<string, Record<string, unknown>>()) {
  const vendor = relationRecord(row.vendors);
  const vendorId = cleanText(row.vendor_id) || cleanText(vendor.id) || "";
  const scorecard = scorecardByVendor.get(vendorId);
  const metadata = objectRecord(row.metadata);
  return {
    ...row,
    vendor_name: cleanText(vendor.vendor_name || vendor.name || vendor.legal_name || vendor.domain),
    vendor_domain: cleanText(vendor.domain),
    vendor_email: cleanText(vendor.primary_email),
    current_tier: cleanText(scorecard?.tier || row.tier_at_open || "tactical"),
    value_score: numericScore(scorecard?.value_score),
    next_step: vendorCiNextStep(row),
    submitted_at: cleanText(metadata.submitted_at),
    submitted_to: cleanText(metadata.submitted_to),
    submission_status: cleanText(metadata.submission_status),
    next_reminder_at: cleanText(metadata.next_reminder_at),
    reminders_enabled: cleanBoolean(metadata.reminders_enabled),
    reminder_interval_days: Number(metadata.reminder_interval_days || 0) || null,
    reminder_count: Number(metadata.reminder_count || 0) || 0,
    last_submission_error: cleanText(metadata.last_submission_error)
  };
}

function vendorImprovementMatchesSearch(row: Record<string, unknown>, search: string) {
  if (!search) return true;
  const haystack = [
    row.title,
    row.description,
    row.vendor_request,
    row.owner_notes,
    row.root_cause,
    row.corrective_action,
    row.preventive_action,
    row.success_metric,
    row.vendor_name,
    row.vendor_domain,
    row.vendor_email,
    row.case_type,
    row.status,
    row.methodology
  ].map((value) => String(value || "").toLowerCase()).join(" ");
  return haystack.includes(search.toLowerCase());
}

function vendorValueScorecardMatchesSearch(row: Record<string, unknown>, search: string) {
  if (!search) return true;
  const attributes = objectRecord(row.attributes);
  const signals = objectRecord(attributes.signals);
  const haystack = [
    row.vendor_name,
    row.vendor_domain,
    row.vendor_email,
    row.tier,
    row.source_summary,
    signals.last_quote_date,
    row.linked_rates,
    row.bid_responses,
    row.awards,
    row.support_open,
    row.chat_messages
  ].map((value) => String(value || "").toLowerCase()).join(" ");
  return haystack.includes(search.toLowerCase());
}

function summarizeVendorCi(rows: Record<string, unknown>[], scorecards: Record<string, unknown>[]) {
  const now = new Date();
  const sevenDays = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);
  const activeRows = rows.filter((row) => !["resolved", "archived"].includes(cleanText(row.status) || ""));
  const dueSoon = activeRows.filter((row) => {
    const dateText = cleanText(row.due_date);
    if (!dateText) return false;
    const due = new Date(dateText);
    return !Number.isNaN(due.getTime()) && due <= sevenDays;
  });
  const averageScore = scorecards.length
    ? scorecards.reduce((sum, row) => sum + Number(row.value_score || 0), 0) / scorecards.length
    : 0;
  return {
    total_cases: rows.length,
    total_vendors_scored: scorecards.length,
    open_active: activeRows.length,
    critical: activeRows.filter((row) => row.severity === "critical").length,
    due_soon: dueSoon.length,
    collaborative: scorecards.filter((row) => row.tier === "collaborative").length,
    strategic: scorecards.filter((row) => row.tier === "strategic").length,
    tactical: scorecards.filter((row) => row.tier === "tactical").length,
    watchlist: scorecards.filter((row) => row.tier === "watchlist").length,
    average_value_score: Math.round(averageScore)
  };
}

async function listVendorImprovementCases(
  supabase: ReturnType<typeof createClient>,
  user: { owner_email: string | null },
  input: Record<string, unknown>
) {
  const limit = Math.min(Math.max(Number(input.limit || 1000) || 1000, 1), 1000);
  const statusFilter = cleanText(input.status)?.toLowerCase() || "all";
  const typeFilter = cleanText(input.case_type || input.type)?.toLowerCase() || "all";
  const tierFilter = cleanText(input.tier)?.toLowerCase() || "all";
  const search = cleanText(input.search)?.toLowerCase() || "";

  let caseQuery = supabase
    .from("vendor_improvement_cases")
    .select("*, vendors(id,vendor_name,name,legal_name,domain,primary_email,base_stage,status)")
    .eq("owner_email", user.owner_email)
    .order("updated_at", { ascending: false })
    .limit(limit);
  if (input.vendor_id) caseQuery = caseQuery.eq("vendor_id", cleanText(input.vendor_id));
  if (statusFilter !== "all") caseQuery = caseQuery.eq("status", normalizedVendorCiStatus(statusFilter));
  if (typeFilter !== "all") caseQuery = caseQuery.eq("case_type", normalizedVendorCiCaseType(typeFilter));

  const casesResult = await caseQuery;
  if (casesResult.error) throw casesResult.error;

  const valueCurve = await buildVendorValueCurve(supabase, user, input);
  const allScorecards = valueCurve.scorecards;
  const scorecardByVendor = new Map(allScorecards.map((row) => [cleanText(row.vendor_id) || "", row]));
  const scorecards = allScorecards
    .filter((row) => tierFilter === "all" || row.tier === tierFilter)
    .filter((row) => vendorValueScorecardMatchesSearch(row, search));
  const rows = (casesResult.data || [])
    .map((row) => serializeVendorImprovementCase(row, scorecardByVendor))
    .filter((row) => tierFilter === "all" || row.current_tier === tierFilter)
    .filter((row) => vendorImprovementMatchesSearch(row, search));

  return {
    rows,
    scorecards,
    summary: {
      ...summarizeVendorCi(rows, scorecards),
      total_vendors: valueCurve.source_counts.vendors,
      manual_scorecards: valueCurve.source_counts.manual_scorecards,
      signal_sources: valueCurve.source_counts,
      warnings: valueCurve.warnings
    },
    playbooks: vendorCiPlaybooks(),
    limit
  };
}

async function createVendorImprovementCase(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  input: Record<string, unknown>
) {
  const source = objectRecord(input.case || input);
  const vendor = await requireOwnedVendorForCi(supabase, user, source.vendor_id);
  const scorecard = await ensureVendorValueScorecard(supabase, user, vendor);
  const title = cleanText(source.title);
  if (!title) throw new Error("Improvement case title is required.");
  const caseType = normalizedVendorCiCaseType(source.case_type || source.type);
  const row = withOwner({
    vendor_id: vendor.id,
    title,
    description: cleanText(source.description),
    case_type: caseType,
    severity: normalizedVendorCiSeverity(source.severity),
    status: normalizedVendorCiStatus(source.status, "open"),
    methodology: normalizedVendorCiMethod(source.methodology, caseType),
    tier_at_open: normalizedVendorCiTier(source.tier_at_open || scorecard.tier, "tactical"),
    target_tier: source.target_tier ? normalizedVendorCiTier(source.target_tier, "strategic") : null,
    vendor_request: cleanText(source.vendor_request),
    owner_notes: cleanText(source.owner_notes),
    root_cause: cleanText(source.root_cause),
    containment_action: cleanText(source.containment_action),
    corrective_action: cleanText(source.corrective_action),
    preventive_action: cleanText(source.preventive_action),
    success_metric: cleanText(source.success_metric),
    due_date: cleanText(source.due_date),
    source: cleanText(source.source) || "manual",
    source_ref: cleanText(source.source_ref),
    metadata: objectRecord(source.metadata)
  }, user);

  const result = await supabase
    .from("vendor_improvement_cases")
    .insert(row)
    .select("*, vendors(id,vendor_name,name,legal_name,domain,primary_email,base_stage,status)")
    .single();
  if (result.error) throw result.error;

  const scorecardByVendor = new Map([[cleanText(scorecard.vendor_id) || "", scorecard]]);
  await writeAuditLog(
    supabase,
    user,
    "vendor_ci.create",
    "vendor_improvement_cases",
    result.data.id,
    `Created vendor CI case for ${cleanText(vendor.vendor_name || vendor.domain) || "vendor"}`,
    { vendor_id: vendor.id, case_type: caseType, severity: row.severity }
  );
  return { row: serializeVendorImprovementCase(result.data, scorecardByVendor) };
}

async function updateVendorImprovementCase(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  input: Record<string, unknown>
) {
  const id = cleanText(input.id || input.case_id);
  if (!id) throw new Error("Improvement case id is required.");
  const patch = objectRecord(input.patch || input);
  const updatePatch: Record<string, unknown> = { updated_at: new Date().toISOString() };
  if ("title" in patch) updatePatch.title = cleanText(patch.title);
  if ("description" in patch) updatePatch.description = cleanText(patch.description);
  if ("case_type" in patch || "type" in patch) {
    const caseType = normalizedVendorCiCaseType(patch.case_type || patch.type);
    updatePatch.case_type = caseType;
    updatePatch.methodology = normalizedVendorCiMethod(patch.methodology, caseType);
  }
  if ("severity" in patch) updatePatch.severity = normalizedVendorCiSeverity(patch.severity);
  if ("status" in patch) {
    const status = normalizedVendorCiStatus(patch.status);
    updatePatch.status = status;
    updatePatch.closed_at = status === "resolved" ? new Date().toISOString() : null;
  }
  if ("methodology" in patch) {
    const method = cleanText(patch.methodology)?.toLowerCase() || "dmaic";
    if (!VENDOR_CI_METHODS.has(method)) throw new Error("Unsupported improvement methodology.");
    updatePatch.methodology = method;
  }
  if ("target_tier" in patch) updatePatch.target_tier = patch.target_tier ? normalizedVendorCiTier(patch.target_tier) : null;
  if ("vendor_request" in patch) updatePatch.vendor_request = cleanText(patch.vendor_request);
  if ("owner_notes" in patch) updatePatch.owner_notes = cleanText(patch.owner_notes);
  if ("root_cause" in patch) updatePatch.root_cause = cleanText(patch.root_cause);
  if ("containment_action" in patch) updatePatch.containment_action = cleanText(patch.containment_action);
  if ("corrective_action" in patch) updatePatch.corrective_action = cleanText(patch.corrective_action);
  if ("preventive_action" in patch) updatePatch.preventive_action = cleanText(patch.preventive_action);
  if ("success_metric" in patch) updatePatch.success_metric = cleanText(patch.success_metric);
  if ("due_date" in patch) updatePatch.due_date = cleanText(patch.due_date);
  if ("metadata" in patch) updatePatch.metadata = objectRecord(patch.metadata);

  const result = await supabase
    .from("vendor_improvement_cases")
    .update(updatePatch)
    .eq("id", id)
    .eq("owner_email", user.owner_email)
    .select("*, vendors(id,vendor_name,name,legal_name,domain,primary_email,base_stage,status)")
    .single();
  if (result.error) throw result.error;

  const scorecards = await supabase
    .from("vendor_value_scorecards")
    .select("*")
    .eq("owner_email", user.owner_email)
    .eq("vendor_id", result.data.vendor_id)
    .limit(1);
  if (scorecards.error) throw scorecards.error;
  const scorecardByVendor = new Map((scorecards.data || []).map((row) => [cleanText(row.vendor_id) || "", row as Record<string, unknown>]));

  await writeAuditLog(
    supabase,
    user,
    "vendor_ci.update",
    "vendor_improvement_cases",
    id,
    `Updated vendor CI case ${id}`,
    { status: result.data.status, severity: result.data.severity }
  );
  return { row: serializeVendorImprovementCase(result.data, scorecardByVendor) };
}

function vendorCiEmailSubject(row: Record<string, unknown>, vendor: Record<string, unknown>) {
  const title = cleanText(row.title) || "Continuous improvement request";
  const vendorName = vendorCiVendorName(vendor);
  return `Action required: ${title} - ${vendorName}`;
}

function vendorCiCaseLabel(row: Record<string, unknown>) {
  const caseType = cleanText(row.case_type)?.replace(/_/g, " ") || "improvement";
  const method = cleanText(row.methodology)?.toUpperCase() || "DMAIC";
  return `${method} / ${caseType}`;
}

function vendorCiEmailText(row: Record<string, unknown>, vendor: Record<string, unknown>, nextReminderAt: string | null) {
  const vendorName = vendorCiVendorName(vendor);
  return [
    `Hello ${vendorName},`,
    "",
    "MARKSMAN is opening a Vendor Continuous Improvement requirement for your team.",
    "",
    `Case: ${cleanText(row.title) || "Continuous improvement request"}`,
    `Process: ${vendorCiCaseLabel(row)}`,
    `Severity: ${cleanText(row.severity) || "medium"}`,
    `Due date: ${cleanText(row.due_date) || "to be confirmed"}`,
    "",
    "Request:",
    cleanText(row.vendor_request || row.description) || "Please review the requirement and confirm corrective actions, owner, target date, and evidence.",
    "",
    cleanText(row.success_metric) ? `Success metric: ${cleanText(row.success_metric)}` : null,
    cleanText(row.corrective_action) ? `Corrective action expected: ${cleanText(row.corrective_action)}` : null,
    nextReminderAt ? `Automatic reminder scheduled: ${nextReminderAt}` : null,
    "",
    "Please reply to this email with your action plan, evidence, and expected completion date.",
    "",
    "Thank you,",
    "MARKSMAN Procurement"
  ].filter(Boolean).join("\n");
}

function vendorCiEmailHtml(row: Record<string, unknown>, vendor: Record<string, unknown>, nextReminderAt: string | null) {
  const escape = (value: unknown) => String(value ?? "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;");
  const request = cleanText(row.vendor_request || row.description) || "Please review the requirement and confirm corrective actions, owner, target date, and evidence.";
  const successMetric = cleanText(row.success_metric);
  const corrective = cleanText(row.corrective_action);
  return `
    <div style="font-family:Arial,sans-serif;color:#17212b;font-size:14px;line-height:1.45">
      <p>Hello ${escape(vendorCiVendorName(vendor))},</p>
      <p>MARKSMAN is opening a <strong>Vendor Continuous Improvement</strong> requirement for your team.</p>
      <table style="border-collapse:collapse;width:100%;max-width:720px;margin:14px 0">
        <tr><td style="border:1px solid #d8e1ea;padding:8px;font-weight:700;background:#f5f8fb">Case</td><td style="border:1px solid #d8e1ea;padding:8px">${escape(cleanText(row.title) || "Continuous improvement request")}</td></tr>
        <tr><td style="border:1px solid #d8e1ea;padding:8px;font-weight:700;background:#f5f8fb">Process</td><td style="border:1px solid #d8e1ea;padding:8px">${escape(vendorCiCaseLabel(row))}</td></tr>
        <tr><td style="border:1px solid #d8e1ea;padding:8px;font-weight:700;background:#f5f8fb">Severity</td><td style="border:1px solid #d8e1ea;padding:8px">${escape(cleanText(row.severity) || "medium")}</td></tr>
        <tr><td style="border:1px solid #d8e1ea;padding:8px;font-weight:700;background:#f5f8fb">Due date</td><td style="border:1px solid #d8e1ea;padding:8px">${escape(cleanText(row.due_date) || "to be confirmed")}</td></tr>
        <tr><td style="border:1px solid #d8e1ea;padding:8px;font-weight:700;background:#f5f8fb">Request</td><td style="border:1px solid #d8e1ea;padding:8px">${escape(request)}</td></tr>
        ${successMetric ? `<tr><td style="border:1px solid #d8e1ea;padding:8px;font-weight:700;background:#f5f8fb">Success metric</td><td style="border:1px solid #d8e1ea;padding:8px">${escape(successMetric)}</td></tr>` : ""}
        ${corrective ? `<tr><td style="border:1px solid #d8e1ea;padding:8px;font-weight:700;background:#f5f8fb">Corrective action</td><td style="border:1px solid #d8e1ea;padding:8px">${escape(corrective)}</td></tr>` : ""}
        ${nextReminderAt ? `<tr><td style="border:1px solid #d8e1ea;padding:8px;font-weight:700;background:#f5f8fb">Reminder</td><td style="border:1px solid #d8e1ea;padding:8px">Automatic reminder scheduled: ${escape(nextReminderAt)}</td></tr>` : ""}
      </table>
      <p>Please reply to this email with your action plan, evidence, and expected completion date.</p>
      <p>Thank you,<br/>MARKSMAN Procurement</p>
    </div>
  `;
}

function vendorCiNextReminderAt(now: Date, input: Record<string, unknown>) {
  if (cleanOptionalBoolean(input.reminders_enabled) === false) return null;
  const interval = Math.max(1, Math.min(Number(input.reminder_interval_days) || 3, 30));
  return new Date(now.getTime() + interval * 24 * 60 * 60 * 1000).toISOString();
}

