async function sendVendorCiGmail(
  supabase: ReturnType<typeof createClient>,
  user: { owner_email: string | null },
  message: Record<string, unknown>
) {
  const accessToken = await gmailAccessToken(supabase, user, GMAIL_ALLOWED_SENDER);
  const response = await fetch("https://gmail.googleapis.com/gmail/v1/users/me/messages/send", {
    method: "POST",
    headers: {
      Authorization: `Bearer ${accessToken}`,
      "Content-Type": "application/json"
    },
    body: JSON.stringify({ raw: gmailRawMessage(message, GMAIL_ALLOWED_SENDER) })
  });
  const payload = await response.json().catch(() => ({})) as Record<string, any>;
  if (!response.ok) {
    const reason = cleanText(payload?.error?.message) || cleanText(payload?.error_description) || `Gmail send failed (${response.status}).`;
    throw new Error(reason);
  }
  return payload;
}

async function submitVendorImprovementCase(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  input: Record<string, unknown>
) {
  const id = cleanText(input.id || input.case_id);
  if (!id) throw new Error("Improvement case id is required.");
  const current = await supabase
    .from("vendor_improvement_cases")
    .select("*, vendors(id,vendor_name,name,legal_name,domain,primary_email,secondary_emails,whatsapp_phone,base_stage,status)")
    .eq("id", id)
    .eq("owner_email", user.owner_email)
    .single();
  if (current.error) throw current.error;

  const row = current.data as Record<string, unknown>;
  const vendor = relationRecord(row.vendors);
  const suppressedEmails = await suppressedEmailSet(supabase, user, vendorContactEmailCandidates(vendor));
  const recipientEmail = (cleanText(input.recipient_email) || firstSendableVendorEmail(vendor, suppressedEmails)).toLowerCase();
  if (!recipientEmail) throw new Error("Vendor has no sendable email. Add or fix the carrier email before submitting this case.");
  if (suppressedEmails.has(recipientEmail)) {
    throw new Error("Selected vendor email is blocked because a delivery failure was detected.");
  }

  const now = new Date();
  const nowIso = now.toISOString();
  const nextReminderAt = vendorCiNextReminderAt(now, input);
  const reminderIntervalDays = nextReminderAt ? Math.max(1, Math.min(Number(input.reminder_interval_days) || 3, 30)) : null;
  const subject = vendorCiEmailSubject(row, vendor);
  const textBody = vendorCiEmailText(row, vendor, nextReminderAt);
  const htmlBody = vendorCiEmailHtml(row, vendor, nextReminderAt);
  const message = { recipient_email: recipientEmail, subject, text_body: textBody, html_body: htmlBody };
  const metadata = objectRecord(row.metadata);
  const baseMetadata = {
    ...metadata,
    submitted_at: nowIso,
    submitted_to: recipientEmail,
    submitted_by: user.owner_email,
    reminders_enabled: Boolean(nextReminderAt),
    next_reminder_at: nextReminderAt,
    reminder_interval_days: reminderIntervalDays,
    reminder_count: Number(metadata.reminder_count || 0) || 0,
    last_reminder_at: cleanText(metadata.last_reminder_at) || null,
    email_subject: subject
  };

  let payload: Record<string, any>;
  try {
    payload = await sendVendorCiGmail(supabase, user, message);
  } catch (error) {
    const reason = error instanceof Error ? error.message : String(error);
    const update = await supabase
      .from("vendor_improvement_cases")
      .update({
        metadata: {
          ...baseMetadata,
          submission_status: "failed",
          last_submission_error: reason
        },
        updated_at: nowIso
      })
      .eq("id", id)
      .eq("owner_email", user.owner_email)
      .select("*, vendors(id,vendor_name,name,legal_name,domain,primary_email,base_stage,status)")
      .single();
    if (update.error) throw update.error;

    const history = await supabase.from("contact_history").insert(withOwner({
      vendor_id: row.vendor_id,
      channel: "email",
      direction: "outbound",
      status: "vendor_ci_failed",
      subject,
      body_preview: reason,
      occurred_at: nowIso,
      metadata: {
        source: "vendor_ci",
        vendor_improvement_case_id: id,
        case_type: row.case_type,
        severity: row.severity,
        sender_email: GMAIL_ALLOWED_SENDER,
        error: reason
      }
    }, user));
    if (history.error) throw history.error;
    throw new Error(`Vendor CI case could not be submitted by email: ${reason}`);
  }

  const update = await supabase
    .from("vendor_improvement_cases")
    .update({
      status: cleanText(row.status) === "open" ? "define" : row.status,
      metadata: {
        ...baseMetadata,
        submission_status: "sent",
        last_submission_error: null,
        provider_message_id: cleanText(payload.id),
        gmail_thread_id: cleanText(payload.threadId)
      },
      updated_at: nowIso
    })
    .eq("id", id)
    .eq("owner_email", user.owner_email)
    .select("*, vendors(id,vendor_name,name,legal_name,domain,primary_email,base_stage,status)")
    .single();
  if (update.error) throw update.error;

  const history = await supabase.from("contact_history").insert(withOwner({
    vendor_id: row.vendor_id,
    channel: "email",
    direction: "outbound",
    status: "vendor_ci_sent",
    subject,
    body_preview: contactPreview(textBody),
    occurred_at: nowIso,
    metadata: {
      source: "vendor_ci",
      vendor_improvement_case_id: id,
      case_type: row.case_type,
      severity: row.severity,
      reminders_enabled: Boolean(nextReminderAt),
      next_reminder_at: nextReminderAt,
      sent_from: "gmail_api",
      sender_email: GMAIL_ALLOWED_SENDER,
      provider_message_id: cleanText(payload.id),
      gmail_thread_id: cleanText(payload.threadId)
    }
  }, user));
  if (history.error) throw history.error;

  await writeAuditLog(
    supabase,
    user,
    "vendor_ci.submit",
    "vendor_improvement_cases",
    id,
    `Submitted vendor CI case to ${recipientEmail}`,
    { vendor_id: row.vendor_id, next_reminder_at: nextReminderAt }
  );

  return { row: serializeVendorImprovementCase(update.data), sent: true, next_reminder_at: nextReminderAt };}
async function processVendorImprovementReminders(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  input: Record<string, unknown>
) {
  const limit = Math.max(1, Math.min(Number(input.limit) || 25, 100));
  const now = new Date();
  const nowIso = now.toISOString();
  const dueCases = await supabase
    .from("vendor_improvement_cases")
    .select("*, vendors(id,vendor_name,name,legal_name,domain,primary_email,secondary_emails,whatsapp_phone,base_stage,status)")
    .eq("owner_email", user.owner_email)
    .in("status", ["open", "define", "measure", "analyze", "improve", "control"])
    .eq("metadata->>reminders_enabled", "true")
    .lte("metadata->>next_reminder_at", nowIso)
    .order("updated_at", { ascending: true })
    .limit(limit);
  if (dueCases.error) throw dueCases.error;

  const results: Array<Record<string, unknown>> = [];
  for (const row of dueCases.data || []) {
    const caseRow = row as Record<string, unknown>;
    const vendor = relationRecord(caseRow.vendors);
    const metadata = objectRecord(caseRow.metadata);
    const reminderCount = (Number(metadata.reminder_count || 0) || 0) + 1;
    const interval = Math.max(1, Math.min(Number(metadata.reminder_interval_days || input.reminder_interval_days) || 3, 30));
    const nextReminderAt = new Date(now.getTime() + interval * 24 * 60 * 60 * 1000).toISOString();
    const suppressedEmails = await suppressedEmailSet(supabase, user, vendorContactEmailCandidates(vendor));
    const recipientEmail = (cleanText(metadata.submitted_to) || firstSendableVendorEmail(vendor, suppressedEmails)).toLowerCase();
    const subject = `Reminder ${reminderCount}: ${vendorCiEmailSubject(caseRow, vendor)}`;
    let emailSent = false;
    let sentPayload: Record<string, any> | null = null;

    try {
      if (!recipientEmail) throw new Error("Vendor has no sendable email.");
      if (suppressedEmails.has(recipientEmail)) throw new Error("Vendor email is blocked because a delivery failure was detected.");
      const textBody = vendorCiReminderEmailText(caseRow, vendor, reminderCount);
      const htmlBody = vendorCiReminderEmailHtml(caseRow, vendor, reminderCount);
      const payload = await sendVendorCiGmail(supabase, user, { recipient_email: recipientEmail, subject, text_body: textBody, html_body: htmlBody });
      emailSent = true;
      sentPayload = payload;
      const update = await supabase
        .from("vendor_improvement_cases")
        .update({
          metadata: {
            ...metadata,
            reminder_count: reminderCount,
            last_reminder_at: nowIso,
            next_reminder_at: nextReminderAt,
            last_reminder_to: recipientEmail,
            last_reminder_error: null,
            last_reminder_provider_message_id: cleanText(payload.id),
            last_reminder_gmail_thread_id: cleanText(payload.threadId)
          },
          updated_at: nowIso
        })
        .eq("id", caseRow.id)
        .eq("owner_email", user.owner_email);
      if (update.error) throw update.error;

      const history = await supabase.from("contact_history").insert(withOwner({
        vendor_id: caseRow.vendor_id,
        channel: "email",
        direction: "outbound",
        status: "vendor_ci_reminder_sent",
        subject,
        body_preview: contactPreview(textBody),
        occurred_at: nowIso,
        metadata: {
          source: "vendor_ci",
          vendor_improvement_case_id: caseRow.id,
          reminder_count: reminderCount,
          next_reminder_at: nextReminderAt,
          sender_email: GMAIL_ALLOWED_SENDER,
          provider_message_id: cleanText(payload.id),
          gmail_thread_id: cleanText(payload.threadId)
        }
      }, user));
      if (history.error) throw history.error;
      results.push({ id: caseRow.id, status: "sent", next_reminder_at: nextReminderAt });
    } catch (error) {
      const reason = error instanceof Error ? error.message : String(error);
      const failureMetadata = emailSent ? {
        ...metadata,
        reminder_count: reminderCount,
        last_reminder_at: nowIso,
        next_reminder_at: nextReminderAt,
        last_reminder_to: recipientEmail,
        last_reminder_error: reason,
        last_reminder_provider_message_id: cleanText(sentPayload?.id),
        last_reminder_gmail_thread_id: cleanText(sentPayload?.threadId)
      } : {
        ...metadata,
        last_reminder_error: reason,
        last_reminder_failed_at: nowIso
      };
      await supabase
        .from("vendor_improvement_cases")
        .update({
          metadata: failureMetadata,
          updated_at: nowIso
        })
        .eq("id", caseRow.id)
        .eq("owner_email", user.owner_email);
      results.push({ id: caseRow.id, status: "failed", error: reason });
    }
  }

  return {
    processed: results.length,
    sent: results.filter((item) => item.status === "sent").length,
    failed: results.filter((item) => item.status === "failed").length,
    rows: results
  };
}

async function upsertVendorValueScorecard(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  input: Record<string, unknown>
) {
  const source = objectRecord(input.scorecard || input);
  const vendor = await requireOwnedVendorForCi(supabase, user, source.vendor_id);
  const valueScore = "value_score" in source ? numericScore(source.value_score) : numericScore(defaultScorecardForVendor(vendor).value_score);
  const tier = source.tier ? normalizedVendorCiTier(source.tier) : tierFromValueScore(valueScore);
  const row = withOwner({
    vendor_id: vendor.id,
    tier,
    value_score: valueScore,
    operational_score: numericScore(source.operational_score),
    commercial_score: numericScore(source.commercial_score),
    financial_score: numericScore(source.financial_score || source.commercial_score),
    compliance_score: numericScore(source.compliance_score),
    technology_score: numericScore(source.technology_score),
    relationship_score: numericScore(source.relationship_score),
    attributes: objectRecord(source.attributes),
    notes: cleanText(source.notes),
    last_scored_at: new Date().toISOString(),
    updated_at: new Date().toISOString()
  }, user);
  const result = await supabase
    .from("vendor_value_scorecards")
    .upsert(row, { onConflict: "owner_email,vendor_id" })
    .select("*, vendors(id,vendor_name,name,legal_name,domain,primary_email,base_stage,status)")
    .single();
  if (result.error) throw result.error;

  await writeAuditLog(
    supabase,
    user,
    "vendor_ci.scorecard_upsert",
    "vendor_value_scorecards",
    result.data.id,
    `Updated vendor value scorecard for ${cleanText(vendor.vendor_name || vendor.domain) || "vendor"}`,
    { vendor_id: vendor.id, tier, value_score: valueScore }
  );
  return { row: serializeVendorValueScorecard(result.data) };
}

function carrierProfileUrl(appOrigin: unknown, token: unknown) {
  const baseUrl = (cleanText(appOrigin) || Deno.env.get("RATEWARE_PUBLIC_APP_URL") || "https://rateware.vercel.app").replace(/\/$/, "");
  const requestToken = cleanText(token);
  return requestToken ? `${baseUrl}/carrier-profile.html?token=${encodeURIComponent(requestToken)}` : "";
}

async function vendorProfileLinksForInvitations(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  invitations: Record<string, unknown>[],
  appOrigin: string,
  metadata: Record<string, unknown> = {}
) {
  const vendorIds = Array.from(new Set(invitations.map((invitation) => cleanText(invitation.vendor_id)).filter(Boolean))) as string[];
  const links = new Map<string, string>();
  if (!vendorIds.length) return links;

  const nowIso = new Date().toISOString();
  const existingBatches = await mapWithConcurrency(chunkValues(vendorIds, 100), 4, async (chunk) => {
    const existing = await supabase
      .from("vendor_profile_requests")
      .select("id,vendor_id,request_token,status,expires_at,created_at")
      .eq("owner_email", user.owner_email)
      .in("vendor_id", chunk)
      .in("status", ["active", "viewed", "submitted"])
      .gt("expires_at", nowIso)
      .order("created_at", { ascending: false });
    if (existing.error) throw existing.error;
    return existing.data || [];
  });
  const existingRows = existingBatches.flat() as Record<string, unknown>[];

  for (const row of existingRows) {
    const vendorId = cleanText(row.vendor_id);
    if (vendorId && !links.has(vendorId)) links.set(vendorId, carrierProfileUrl(appOrigin, row.request_token));
  }

  const missingVendorIds = vendorIds.filter((vendorId) => !links.has(vendorId));
  if (!missingVendorIds.length) return links;

  const expiresAt = new Date(Date.now() + 90 * 86400000).toISOString();
  const rows = missingVendorIds.map((vendorId) => {
    const requestToken = `${crypto.randomUUID()}${crypto.randomUUID()}`.replace(/-/g, "").slice(0, 48);
    links.set(vendorId, carrierProfileUrl(appOrigin, requestToken));
    return withOwner({
      vendor_id: vendorId,
      request_token: requestToken,
      status: "active",
      expires_at: expiresAt,
      metadata: {
        ...metadata,
        generated_from: "rfx_outreach",
        expires_in_days: 90
      }
    }, user);
  });

  await mapWithConcurrency(chunkValues(rows, 250), 4, async (chunk) => {
    const created = await supabase.from("vendor_profile_requests").insert(chunk).select("id,vendor_id,request_token");
    if (created.error) throw created.error;
    return created.data || [];
  });

  return links;
}

function outreachContext(
  invitation: Record<string, unknown>,
  appOrigin: string,
  invitationGroup: Record<string, unknown>[] = [invitation],
  template: Record<string, unknown> | null | undefined = null,
  profileLink = ""
) {
  const vendor = typeof invitation.vendors === "object" && invitation.vendors ? invitation.vendors as Record<string, unknown> : {};
  const lane = typeof invitation.rfx_lanes === "object" && invitation.rfx_lanes ? invitation.rfx_lanes as Record<string, unknown> : {};
  const event = typeof invitation.rfx_events === "object" && invitation.rfx_events ? invitation.rfx_events as Record<string, unknown> : {};
  const bidLink = `${appOrigin.replace(/\/$/, "")}/rfx-bid.html?token=${encodeURIComponent(String(invitation.invitation_token || ""))}${invitationGroup.length > 1 ? "&view=book" : ""}`;
  const language = outreachTemplateLanguage(template);
  return {
    vendor_name: vendor.vendor_name || vendor.domain || "Carrier",
    contact_name: vendor.contact_name || vendor.vendor_name || "team",
    vendor_domain: vendor.domain || "",
    vendor_email: vendor.primary_email || "",
    rfx_id: event.rfx_id || "",
    event_name: event.name || event.rfx_id || "",
    rfx_type: event.event_type || "",
    customer: event.customer || "",
    due_date: event.due_date || "",
    lane_origin: lane.origin || lane.origin_city || "",
    lane_destination: lane.destination || lane.destination_city || "",
    origin_market: lane.origin_market || "",
    destination_market: lane.destination_market || "",
    equipment: lane.equipment || "",
    trailer: lane.trailer || "",
    config: lane.config || "",
    operation: lane.operation || "",
    service: lane.service || "",
    weekly_volume: lane.weekly_volume || "",
    target_rate: lane.target_rate || "",
    currency: lane.currency || "USD",
    lane_count: invitationGroup.length,
    lane_table: outreachLaneTableHtml(invitationGroup, language),
    lane_rows_text: outreachLaneRowsText(invitationGroup, language),
    lane_table_signature: outreachLaneTableSignature(invitationGroup),
    bid_link: bidLink,
    profile_link: profileLink || carrierProfileUrl(appOrigin, "")
  };
}

function messageChannels(channel: unknown) {
  const normalized = cleanText(channel)?.toLowerCase() || "email";
  if (normalized === "email" || normalized === "gmail" || normalized === "gmail_only") return ["email"];
  if (normalized === "whatsapp") return ["whatsapp"];
  if (normalized === "whatsapp_group") return ["whatsapp_group"];
  if (normalized === "multi" || normalized === "email_whatsapp" || normalized === "email+whatsapp") return ["email", "whatsapp"];
  if (normalized === "whatsapp_direct_group" || normalized === "whatsapp+group") return ["whatsapp", "whatsapp_group"];
  if (normalized === "email_whatsapp_group" || normalized === "all") return ["email", "whatsapp", "whatsapp_group"];
  return ["email"];
}

async function fetchOutreachTemplate(supabase: ReturnType<typeof createClient>, user: { owner_email: string | null }, id: unknown) {
  const templateId = cleanText(id);
  if (!templateId) throw new Error("Outreach template id is required.");
  const result = await supabase
    .from("outreach_templates")
    .select("*")
    .eq("id", templateId)
    .single();
  if (result.error) throw result.error;
  if (result.data.owner_email && result.data.owner_email !== user.owner_email) throw new Error("Outreach template not found.");
  return result.data;
}

async function requireOwnedOutreachCampaign(supabase: ReturnType<typeof createClient>, user: { owner_email: string | null }, id: unknown) {
  const campaignId = cleanText(id);
  if (!campaignId) throw new Error("Outreach campaign id is required.");
  const result = await supabase
    .from("outreach_campaigns")
    .select("*")
    .eq("id", campaignId)
    .eq("owner_email", user.owner_email)
    .single();
  if (result.error) throw result.error;
  return result.data;
}

function normalizeSaasProfile(input: Record<string, unknown>) {
  const accessMode = cleanText(input.access_mode)?.toLowerCase() || "full_access";
  return {
    full_name: cleanText(input.full_name || input.name),
    job_title: cleanText(input.job_title || input.title),
    phone: cleanText(input.phone),
    timezone: cleanText(input.timezone) || "America/Mexico_City",
    preferred_language: cleanText(input.preferred_language || input.language) || "en",
    access_mode: ["full_access", "roles_later"].includes(accessMode) ? accessMode : "full_access",
    avatar_url: cleanText(input.avatar_url),
    updated_at: new Date().toISOString()
  };
}

function normalizeOrganization(input: Record<string, unknown>) {
  return {
    org_name: cleanText(input.org_name || input.name) || "Rateware workspace",
    workspace_slug: cleanText(input.workspace_slug || input.slug),
    website: cleanText(input.website),
    industry: cleanText(input.industry) || "freight procurement",
    timezone: cleanText(input.timezone) || "America/Mexico_City",
    billing_email: cleanText(input.billing_email),
    notes: cleanText(input.notes),
    updated_at: new Date().toISOString()
  };
}

async function ensureSaasProfile(supabase: ReturnType<typeof createClient>, user: { owner_user_id: string | null; owner_email: string | null }) {
  const existing = await supabase
    .from("user_profiles")
    .select("*")
    .eq("owner_email", user.owner_email)
    .maybeSingle();
  if (existing.error) throw existing.error;
  if (existing.data) return existing.data;

  const result = await supabase
    .from("user_profiles")
    .insert(withOwner({
      owner_email: user.owner_email,
      full_name: user.owner_email,
      access_mode: "full_access"
    }, user))
    .select()
    .single();
  if (result.error) throw result.error;
  return result.data;
}

async function ensureOrganization(supabase: ReturnType<typeof createClient>, user: { owner_user_id: string | null; owner_email: string | null }) {
  const existing = await supabase
    .from("organizations")
    .select("*")
    .eq("owner_email", user.owner_email)
    .maybeSingle();
  if (existing.error) throw existing.error;
  if (existing.data) return existing.data;

  const defaultName = user.owner_email?.includes("@")
    ? `${user.owner_email.split("@").pop()?.split(".")[0] || "Rateware"} workspace`
    : "Rateware workspace";
  const result = await supabase
    .from("organizations")
    .insert(withOwner({
      org_name: defaultName,
      billing_email: user.owner_email
    }, user))
    .select()
    .single();
  if (result.error) throw result.error;
  return result.data;
}

