async function verifyWhatsappWebhook(
  supabase: ReturnType<typeof createClient>,
  user: RatewareUser
) {
  const connection = await activeWhatsappConnection(supabase, user, { requireConnected: false });
  const verifyTokenConfigured = connection.internalWorkspace
    ? Boolean(WHATSAPP_WEBHOOK_VERIFY_TOKEN)
    : Boolean(connection.row.webhook_verify_token_encrypted);
  const appSecretConfigured = connection.internalWorkspace
    ? Boolean(WHATSAPP_APP_SECRET)
    : Boolean(connection.row.app_secret_encrypted);
  const verified = verifyTokenConfigured && appSecretConfigured;
  const now = new Date().toISOString();
  const update = await supabase
    .from("whatsapp_business_connections")
    .update({
      webhook_verified_at: verified ? now : null,
      last_error: verified ? null : "Webhook verify token or app secret is missing.",
      updated_at: now
    })
    .eq("id", connection.row.id)
    .select("*")
    .single();
  if (update.error) throw update.error;
  return {
    row: publicWhatsappConnection(update.data, { internalWorkspace: connection.internalWorkspace }),
    endpoint: `${String(SUPABASE_URL || "").replace(/\/$/, "")}/functions/v1/whatsapp-webhook`,
    verify_token_configured: verifyTokenConfigured,
    app_secret_configured: appSecretConfigured,
    connection_id: connection.row.id,
    verified
  };
}

async function verifyVendorWhatsappGroup(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  input: Record<string, unknown>
) {
  const vendorId = cleanText(input.vendor_id);
  if (!vendorId) throw new Error("Vendor id is required.");
  const groupUrl = cleanText(input.group_url || input.whatsapp_group_url);
  const groupName = cleanText(input.group_name || input.whatsapp_group_name);
  const metaGroupId = cleanText(input.meta_group_id || input.whatsapp_meta_group_id);
  const verificationStatus = WHATSAPP_GROUPS_ENABLED && metaGroupId ? "api_ready" : "manual_only";
  const row = withOwner({
    vendor_id: vendorId,
    group_name: groupName,
    group_url: groupUrl,
    meta_group_id: metaGroupId,
    verification_status: verificationStatus,
    permission_basis: cleanText(input.permission_basis) || "contractual",
    do_not_contact: cleanBoolean(input.do_not_contact),
    last_verified_at: new Date().toISOString(),
    last_error: verificationStatus === "manual_only" ? "Meta group API is not enabled. Use manual send controls." : null,
    updated_at: new Date().toISOString()
  }, user);
  let existingQuery = supabase
    .from("vendor_whatsapp_groups")
    .select("id")
    .eq("owner_email", user.owner_email)
    .eq("vendor_id", vendorId)
    .limit(1);
  if (metaGroupId) existingQuery = existingQuery.eq("meta_group_id", metaGroupId);
  else if (groupUrl) existingQuery = existingQuery.eq("group_url", groupUrl);
  else if (groupName) existingQuery = existingQuery.eq("group_name", groupName);
  const existing = await existingQuery.maybeSingle();
  if (existing.error) throw existing.error;
  const result = existing.data?.id
    ? await supabase.from("vendor_whatsapp_groups").update(row).eq("id", existing.data.id).select("*").single()
    : await supabase.from("vendor_whatsapp_groups").insert(row).select("*").single();
  if (result.error) throw result.error;
  await supabase
    .from("vendors")
    .update({
      whatsapp_group_url: groupUrl || null,
      whatsapp_group_name: groupName || null,
      whatsapp_meta_group_id: metaGroupId || null,
      whatsapp_group_status: verificationStatus,
      whatsapp_last_verified_at: new Date().toISOString(),
      updated_at: new Date().toISOString()
    })
    .eq("id", vendorId)
    .eq("owner_email", user.owner_email);
  return { row: result.data, manual_only: verificationStatus === "manual_only", groups_enabled: WHATSAPP_GROUPS_ENABLED };
}

async function startGoogleChatOauth(
  supabase: ReturnType<typeof createClient>,
  user: { owner_user_id: string | null; owner_email: string | null },
  input: Record<string, unknown> = {}
) {
  const requestedAccount = (cleanText(input.account_email) || GOOGLE_CHAT_ALLOWED_ACCOUNT).toLowerCase();
  if (requestedAccount !== GOOGLE_CHAT_ALLOWED_ACCOUNT) {
    return {
      error: `Only ${GOOGLE_CHAT_ALLOWED_ACCOUNT} can be connected to Google Chat for this workspace.`,
      status: 400
    };
  }

  const clientId = Deno.env.get("GOOGLE_CLIENT_ID");
  const clientSecret = Deno.env.get("GOOGLE_CLIENT_SECRET");
  const encryptionKey = Deno.env.get("GMAIL_TOKEN_ENCRYPTION_KEY");
  if (!clientId || !clientSecret || !encryptionKey) {
    return {
      error: "Google Chat connector is not enabled for this deployment yet.",
      status: 400,
      configured: false
    };
  }

  const state = crypto.randomUUID().replace(/-/g, "") + crypto.randomUUID().replace(/-/g, "");
  const redirectAfter = cleanText(input.redirect_after) || "settings.html?view=integrations&chat=connected";
  const stateResult = await supabase.from("google_chat_oauth_states").insert({
    state,
    owner_user_id: user.owner_user_id,
    owner_email: user.owner_email,
    account_email: GOOGLE_CHAT_ALLOWED_ACCOUNT,
    redirect_after: redirectAfter,
    expires_at: new Date(Date.now() + 15 * 60 * 1000).toISOString(),
    metadata: { requested_from: "settings", provider: "google_chat" }
  });
  if (stateResult.error) throw stateResult.error;

  const params = new URLSearchParams({
    client_id: clientId,
    redirect_uri: googleChatRedirectUri(),
    response_type: "code",
    scope: GOOGLE_CHAT_OAUTH_SCOPES.join(" "),
    state,
    access_type: "offline",
    prompt: "consent",
    include_granted_scopes: "true",
    login_hint: GOOGLE_CHAT_ALLOWED_ACCOUNT
  });

  return {
    authorization_url: `https://accounts.google.com/o/oauth2/v2/auth?${params.toString()}`,
    account_email: GOOGLE_CHAT_ALLOWED_ACCOUNT,
    redirect_uri: googleChatRedirectUri(),
    scopes: GOOGLE_CHAT_OAUTH_SCOPES
  };
}

async function disconnectGoogleChatConnection(supabase: ReturnType<typeof createClient>, user: { owner_email: string | null }) {
  const result = await supabase
    .from("google_chat_connections")
    .upsert({
      owner_email: user.owner_email,
      account_email: GOOGLE_CHAT_ALLOWED_ACCOUNT,
      provider: "google_chat",
      status: "revoked",
      access_token_encrypted: null,
      refresh_token_encrypted: null,
      token_expires_at: null,
      default_space_name: null,
      default_space_display_name: null,
      last_error: null,
      updated_at: new Date().toISOString()
    }, { onConflict: "owner_email,account_email" })
    .select("account_email,provider,status,scopes,token_expires_at,updated_at,last_error,default_space_name,default_space_display_name")
    .single();
  if (result.error) throw result.error;
  return publicGoogleChatConnection(result.data);
}

